INSERT INTO layer0.health_condition_categories (category_name,description,etl_version,etl_run_at) VALUES ('Cardiac','HR ceiling enforcement; avoid max-effort and high-HR-spike work — Examples: Hypertension, arrhythmia, post-MI, HCM, mitral valve issues','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Respiratory','Altitude-sim caution; interval intensity management; cold-air protocols — Examples: Asthma, EIB, COPD, post-COVID lung','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Endocrine / Metabolic','Carb-timing for diabetic ultra; thyroid-aware volume ramps; cortisol-aware load mgmt — Examples: T1D, T2D, hypo/hyperthyroid, adrenal insufficiency, PCOS','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('GI','Race-fueling planning; aid-station strategy; avoid high-jostle post-fueling — Examples: IBS, IBD, Crohn''s, celiac, chronic reflux','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Neurological','Coordination/disorientation drill caution; concussion return-to-load; seizure-risk gating — Examples: Concussion history, migraine, epilepsy, MS, neuropathy','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Cognitive / Mental health','Plan complexity calibration; recovery prioritisation; stimulant interaction with HR — Examples: ADHD, anxiety, depression, OCD — when affects training adherence/intensity','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Cognitive','Skill-heavy drill gating; sequencing-load caution; processing-speed-aware progression — Examples: TBI, post-concussion processing-speed deficits, cognitive impairment affecting drill execution','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Musculoskeletal (chronic, non-injury)','Permanent regression chain; load management; flare-up flags — Examples: Arthritis, fibromyalgia, hypermobility, congenital structural','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skin','Sun-exposure exercise filtering; abrasion-risk surfaces; sweat-irritation gear — Examples: Photosensitivity, eczema, severe sweat allergy','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Thermoregulation','Heat/cold tolerance flags; pairs with system-tracked heat-acclim history — Examples: Heat intolerance, Raynaud''s, MS-related thermal dysreg','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Immune / Autoimmune','Recovery time inflation; flare-aware load management — Examples: RA, lupus, MCAS, post-infection syndromes','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Other','Captures anything not above — Examples: Free text in Name field describes','0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
