INSERT INTO layer0.terrain_types (terrain_id,canonical_name,category,requires_elevation,technical_surface,environment,simulatable,simulation_note,notes,race_eligible,etl_version,etl_run_at) VALUES ('TRN-001','Road / Paved','Foot',FALSE,FALSE,'Outdoor','full','Treadmill is full-fidelity substitute for road running.','Standard road and paved path running surface.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-002','Groomed Trail','Foot',FALSE,FALSE,'Outdoor','partial','Treadmill covers aerobic load; loses surface variation and proprioceptive demand.','Compacted, maintained singletrack or dirt trail. Low surface variability.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-003','Technical Trail','Foot',FALSE,TRUE,'Outdoor','partial','Agility and balance drills are partial proxy; proprioceptive adaptation to variable surface requires real terrain.','Rocky, root-crossed, or otherwise unpredictable trail surface. High ankle demand.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-004','Hill / Rolling','Foot',TRUE,FALSE,'Outdoor','partial','Max-incline treadmill simulates uphill aerobic load; descent EIMD adaptation requires actual downhill terrain.','Moderate sustained elevation. Rolling hills with recoverable grades.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-005','Mountain / Alpine','Foot',TRUE,TRUE,'Outdoor','partial','Stair climber and weighted vest simulate vertical load; descent skill and alpine balance cannot be replicated indoors.','High sustained elevation with exposed, technical, or multi-hour vertical gain. Includes above-treeline terrain.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-006','Fell / Moorland','Foot',TRUE,TRUE,'Outdoor','none','No meaningful indoor substitute. Navigation on unmarked terrain and variable footing on heather/bog cannot be simulated.','Open, pathless, navigationally demanding terrain. Steep grass, heather, bog, moorland. Fell running specific.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-007','Technical Rock / Scree','Foot',FALSE,TRUE,'Outdoor','none','Balance drills develop general stability but rock-specific proprioceptive adaptation requires actual boulder/scree terrain.','Loose boulder fields, scree slopes, rock gardens. Distinct from rock climbing — locomotive movement over unstable rock.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-018','Off Trail / Bushwhack','Foot',FALSE,TRUE,'Outdoor','none','No indoor substitute. Trackless travel through scrub, tall grass, deadfall, and uneven vegetated ground demands constant footing micro-adjustment, vegetation resistance, and continuous route-finding that no treadmill or machine reproduces.','Trackless off-trail ground — scrub brush, tall grass, bushwhacking through vegetated or untracked terrain. No path at all. Distinct from groomed trail (TRN-002), technical-but-tracked trail (TRN-003), and open pathless upland (TRN-006 Fell / Moorland). Expedition-AR stimulus.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-020','Gravel','Foot',FALSE,FALSE,'Outdoor','partial','Treadmill covers aerobic load and gait pattern; loses gravel-specific surface inconsistency (slip, micro-instability, occasional embedded rocks). Indoor cycling trainer covers cadence/power but loses bike-handling on loose surface for cycling use.','Compacted unpaved gravel road or path. Distinct from paved road (TRN-001) and dirt singletrack (TRN-002). Serves both gravel-running and gravel-cycling stimuli; modality captured by discipline + equipment.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-008','Pool','Water',FALSE,FALSE,'Indoor','full','Full fidelity for stroke mechanics and aerobic base. Standard pool environment.','Controlled lane swimming. Flip turns, lane lines, consistent conditions.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-009','Flat Water','Water',FALSE,FALSE,'Outdoor','partial','Pool covers aerobic base and stroke mechanics; loses open-water pacing, sighting, and conditions handling (wind, chop).','Still water — lake, reservoir, pond. No perceptible current. Standard flatwater paddling and open-water swim training environment.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-017','Moving Water','Water',FALSE,FALSE,'Outdoor','partial','Flat water covers paddle aerobic and stroke mechanics; loses current reading, ferry angles, and eddy use. Whitewater experience over-covers these skills.','Rivers, current-driven channels, or tidal flats below Class II. Ferry angles, eddy reads, and current navigation required. Standard river-paddling and packraft-touring environment.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-010','Ocean / Tidal','Water',FALSE,FALSE,'Outdoor','partial','Pool maintains aerobic base; loses sighting, wave/swell navigation, salt and cold exposure, and mass-start dynamics.','Saltwater or tidal water — ocean, sea, or tidal estuary. Cold-shock potential, salt exposure, swell, horizon sighting. OW swimming and ocean paddling territory.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-011','Whitewater','Water',FALSE,TRUE,'Outdoor','none','Flat water maintains paddling fitness only. Whitewater skill (eddy catches, reading water, bracing, rolling) requires moving water.','Class II+ moving water with rapids, eddies, hydraulics. Technical paddling terrain.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-012','Snow / Winter Alpine','Snow',TRUE,TRUE,'Outdoor','partial','Stair climber with poles approximates uphill skinning aerobic load. Descent skill on snow cannot be simulated off-snow.','Snow-covered mountain terrain requiring skis, snowshoes, or crampons. Includes groomed tracks, off-piste, and alpine descent.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-013','Rock Wall (Outdoor)','Climbing',FALSE,TRUE,'Outdoor','partial','Climbing gym transfers movement patterns and strength well; loses natural rock reading, exposure confidence, and protection placement.','Natural rock climbing terrain. Sport routes, trad, or scrambling on real rock.',TRUE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-014','Climbing Gym','Climbing',FALSE,TRUE,'Indoor','full','Full fidelity for movement pattern development, finger strength, and route reading on plastic holds.','Indoor climbing wall. Bouldering or roped. Standard AR climbing prep environment.',FALSE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-015','Pump Track / Skills Course','MTB',FALSE,TRUE,'Outdoor','none','No indoor substitute for pump track or MTB skills course. Balance and cornering drills are poor proxies.','MTB-specific terrain. Berms, jumps, pump sections, technical flow. Skills training focused.',FALSE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('TRN-016','Indoor / Gym','Gym',FALSE,FALSE,'Indoor','full','By definition this is the simulation environment. Full fidelity for any exercise it hosts.','Treadmill, stair climber, erg, gym equipment. The indoor training environment itself.',FALSE,'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
