  ('Whitewater paddling setup','Whitewater paddling setup','Spray skirt, Whitewater helmet, Whitewater PFD, Throw bag',ARRAY[]::TEXT[],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'0C-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
