INSERT INTO layer0.sports (sport_name,typical_duration_range,team_vs_solo,flag_navigation,navigation_notes,flag_sleep_deprivation,sleep_deprivation_notes,flag_pack_carry,pack_carry_notes,pack_weight_lbs_low,pack_weight_lbs_high,flag_transition_training,transition_training_notes,primary_discipline_count,secondary_discipline_count,status_label,constituent_movements,endurance_profile,participation_format,multi_discipline,etl_version,etl_run_at) VALUES ('Adventure Racing','4 hrs – 14 days','Teams of 4 (mixed gender at world-level). All members must finish sections together.',TRUE,'YES — Core discipline. Navigation (map + compass, no GPS) overlaid on all physical disciplines continuously.',TRUE,'YES — Unique to long-format AR (48 hr+). Sleep deprivation is a race discipline.',TRUE,'YES — 25–35 lb race pack on foot and bike legs. Pack carry training mandatory.',25.0,35.0,TRUE,'YES — Discipline transitions (bike→run, run→packraft, etc.) are time-sinks. Train gear swaps.',8,7,'ACTIVE — Full detail',ARRAY['running','cycling','paddling','hiking','navigation','climbing'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon','1 hr – 17 hrs','Individual. Draft-legal (ITU/WTS) and non-drafting (Ironman/age-group) categories. Relay teams exist in some events.',FALSE,'NO — course is marked. No map/compass required.',FALSE,'NO for Sprint/Olympic. Minimal for 70.3 (8 hrs max). Partial for Full IM — slowest finishers may encounter sleep deficit if finishing at night.',FALSE,'NO — no mandatory pack carry. Nutrition carried on bike (bento box, bottles) and in jersey pockets/race belt.',NULL,NULL,TRUE,'YES — T1 (Swim→Bike) and T2 (Bike→Run) are separately timed. Brick workouts (Bike→Run) are the primary training differentiator vs. single-sport.',3,0,'ACTIVE — Full detail added',ARRAY['running','cycling','swimming'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon (Sprint)','0.75 hrs – 2 hrs','Individual. Draft-legal at ITU/WTS elite. Age-group non-drafting. Relay teams at some mass-participation events.',FALSE,'NO — course fully marked with buoys, signs, and mile markers.',FALSE,'NO — race too short for sleep deprivation to be a factor.',FALSE,'NO — no mandatory pack carry. Wetsuit if water ≤24.5°C. Bento box or gel flask on bike. Race belt for run.',NULL,NULL,TRUE,'YES — T1 (Swim→Bike) and T2 (Bike→Run) are separately timed. At Sprint distance, T1+T2 can represent 3–5% of total race time — highest transition time impact of any triathlon format. Transition speed is a meaningful performance differentiator.',3,0,'ACTIVE — Sub-format extracted from parent Triathlon entry',ARRAY['running','cycling','swimming'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon (Standard / Olympic)','1.5 hrs – 3 hrs','Individual (primary). Mixed Relay (2M + 2F — Olympic format). Draft-legal at ITU/WTS elite. Non-drafting at most age-group events.',FALSE,'NO — course fully marked.',FALSE,'NO — race duration too short for sleep deprivation.',FALSE,'NO — no pack carry. Wetsuit if water ≤24.5°C. Bento box on bike. Race belt for run.',NULL,NULL,TRUE,'YES — T1 (Swim→Bike) and T2 (Bike→Run). Transition speed is a meaningful differentiator at elite level. Mixed Relay adds a hand-off transition zone (4th athlete to finish crosses the line).',3,0,'ACTIVE — Sub-format extracted from parent Triathlon entry',ARRAY['running','cycling','swimming'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon (Half / 70.3)','3.5 hrs – 8 hrs (elite ~3:30–4:00; age-group 4–8 hrs)','Individual. Non-drafting (age-group). Draft-legal elite only. No mandatory team format.',FALSE,'NO — course fully marked.',FALSE,'NO for most athletes (finish <8 hrs). MINIMAL for athletes finishing in 7–8 hrs — night racing possible at late starts, but sleep deprivation not a training variable.',FALSE,'NO — nutrition on bike (bottles, bento box, special needs bag at ~45km mark). Gel/nutrition on run (race belt). No mandatory pack carry.',NULL,NULL,TRUE,'YES — T1 (Swim→Bike) and T2 (Bike→Run). Special needs bags (bike and run) require planning. Changing tent standard at most IRONMAN 70.3 events. Nutrition drop bags are format-specific and must be practiced.',3,0,'ACTIVE — Sub-format extracted from parent Triathlon entry',ARRAY['running','cycling','swimming'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon (Full / Ironman 140.6)','8 hrs – 17 hrs (elite ~7:30–8:30; age-group 9–17 hrs)','Individual. Non-drafting (universal). No team format at standard events.',FALSE,'NO — course fully marked.',FALSE,'PARTIAL — athletes finishing in 14–17 hrs may encounter night racing and cumulative sleep deficit in the days prior. Strategic sleep management is relevant for athletes expecting 15+ hrs. Not a primary race variable for athletes finishing under 14 hrs.',FALSE,'NO mandatory pack carry. Nutrition carried on bike (bottles, aero bars storage, bento box, special needs bag at ~90km). Run nutrition from aid stations every mile (cola, broth, gels, bars, chicken soup). Special needs bag at ~21km of run.',NULL,NULL,TRUE,'YES — T1 and T2 with changing tents (standard at all Full IM events — unlike shorter formats). Two special needs bags (bike + run) require planning, packing, and mental rehearsal. Transition layout, nutrition strategy, and sunscreen/anti-chafe are format-specific skills.',3,0,'ACTIVE — Sub-format extracted from parent Triathlon entry',ARRAY['running','cycling','swimming'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Trail)','4 hrs (50K fast) to 36+ hrs (100M); 7+ days (200+ miles)','Individual. Pacer systems legal/common in 100-mile events. Crew access at aid stations.',FALSE,'PARTIAL — most courses marked with flags. Some wilderness ultras require maps at junctions.',TRUE,'YES for 100+ miles. Sleep deprivation is a race performance variable. Strategic sleep, caffeine timing.',TRUE,'YES — mandatory kit varies by race (emergency bivvy, waterproof, headlamp, food, water). Hydration vest standard.',NULL,NULL,FALSE,'PARTIAL — aid station transitions (shoe change, resupply, crew handoff) are time-sinks that improve with practice.',NULL,NULL,'ACTIVE — sub-format split from Ultramarathon (Road and Trail) parent',ARRAY['running'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Road)','5 hrs (50K fast road) to 36+ hrs (Spartathlon); multi-day for 100M+ road events','Individual. Pacers legal in some events; crew/aid common.',FALSE,'NO — fully marked road courses with mile/km markers.',TRUE,'YES for 100+ miles or multi-day. Less common than trail ultras for 50K–100K events.',FALSE,'MINIMAL — hydration belt or vest. No mandatory emergency kit (well-supported aid stations).',NULL,NULL,FALSE,'NO formal transitions. Aid stations every 1–3 miles typical.',NULL,0,'ACTIVE — sub-format split from Ultramarathon (Road and Trail) parent',ARRAY['running'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling','1.5 hrs (short TT/XCS) to 9+ days (Race Across America)','Individual for road/gravel/TT/XCO/Enduro. Team TT: 4-8 rider teams. Mountain Marathon XCM: solo. RAAM: solo or relay teams.',FALSE,'NO for sanctioned events (courses marked). YES for ultra-gravel (Unbound 200 has nav elements between checkpoints). YES for bikepacking (GPS route-following or map navigation).',FALSE,'NO for most formats. PARTIAL for ultra-endurance (RAAM, 24-hr events) — sleep management is a performance variable.',FALSE,'MINIMAL for road/TT. MODERATE for gravel (nutrition, tools, tubes — self-supported). MINIMAL for XC MTB. STANDARD for Enduro (mandatory protective kit: helmet, knee pads, back protector in some events).',NULL,NULL,FALSE,'NO for road/gravel/TT. PARTIAL for Enduro (timed stages to untimed transfer — transition involves quick bike check, food, mental reset).',NULL,0,'ACTIVE — Full detail added (Replaces stub: XC / Enduro MTB)',ARRAY['cycling'],'Pure endurance','Both',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling (Road / Gran Fondo)','1.5 hrs (short gran fondo) to 9+ days (Race Across America)','Individual for most events. RAAM: solo or relay teams.',FALSE,'NO for sanctioned events (courses marked).',FALSE,'NO for most formats. PARTIAL for ultra-endurance (RAAM, 24-hr events) — sleep management is a performance variable.',FALSE,'MINIMAL for road events.',NULL,NULL,FALSE,'NO',NULL,0,'ACTIVE — Sub-format extracted from parent LDC entry',ARRAY['cycling'],'Pure endurance','Both',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling (Gravel)','2.5 hrs (short gravel event) to 2–3 days (ultra-gravel 200+ miles)','Individual.',FALSE,'PARTIAL — Ultra-gravel (Unbound 200) has nav elements between checkpoints. GPS route-following common.',FALSE,'NO for sprint/standard events. PARTIAL for ultra-gravel (200+ miles) — sleep management is a performance variable.',FALSE,'MODERATE — Nutrition, tools, tubes, spare wheel. Self-supported riding mandatory.',NULL,NULL,FALSE,'NO',NULL,NULL,'ACTIVE — Sub-format extracted from parent LDC entry',ARRAY['cycling'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling (Time Trial)','0.25 hrs (10 km TT) to 3.5 hrs (100 km TT)','Individual TT (1 athlete). Team TT: 4–8 rider teams.',FALSE,'NO — Courses fully marked.',FALSE,'NO',FALSE,'MINIMAL — Time trial specific: race kit, aero helmet, timing chip.',NULL,NULL,FALSE,'MINIMAL — TT is pure time effort; minimal transitions between stages.',NULL,0,'ACTIVE — Sub-format extracted from parent LDC entry',ARRAY['cycling'],'Pure endurance','Both',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling (XC Mountain Biking)','0.5 hrs (XCS) to 7 hrs (XCM)','Individual (all formats).',FALSE,'NO — Courses marked; some XCM events have minimal nav between stages.',FALSE,'NO',FALSE,'MINIMAL — Race kit, trail tools, spare tube(s). XCM may include fueling items for 3–7 hrs of riding.',NULL,NULL,FALSE,'NO for single-stage XCO/XCS. MINIMAL for XCM multi-stage (bike check, nutrition between laps).',NULL,0,'ACTIVE — Sub-format extracted from parent LDC entry',ARRAY['cycling'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling (Enduro)','4–8 hrs (single day) to 5+ days (stage race)','Individual.',FALSE,'MINIMAL — Stages are marked; transfers may include nav elements for untimed sections.',FALSE,'PARTIAL for multi-day events — sleep management and recovery between stages is a performance variable.',FALSE,'STANDARD — Mandatory protective kit: helmet, knee pads, back protector (event-dependent). Race kit, tools, spare drivetrain parts.',NULL,NULL,FALSE,'PARTIAL — Timed stage to untimed transfer transition; quick bike check, food, mental reset between stages.',NULL,0,'ACTIVE — Sub-format extracted from parent LDC entry',ARRAY['cycling'],'Technical-dominant','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Duathlon','1 hr – 10 hrs','Individual. Draft-legal at Sprint (ITU format). Non-drafting at Standard+.',FALSE,'NO — course marked.',FALSE,'NO — race durations up to ~10 hrs but sleep deprivation not a standard race element.',FALSE,'NO — no mandatory pack. Nutrition on bike and in pockets.',NULL,NULL,TRUE,'YES — T1 (Run→Bike) and T2 (Bike→Run). Two brick types required. T2 is the harder transition.',2,NULL,'ACTIVE — Full detail added',ARRAY['running','cycling'],'Mixed','Individual',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Aquathlon','30 min – 2 hrs','Individual. Sometimes relay.',FALSE,'NO — course marked.',FALSE,'NO',FALSE,'NO — minimal gear. Wetsuit if cold water. Goggles, swim cap, running shoes.',NULL,NULL,TRUE,'YES — 1–2 transitions (run→swim or swim→run). Simple compared to triathlon.',2,0,'ACTIVE — Full detail added',ARRAY['running','swimming'],'Mixed','Individual',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Aquabike','1.5 hrs – 8 hrs','Individual. Age-group divisions.',FALSE,'NO — course marked.',FALSE,'NO',FALSE,'NO — nutrition on bike and in wetsuit pockets.',NULL,NULL,TRUE,'YES — T1 (Swim→Bike) only. Same as triathlon T1.',2,0,'ACTIVE — Full detail added',ARRAY['cycling','swimming'],'Mixed','Individual',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Swimrun','2 hrs – 14+ hrs','Teams of 2 (mandatory at most events incl. ÖTILLÖ — must stay within 10m). Solo format emerging.',FALSE,'PARTIAL — Some courses marked, some require basic nav to islands/checkpoints.',FALSE,'NO for sprint/standard. Partial for ÖTILLÖ (10–14 hrs).',TRUE,'YES — ALL equipment carried from start to finish (no transition area). Run in wetsuit. Swim in running shoes. Pull buoy strapped to body during runs.',NULL,NULL,FALSE,'N/A — No transition zones. Swim/run alternation is continuous with brief water entry/exit.',NULL,0,'ACTIVE — Full detail added',ARRAY['running','swimming'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo','3 min – 12 hrs (sprint to long distance)','Individual and team formats. Team events: partners must stay within 30s on ascent, 10s on descent. Mixed relay: one male + one female athlete alternating.',FALSE,'PARTIAL — on-snow courses are marked with flags and gates. Some backcountry long-course races require basic mountain navigation. Transition zones are strictly marked.',FALSE,'NO for Sprint/Individual. PARTIAL for long-distance multi-day events.',TRUE,'YES — minimal mandatory kit (avalanche transceiver, probe, shovel in most backcountry events; crampons required; helmet mandatory). Race kit is ultralight — skis, boots, skins, poles, crampons. Every gram matters on ascent.',NULL,NULL,TRUE,'YES — transitions (skin attachment/removal) are a distinct performance variable. Top athletes complete skin-off/on transitions in under 10 seconds. Bootpack transitions (skis to pack) also timed.',NULL,0,'ACTIVE — Full detail added',ARRAY['skiing','climbing'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo (Sprint)','3–4 min per heat (full event 2–3 hrs including rest between heats)','Individual Sprint. Mixed Relay: 1 male + 1 female athlete alternating heats.',FALSE,'MINIMAL — course marked with gates and flags. No route-finding required.',FALSE,'NO — individual heats too short; full event manageable with rest intervals.',FALSE,'MINIMAL — ISMF mandatory safety kit (transceiver, probe, shovel) at backcountry/mountain events.',NULL,NULL,TRUE,'YES — skin removal transition is timed and race-defining. One bad 10-sec transition in a 3-min heat = 5.5% of race time. Target <5 sec. Automaticity under fatigue is the training goal.',3,0,'ACTIVE — Sub-format extracted from parent Skimo entry',ARRAY['skiing','climbing'],'Technical-dominant','Individual',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo (Vertical / VK)','30 min – 90 min','Individual.',FALSE,'MINIMAL — course marked with flags. No descent route-finding required.',FALSE,'NO — race too short.',FALSE,'MINIMAL — ISMF mandatory safety kit at relevant events.',NULL,NULL,FALSE,'MINIMAL — one boot-pack section typically. Skin removal not required at summit (no descent). Boot-pack/crampon application is the primary transition skill.',2,0,'ACTIVE — Sub-format extracted from parent Skimo entry',ARRAY['skiing','climbing'],'Mixed','Individual',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo (Individual / Team)','1.5 hrs – 3.5 hrs','Individual (solo). Team (mandatory pairs). Mixed Relay (1M + 1F).',FALSE,'MINIMAL — marked circuit course. Team proximity rules add a partner-coordination variable.',FALSE,'NO',FALSE,'MINIMAL to MODERATE — ISMF mandatory kit (transceiver, probe, shovel, crampons, emergency bivvy at some events). Race kit is ultralight — every gram affects ascent performance.',NULL,NULL,TRUE,'YES — multiple skin-on/off transitions (5–10+ per race). 5-sec advantage per transition × 8 transitions = 40 sec. Top athletes complete skin transitions in under 10 sec. Boot-pack crampon transitions also timed.',3,0,'ACTIVE — Sub-format extracted from parent Skimo entry',ARRAY['skiing','climbing'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo (Long Distance / Grand Traverse)','5 hrs – 12 hrs','Individual. Team pairs at some events (proximity rules vary by event).',FALSE,'PARTIAL — course marked but complex mountain terrain may require basic route-finding in poor visibility or between marked sections.',FALSE,'PARTIAL — overnight events (Grand Traverse departs at night, finishes at dawn). Night skinning and descent are race variables. Strategic caffeine management relevant for 8–12 hr events.',FALSE,'STANDARD — mandatory safety kit is more extensive for longer events (emergency bivvy, waterproof layers, warm layer, food, water). Pack weight management combined with self-sufficiency.',NULL,NULL,TRUE,'YES — multiple transitions over 5–12 hrs. Transition efficiency under cumulative fatigue (not raw speed) is the priority. Cold-hand management (heavy gloves still functional for skin removal and crampon attachment) is the primary transition challenge.',3,0,'ACTIVE — Sub-format extracted from parent Skimo entry',ARRAY['skiing','climbing','hiking'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Mountain Running / Skyrunning','30 min - 12+ hrs','Individual. Team relay at some events. No mandatory team proximity rules.',FALSE,'PARTIAL - marked courses in most sanctioned events. Long-course and Sky Extreme events may require basic nav in high mountain terrain.',FALSE,'NO for VK/Skyrace. PARTIAL for SkyUltra (>12 hrs).',TRUE,'YES - mandatory safety kit in most events: emergency bivvy, waterproof jacket, whistle, first aid. Volume varies by format. Altitude gear for races above 4000m.',NULL,NULL,FALSE,'NO formal transitions. Aid stations in longer events.',NULL,NULL,'ACTIVE - Full detail added',ARRAY['running'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Fell Running','15 min (short fell sprint) - 24 hrs (rounds/ultras)','Individual. Mountain Marathons: mandatory pairs (2 runners). Rounds: solo or supported.',TRUE,'YES - MANDATORY AND SAFETY-CRITICAL. GPS explicitly prohibited. Map and compass only. No marked route between checkpoints except at critical safety points. Navigation errors have led to fatalities. FRA runs navigation training courses. Most serious incidents occur when runners leave the route.',FALSE,'NO for standard fell races. YES for Mountain Marathons (2-day self-sufficient events with overnight bivvy).',TRUE,'YES - FRA Mandatory Minimum Kit: waterproof whole-body cover (taped seams, integrated hood), hat, gloves, map of route, compass, whistle, emergency food. Kit can be checked and you can be disqualified for non-compliance. Hypothermia has caused multiple fatalities - mandatory kit is a genuine safety requirement, not bureaucracy.',NULL,NULL,FALSE,'NO formal transitions. Mountain Marathons: checkpoint-to-checkpoint with overnight camp as a ''rest transition''.',NULL,NULL,'ACTIVE - Full detail added',ARRAY['running','navigation'],'Pure endurance','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Road)','2 hrs (elite) to 6 hrs (back-of-pack)','Individual. Pace groups available at most major road marathons.',FALSE,'NO — fully marked, mile/km markers throughout.',FALSE,'NO — race duration not sufficient for sleep deprivation issues.',FALSE,'NO pack carry. Hydration belt only for hot races or supplementary fuel.',NULL,NULL,FALSE,'NO formal transitions. Aid stations at 1–2 mile intervals.',NULL,0,'ACTIVE — sub-format split from Marathon (Road and Trail) parent',ARRAY['running'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Trail)','3 hrs (fast trail) to 7+ hrs (technical / wet course)','Individual. Solo navigation rare; courses marked.',FALSE,'PARTIAL — marked but some wilderness-nav events exist.',FALSE,'NO — race duration too short.',FALSE,'MINIMAL — hydration vest, basic kit (whistle, emergency layer for some events).',NULL,NULL,FALSE,'NO formal transitions. Aid stations at variable intervals (3–6 miles typical for trail).',NULL,NULL,'ACTIVE — sub-format split from Marathon (Road and Trail) parent',ARRAY['running'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Mountain)','4 hrs (elite) to 9+ hrs','Individual. Solo; safety-aware due to remote terrain.',FALSE,'PARTIAL — marked but exposure / weather variable.',FALSE,'NO — race duration too short.',FALSE,'MINIMAL to MODERATE — mandatory kit varies (emergency bivvy, waterproof, gloves, hat for high alpine).',NULL,NULL,FALSE,'NO formal transitions.',NULL,0,'ACTIVE — sub-format split from Marathon (Road and Trail) parent',ARRAY['running'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','1.5 hrs (XTERRA sprint) to 8 hrs (long quadrathlon) (Occasional multi-day formats for free-format events)','Individual for most XTERRA and Quadrathlon events. Relay teams permitted at many events. No mandatory team proximity rules (vs. AR).',FALSE,'NO — all courses marked with flags/signs. No map or compass required. Key distinction from Adventure Racing.',FALSE,'NO — race durations too short for sleep deprivation.',FALSE,'MINIMAL — wetsuit (for cold swims), hydration vest optional. No mandatory pack carry equivalent to AR. XTERRA: race nutrition in jersey pockets or bento box. Quadrathlon: kayak-specific gear (PFD, paddle).',NULL,NULL,TRUE,'YES — T1 (Swim→Bike or Swim→Kayak), T2 (Bike or Kayak→Run). Quadrathlon adds a paddle transition unique to the format. Transition efficiency is a performance variable. Brick training applies.',NULL,0,'ACTIVE — Full detail added NOTE: AR but without nav — see Adventure Racing for nav-integrated version',ARRAY['running','cycling','paddling'],'Mixed','Both',TRUE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Cross-Country / Nordic Skiing','3 min (sprint) to 5+ hrs (90km Vasaloppet)','Individual. Team sprint (pairs). Relay (4-person).',FALSE,'NO - courses marked.',FALSE,'NO - max race duration ~5 hrs for 90km events.',FALSE,'MINIMAL - ski, boots, poles, race bib. No pack.',NULL,NULL,FALSE,'NO formal transitions. Skiathlon has one mid-race classic-to-skate equipment change.',NULL,0,'ACTIVE - Full detail added',ARRAY['skiing'],'Pure endurance','Both',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Canoe / Kayak Marathon','ICF race: 90 min - 4+ hrs Ultra: 1 - 14+ days','Individual (K1, C1). Double (K2, C2). Relay for club events.',FALSE,'MINIMAL for ICF (marked courses). PARTIAL for ultra-distance remote sections.',TRUE,'YES for ultra-distance (MR340, Yukon - 88-100 hr limits). NO for ICF standard.',FALSE,'MINIMAL for ICF. SIGNIFICANT for ultra (food, water, safety equipment, repair kit).',NULL,NULL,FALSE,'PARTIAL - portage transitions (boat to land to water) are timed and tactical.',NULL,0,'ACTIVE - Full detail added',ARRAY['paddling'],'Pure endurance','Both',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Canoe / Kayak Marathon (ICF Competition)','1.5 hrs – 4+ hrs (20km ICF junior ~90 min; 30km elite ~3.5–4 hrs)','Individual (K1, C1) and Double (K2, C2). Relay at some club events.',FALSE,'MINIMAL — ICF courses are marked with buoys and gates. Portage path between water entry/exit points may require judgment at some venues.',FALSE,'NO — race duration too short for sleep deprivation.',FALSE,'MINIMAL — boat carry during portages (race-defining physical task, typically 50–200m run with boat). No pack during paddle leg.',NULL,NULL,FALSE,'PARTIAL — portage transitions (water exit → carry → water entry) are timed and highly tactical. Entry/exit speed, boat-carry technique, and water re-entry stabilization are trainable skills that differentiate close finishers.',1,0,'ACTIVE — Sub-format extracted from parent Canoe/Kayak Marathon entry',ARRAY['paddling'],'Pure endurance','Both',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Canoe / Kayak Marathon (Ultra-Distance)','1 day – 4+ days (DW non-stop ~24–30 hrs; Yukon River Quest ~50–88 hrs)','Individual (most formats). Doubles permitted at some events. Relay teams at select ultra-distance events.',FALSE,'PARTIAL — ultra-distance river sections require basic river navigation. Some events use GPS checkpoints; others require reading river flow and portage landmarks. DW non-stop: night paddling with headlamp navigation is a race variable.',TRUE,'YES for non-stop events — DW non-stop (24–30 hrs), Yukon River Quest (50–88 hrs). Sleep management, caffeine timing, and hallucination awareness are race-critical variables for events over 24 hrs. Training implications: include at least one overnight paddle session in peak phase for non-stop events.',FALSE,'SIGNIFICANT for self-supported formats — food, water, safety equipment, repair kit, and overnight gear (if multi-day) carried in boat. Portage pack weight and organization is a logistics and performance variable.',NULL,NULL,TRUE,'YES — portage transitions are extensive and race-defining at ultra distance (DW: 77 portage locks; each requires water exit, boat shoulder/carry, run, water re-entry under accumulating fatigue). Speed and consistency across repeated portage transitions distinguishes finishers from non-finishers.',1,0,'ACTIVE — Sub-format extracted from parent Canoe/Kayak Marathon entry',ARRAY['paddling'],'Pure endurance','Both',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Open Water Marathon Swimming','1:50 hrs (10km elite) to 12+ hrs (channel swims)','Individual. Mass start. No team format in standard events.',FALSE,'NO for sanctioned events. YES for point-to-point channel swims (sighting in open water).',TRUE,'YES for ultra-distance channel swims (15-20+ hrs). NO for 10/25km.',FALSE,'No swim aids beyond standard wetsuit (rules vary by water temp). Feeding cup from pontoon/escort.',NULL,NULL,FALSE,'NO formal transitions. Feed stops at pontoon (deviating from optimal line is a tactical decision).',NULL,0,'ACTIVE - Full detail added',ARRAY['swimming'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Open Water Marathon Swimming (10km / Olympic Distance)','55 min (5km elite) – 3 hrs (10km age-group)','Individual. Mass start. No team format in standard events.',FALSE,'NO for sanctioned loop events — course fully marked with buoys. MINIMAL for point-to-point open water events (sighting required).',FALSE,'NO — race too short (2 hrs max for most athletes).',FALSE,'NO — nutrition from pontoon feeds only (roll on back to receive cup, drink, roll forward). Wetsuit only if water temperature rules permit.',NULL,NULL,FALSE,'NO formal transitions. FEED STOPS (every 2.5km) are tactical decisions — deviating from optimal race line to receive feed costs 8–15 sec. Feed technique (rolling on back, drinking while moving) requires 15–20 training repetitions to become automatic.',1,0,'ACTIVE — Sub-format extracted from parent Open Water Marathon Swimming entry',ARRAY['swimming'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Open Water Marathon Swimming (25km / Ultra Distance)','4.5 hrs (25km elite) – 14+ hrs (channel swims and ultras)','Individual. Some channel swims allow relay team format (staged crossing — each swimmer does a rotation of ~1-hr legs).',FALSE,'NO for sanctioned loop events. YES for point-to-point and channel swims — currents, tides, and shipping lanes require continuous course adjustment, guided by a support boat (pilot). Athlete cannot see their line — pilot navigation is a race variable.',FALSE,'PARTIAL — channel swims and ultra events exceeding 10–12 hrs. Cognitive management, hallucination awareness, and emotional resilience under hypothermia stress are race variables for the longest events. Cold water accelerates cognitive decline relative to warm-water ultra distances.',FALSE,'NO mandatory pack carry. Nutrition from support boat (handled cup or bottle tossed to swimmer) or pontoon every 2.5km. Wetsuit rules: WA events above 16°C no wetsuit; channel/LMS swims: no wetsuit traditional for record attempts and prestige swims.',NULL,NULL,FALSE,'NO formal transitions. FEEDING more complex than 10km — hypothermia slows swallowing and impairs judgment at feeding stops for cold-water events. Pack dynamics over 5–6 hrs differ substantially from 2-hr 10km racing. Night swimming is likely for 10+ hr events — practice required.',1,0,'ACTIVE — Sub-format extracted from parent Open Water Marathon Swimming entry',ARRAY['swimming'],'Pure endurance','Individual',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
INSERT INTO layer0.disciplines (discipline_id,discipline_name,endurance_profile,primary_movement,min_base_phase_text,min_base_phase_weeks_low,min_base_phase_weeks_high,periodization_text,ramp_text,age_adjusted_ramp_text,age_ramp_40_44_pct,age_ramp_45_54_pct,age_ramp_55_plus_pct,taper_norms_text,common_injury_patterns,injury_preceding_behaviors,recovery_priority_text,recovery_modalities,evidence_quality_text,stimulus_components,etl_version,etl_run_at) VALUES ('D-001','Trail Running','Pure endurance',NULL,'4–6 weeks easy aerobic (RPE ≤ 6, flat/moderate terrain) before tempo, hill work, or speed work. New to trail: 8 weeks.',4,6,'BASE: 4–8 wks (easy aerobic, form, weekly long run) BUILD: 6–10 wks (tempo, hill reps, back-to-back long days, peak volume) PEAK: 3–4 wks (race simulation, sport-specific demands) TAPER: 2–3 wks','ACWR 0.8–1.3 (preferred — individualized) Flat % heuristic: max 10%/week mileage EVIDENCE: Increases >20–30%/week associated with significantly elevated RRI (Damsted, Nielsen, Winter). 10% rule is a heuristic; ACWR is better-supported (27-study SR, Maupin 2020).','40–44: Standard ramp; add 1 easy/recovery day if training 5+ days/week. 45–54: Max 8%/week. Tendon lag 6–10 wks. Recovery between hard sessions: 48–72 hrs. 55+: Max 5–7%/week. Deload every 3rd week. Frequency > single-session volume.',NULL,8.0,5.0,'2–3 weeks (55+: 3 weeks) Volume cut: 40–50% Maintain 1–2 intensity sessions/week',ARRAY['IT Band Syndrome','Plantar Fasciitis','Stress Fractures (tibia, metatarsal)','Patellar Tendinopathy','Achilles Tendinopathy','Ankle sprains'],ARRAY['Mileage spike >15–20%/week','Too much downhill too soon','Insufficient B2B recovery','Worn footwear (>500 miles)','Ignoring early Achilles/ITB tightness'],'1. Sleep (8+ hrs) 2. CWI lower body (11–15°C, 10–15 min) after eccentric sessions 3. Protein within 30–60 min 4. Active recovery (easy walk or bike) 5. Compression (lower limb)',ARRAY['Sleep (8+ hrs) 2. CWI lower body (11–15°C, 10–15 min) after eccentric sessions 3. Protein within 30–60 min 4. Active recovery (easy walk or bike) 5. Compression (lower limb)'],'ACWR / ramp: Strong (multiple meta-analyses) CWI for DOMS: Strong (Moore et al. 2023, 28 RCTs) Masters injury epidemiology: Strong (UT Austin SR)',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-002','Road Running','Pure endurance',NULL,'No hard minimum. 2–3 weeks easy aerobic before structured tempo or intervals. Athletes coming from cycling base: cardiovascular fitness transfers but running musculoskeletal tolerance must still be built progressively.',2,3,'BASE: 4–6 wks (easy aerobic, form work, frequency building, no quality sessions) BUILD: 6–8 wks (tempo, intervals, long run progression, brick runs for triathlon) PEAK: 3–4 wks (race-pace work, long run at race effort, brick-specific pacing practice) TAPER: 2 wks (cut volume 40–50%, maintain frequency and 1 intensity session)  TRIATHLON NOTE: Running is the final discipline — run after cycling always. Brick training (Bike→Run) is mandatory from Build phase onward. First 2–10 min of run will always feel biomechanically abnormal; train through it.','ACWR 0.8–1.3 (preferred). Flat % heuristic: max 10%/week mileage.  TRIATHLON-SPECIFIC: Running injury rate is highest of the three triathlon disciplines (systematic review, PMC8884864; short-course SR, PMC10980869). Overuse injuries from running are 37–91% in triathletes (range reflects elite vs. non-elite). Running volume should be conservative relative to total training load — cycling and swimming provide aerobic stimulus with lower injury risk per hour.  SWIM-FIRST PROTECTIVE EFFECT: Swimming volume negatively associated with injury incidence in triathletes and runners (IJSPT 2025) — suggests swim acts as protective cross-training.','40–44: Standard ramp; monitor closely if athlete has running-dominant background (easy to over-run relative to cycling base). 45–54: Max 8%/week. Tendon lag: 6–10 wks. Two easy days per week during build. 55+: Max 5–7%/week. Deload every 3rd week. Prioritize frequency (5×30 min) over long-session volume.',NULL,8.0,5.0,'2 weeks (55+: 3 weeks) Volume cut: 40–50% Maintain frequency and 1 quality session (but shorter) BRICK RUNS: Continue short brick runs (20 min) even in taper — neuromuscular pattern maintenance',ARRAY['Plantar Fasciitis','IT Band Syndrome','Patellar Tendinopathy','Achilles Tendinopathy','Shin Splints','Hamstring strain','Stress fractures (metatarsal, tibia)
INSERT INTO layer0.sport_discipline_map (sport_name,discipline_id,discipline_name,applicability,role,race_time_pct_text,race_time_pct_low,race_time_pct_high,sport_specific_context,b2b_pairing_rule_text,phase_load_text,etl_version,etl_run_at) VALUES ('Adventure Racing','D-001','Trail Running','INCLUDED','Primary','8–15% (Expedition AR: hike-walking dominates foot share; running reserved for runnable flats.)',8.0,15.0,'Always with 25–35 lb race pack. Add pack from Week 1 at 15 lb; escalate to race weight by Week 6–8. Power hiking uphills is faster than running in AR — train it. Night running is common.','→ Hiking: PREFERRED → XC Cycling: PREFERRED (standard brick) → Packraft/Kayak: ACCEPTABLE','Base: 12–15% / Build: 12–15% / Peak: 10–14% / Taper: 10–12%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-003','Trekking','INCLUDED','Primary','18–30% (Trek is the primary foot discipline in expedition AR; long loaded hike legs of 20–50 km common.)',18.0,30.0,'Always fully loaded. Nav-dense legs — use hiking pace to plan ahead for run legs. Night hiking common. Creek crossings and bushwhack terrain expected.','→ Trail Running: PREFERRED → XC Cycling: PREFERRED → Packraft/Kayak: ACCEPTABLE','Base: 15–20% / Build: 18–22% / Peak: 18–22% / Taper: 12–15%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-006','Road Cycling','INCLUDED','Primary','0–15% (XC/gravel cycling rare in expedition AR; MTB dominates the bike leg. Range supports occasional road-section AR formats.)',0.0,15.0,'Full race pack on bike. Eating and drinking while riding is a race skill — practice every long ride. Conservation pace (RPE 5–6.5) — cycling legs are relative recovery in AR.','→ Trail Running: PREFERRED → MTB: PREFERRED → Packraft/Kayak: ACCEPTABLE','Base: 20–25% / Build: 22–28% / Peak: 20–25% / Taper: 15–20%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-008','Mountain Biking','INCLUDED','Primary','35–55% (Mountain Biking is the dominant time block in expedition AR. Sea-to-Sea published 60% of distance on bike → 35–55% of time once trek-slow-down accounted for. Was 10–20% in v11 — materially wrong.)',35.0,55.0,'Full race pack. Technical sections with pack = different COG — must train specifically. Know when to dismount vs. ride — a crash costs more time than a walk. Night MTB if race includes night.','→ Trail Running: PREFERRED → XC Cycling: PREFERRED → Rock Climbing: AVOID','Base: 8–12% / Build: 10–15% / Peak: 12–16% / Taper: 8–10%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-009','Packrafting','INCLUDED','Primary','10–25% (Packraft is the typical AR paddle craft when course requires portage-friendly boat.)',10.0,25.0,'Packraft is mandatory kit — carried deflated on back during other legs (adds 4–7 lb). Inflation and deflation under fatigue with cold hands is a race-critical skill. Train the transition drill.','→ Trail Running: PREFERRED (paddle→run) → Hiking: PREFERRED → Rock Climbing: AVOID','Base: 5–8% / Build: 8–10% / Peak: 8–10% / Taper: 5–8%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-010','Kayaking','INCLUDED','Primary','10–25% (Flat-water kayak alternates with packraft as the typical AR paddle craft.)',10.0,25.0,'Gear stored in kayak (not on body) during paddle legs. After kayak leg, pack returns to back — transition is a skill. Ocean kayak: tide and current awareness. River: class of whitewater varies by race.','→ Trail Running: PREFERRED → Hiking: PREFERRED → Rock Climbing: AVOID','Base: 5–8% / Build: 8–10% / Peak: 8–10% / Taper: 5–8%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-011','Canoeing','INCLUDED','Primary (race-dependent)','0–15% (Canoeing is race-conditional; some North American expedition AR formats use canoe.)',0.0,15.0,'Team paddling (2 per boat). Partner coordination is a performance variable. Stern paddler holds bearing; bow provides power. Train with actual race teammate.','→ Trail Running: PREFERRED → Hiking: PREFERRED','Base: 2–5% / Build: 5–8% / Peak: 6–8% / Taper: 3–5% (Only if race-confirmed)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-012','Rock Climbing','INCLUDED','Secondary','0–5%',0.0,5.0,'Arrive at base physically exhausted and still need to climb. Full race pack may be worn or clipped to harness. Fixed top-rope or easy lead — focus on technique and energy management, not grade.','→ Abseiling: PREFERRED → Via Ferrata: PREFERRED → Paddle (any): AVOID','Base: 3–5% / Build: 3–5% / Peak: 4–6% / Taper: 2–3% (Sessions are short; high tendon load)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-013','Abseiling','INCLUDED','Minor','0–2%',0.0,2.0,'Pre-rigged anchors set by race org. Primary challenge: managing device with fatigued hands in the dark. Pack worn during descent changes COG — practice specifically.','→ Rock Climbing: ACCEPTABLE → Hiking: PREFERRED (post-abseil)','Base: 0–1% / Build: 1–2% / Peak: 1–2% / Taper: 0–1% (Technique acquisition; not volume-based)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-014','Via Ferrata','INCLUDED','Minor','0–3%',0.0,3.0,'Y-lanyard clip-in must be automatic. Pack significantly increases effort. Psychological component (exposure) is the primary prep challenge beyond the physical. Never separate from team on exposed ridgeline.','→ Rock Climbing: PREFERRED → Abseiling: PREFERRED → Paddle (any): AVOID','Base: 0–1% / Build: 1–2% / Peak: 1–2% / Taper: 0–1%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-004','Swimming','INCLUDED','Minor','0–2%',0.0,2.0,'Unexpected, cold, in moving water — very different from triathlon swim. Pack must be waterproofed or used as flotation. Cold shock response management is safety-critical.','→ Hiking: ACCEPTABLE → Running: ACCEPTABLE','Base: 0–2% / Build: 1–2% / Peak: 1–3% / Taper: 1–2% (Recovery + safety skill)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-017','Snowshoeing','INCLUDED','Minor','0–5%',0.0,5.0,'Replaces hiking in snow terrain. Wider stance gait — hip abductors fatigue faster. Trail breaking in fresh snow significantly harder than following tracks.','→ Hiking: PREFERRED → Mountaineering: PREFERRED','Base: 0% / Build: 1–2% / Peak: 1–2% / Taper: 0% (Winter/mountain races only)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-018','Mountaineering','INCLUDED','Minor','0–5%',0.0,5.0,'Glacier/snowfield travel with crampons. Very rare in standard AR — more common in Patagonia, European Alpine, or expedition races. Guided training non-negotiable.','→ Snowshoeing: PREFERRED → Hiking: PREFERRED → XC Cycling: AVOID (altitude fatigue + cycling = AMS risk)','Base: 0% / Build: 1–2% / Peak: 1–2% / Taper: 0–1% (Race-relevant only)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon','D-004','Swimming','INCLUDED','Primary','Swim: 15–22% of race time (Olympic elite ~25min of ~120min = ~21%; lower for fast swimmers.)',15.0,22.0,'WETSUIT: Legal at water temps ≤24.5°C in most events — provides buoyancy and warmth. Train with wetsuit monthly from Build phase onward; first time in wetsuit on race day is a mistake.  SIGHTING: Every 6–10 strokes in open water (more in chop). Lift eyes only — not full head raise. Landmark sight, not buoy sight where possible (landmark is bigger).  DRAFTING: In draft-legal ITU racing, swim drafting (feet of swimmer ahead) estimated 6–10% energy savings. Train positioning in pool. Not legal in non-draft events but occurs naturally in mass starts.  MASS START: Seeding by expected swim time. Start wide to avoid contact if not confident in contact swimming. Practice in open water group swim sessions.  T1 TRANSITION: Wetsuit removal requires practice — zipper pull, foot step-out, not standing on suit. Time this. Goggle/cap removal. Run to bike. Helmet ON before touching bike (mandatory).  PERFORMANCE PREDICTOR: Swimming is strongest predictor of overall performance in Olympic-distance triathlon (PMC8131838, n=16,667). At Sprint distance, cycling predicts better — swim differences compress at shorter distances.','→ Road Cycling (T1): PREFERRED — upper body swim fatigue does not impair cycling; legs are fresh. Standard triathlon sequence. → Road Running: ACCEPTABLE (swim → run directly in sprint sim or aquathlon) → Strength: ACCEPTABLE same-day if swim is easy','Base: 15–20% / Build: 15–20% / Peak: 12–15% / Taper: 10–12%  NOTE: Swim volume is lower than its importance might suggest — injury risk is lowest of three disciplines; benefit per hour is high; serves as active recovery tool on heavy bike/run days.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon','D-006','Road Cycling','INCLUDED','Primary','Bike: 45–55% of race time (Sprint ~30–45 min, Olympic ~60–75 min, 70.3 ~2.5–4 hrs, IM ~5–8 hrs)',45.0,55.0,'BIKE TYPE: • Road bike: standard for sprint/Olympic beginners. More comfortable, more handling ability, legal in all events. Recommended for first year of triathlon. • Tri bike: purpose-built for non-drafting long-distance tri. Aero position, forward seat (hip angle for run-off), nutrition/hydration storage. Requires a separate bike fit from road bike — not interchangeable. • TT bike: UCI-legal time trial bike. Stiffer, less comfortable, less storage than tri bike. Sometimes used in triathlon by road cyclists — less ideal for self-supported efforts. • Clip-on aerobars on road bike: good intermediate step; retains road handling while gaining some aerodynamic benefit.  SWITCHING TO TRI BIKE: Do this in Base or early Build phase — not in peak or taper. Requires 4–8 weeks of adaptation rides before any intensity sessions in new position.  DRAFTING RULES: Non-drafting (most age-group events): 12m draft zone — if you enter, you must pass within 20 seconds. Penalty for violations. Practice riding alone at race pace.  T2 TRANSITION: Dismount before line, rack bike, swap shoes (or use elastic laces), helmet off, run. Practice this sequence.  PERFORMANCE: Cycling predicts overall performance in Sprint and 70.3 (PMC8131838). Training split observed in real triathletes: 48% of training time is cycling (Andersen et al. 2013). This aligns with its race time dominance.  BRICK PACING: Lower cycling intensity in final 1–2 km before T2 — research shows this reduces blood lactate spike and improves run-off biomechanics (PMC9344700).','→ Road Running (T2 brick): PREFERRED — the defining triathlon training unit. Brick runs (Bike→Run) mandatory in Build and Peak phases, 1×/week minimum. → Open Water Swimming: ACCEPTABLE same-day (swim easy before bike for aerobic maintenance) → Strength: ACCEPTABLE after cycling if not a hard bike day','Base: 40–45% / Build: 42–50% / Peak: 40–48% / Taper: 35–40%  NOTE: Highest volume allocation at every phase. Reflects both race time dominance and low injury-per-hour risk vs. running. Observed real-world training split (Andersen et al. 2013): 48% cycling.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon','D-007','Time-Trial Cycling','INCLUDED','Primary',NULL,0.0,0.0,'BIKE TYPE: • Road bike: standard for sprint/Olympic beginners. More comfortable, more handling ability, legal in all events. Recommended for first year of triathlon. • Tri bike: purpose-built for non-drafting long-distance tri. Aero position, forward seat (hip angle for run-off), nutrition/hydration storage. Requires a separate bike fit from road bike — not interchangeable. • TT bike: UCI-legal time trial bike. Stiffer, less comfortable, less storage than tri bike. Sometimes used in triathlon by road cyclists — less ideal for self-supported efforts. • Clip-on aerobars on road bike: good intermediate step; retains road handling while gaining some aerodynamic benefit.  SWITCHING TO TRI BIKE: Do this in Base or early Build phase — not in peak or taper. Requires 4–8 weeks of adaptation rides before any intensity sessions in new position.  DRAFTING RULES: Non-drafting (most age-group events): 12m draft zone — if you enter, you must pass within 20 seconds. Penalty for violations. Practice riding alone at race pace.  T2 TRANSITION: Dismount before line, rack bike, swap shoes (or use elastic laces), helmet off, run. Practice this sequence.  PERFORMANCE: Cycling predicts overall performance in Sprint and 70.3 (PMC8131838). Training split observed in real triathletes: 48% of training time is cycling (Andersen et al. 2013). This aligns with its race time dominance.  BRICK PACING: Lower cycling intensity in final 1–2 km before T2 — research shows this reduces blood lactate spike and improves run-off biomechanics (PMC9344700).','→ Road Running (T2 brick): PREFERRED — the defining triathlon training unit. Brick runs (Bike→Run) mandatory in Build and Peak phases, 1×/week minimum. → Open Water Swimming: ACCEPTABLE same-day (swim easy before bike for aerobic maintenance) → Strength: ACCEPTABLE after cycling if not a hard bike day','Base: 40–45% / Build: 42–50% / Peak: 40–48% / Taper: 35–40%  NOTE: Highest volume allocation at every phase. Reflects both race time dominance and low injury-per-hour risk vs. running. Observed real-world training split (Andersen et al. 2013): 48% cycling.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon','D-002','Road Running','INCLUDED','Primary','Run: 25–35% of race time (Olympic elite ~35min of ~120min = ~29%.)',25.0,35.0,'BRICK CONTEXT: Triathlon running is always after cycling — never a fresh run. The bike-to-run transition causes: reduced stride length, altered O2 utilization in periphery, elevated perceived effort for equivalent pace, ''brick legs'' sensation (2–10 min duration for most athletes).  RESEARCH: Intense cycling prior to running impairs economy via reduced stride length and peripheral O2 utilization (PMC6572577). Brick training specifically improves knee behavior and biomechanical adaptability at T2 (ResearchGate 2010). Lowering cycling intensity in final 1–2 km before dismount measurably reduces the run-off decrement (PMC9344700).  PACING STRATEGY: First 0.5–1 mile of run: shorten stride, run by feel not pace — legs need time to recruit running-specific motor patterns. Do not chase pace numbers in first mile. First-mile pace in race can be 20–45 sec/mile slower than target without performance cost.  PERFORMANCE PREDICTOR: Running is strongest predictor of overall performance in Full Ironman (PMC8131838) — at IM distance, who runs best wins. At shorter distances, cycling and swimming are relatively more important. Train accordingly by race distance.  INJURY RISK: Running causes most triathlon overuse injuries. Systematic reviews across both short and long distance: knee most common site. Running volume should be conservative relative to total training load.  80/20 INTENSITY: Age-groupers do ~69% training at low intensity, 25% moderate (Stirling 2011). Optimal is ~80% low / 20% high. Training too much in the moderate ''grey zone'' is the most common intensity distribution error.','→ Open Water Swimming: PREFERRED — run → swim is ideal next-day recovery (pool swim is lowest impact) → Road Cycling: PREFERRED as same-day sequence (run → easy bike = classic brick in reverse, used as cooldown) → Strength: ACCEPTABLE after easy runs; AVOID after long runs or brick runs','Base: 28–32% / Build: 28–33% / Peak: 28–35% / Taper: 28–32%  NOTE: Run % stays relatively stable across phases — volume increases are in absolute hours, not percentage. Running injury risk limits aggressive volume spikes. Brick runs (counted here) are the key quality sessions in Build and Peak.  FULL IM ATHLETES: Increase run allocation to upper end of range in Peak — run predicts IM performance more than any other discipline.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Trail)','D-001','Trail Running','INCLUDED','Primary','50–65% of race time (Power-hiking included; Damian Hall published ~60% running, ~40% hiking for UTMB.)',50.0,65.0,'Trail running on technical terrain with periodic power hiking on steep climbs. Pace by HR/effort, not distance — slower than road equivalents.','Run → Power Hike → Run transitions are continuous within a single session, not formal bricks.','Base: 65–75% / Build: 58–68% / Peak: 55–65% / Taper: 67–77%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Trail)','D-024','Mountain Running','INCLUDED','Primary','15–30% of race time (course-dependent)',15.0,30.0,'Sustained-grade ascent. Typical trail ultras have major climbs (UTMB ~10000m gain in 100M).','Power hike transition: integrate within long sessions when grade exceeds run-economic threshold (varies by athlete, typically >12-15% sustained).','Base: 7–13% / Build: 12–18% / Peak: 15–21% / Taper: 8–14%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Trail)','D-002','Road Running','INCLUDED','Secondary (*Conditional)','0–15% (situational)',0.0,15.0,'*Conditional — REPLACES Trail+PH volume, NOT additive. Used when trail unsafe, for measurable pace work, or limited trail access.','Standalone road sessions; no brick relationship with other ultra disciplines.','Base: 10–25% / Build: 8–20% / Peak: 5–15% / Taper: 15–30% (Conditional — zero out for sum-to-100 validation)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Trail)','D-018','Mountaineering','EXCLUDED','—','—',NULL,NULL,'Excluded for trail ultras. Trail ultra terrain may include exposed sections but does not require true mountaineering skills.','—','—','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Road)','D-002','Road Running','INCLUDED','Primary','95–100% of race time',95.0,100.0,'Standard road running mechanics. Long-run progression dominates. No technical terrain.','No bricks within Ultra (Road). Standalone discipline.','Base: 81–91% / Build: 81–91% / Peak: 83–93% / Taper: 83–93%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Duathlon','D-002','Road Running','INCLUDED','Primary','Total run: 40–55% of race time (R1 ~25%, R2 ~16%; combined run dominates over bike for standard duathlon.)',40.0,55.0,'R1 PACING (the critical decision): Approach R1 as the opening of a half-marathon, NOT a standalone run. Start too fast in R1 and you sacrifice the bike AND R2. Elite duathletes (Q1) are among the relatively slowest in R1 — they bank energy for what follows (MDPI 2018, Powerman Zofingen data).  R1 TARGET: ~75–85% of standalone 10km race pace. Err conservative.  R2 CONTEXT: This is the most race-specific stimulus. Bike→Run (T2) transition in duathlon is harder than triathlon''s T2 — legs carry fatigue from BOTH R1 and the bike, not just the bike. R2 is where races are won. Fastest athletes are fastest in R2 (research confirmed).  R2 TRAINING: Weekly Bike→Run brick is mandatory from Build phase. Include also a Run→Bike brick 1×/week to train T1. R2 brick runs should feel hard but sustainable — if they feel impossible, R1 or bike pacing was too aggressive.  OFF-ROAD DUATHLON: Replace D-002 with D-001 (trail running). Same pacing principles apply with terrain-specific adjustments.','→ Road Cycling (T1 brick): PREFERRED — the primary duathlon training unit → Strength: ACCEPTABLE after easy R1 simulation runs','Base: 35–42% / Build: 32–40% / Peak: 32–40% / Taper: 35–42%  NOTE: Run % is higher than triathlon because there is no swim to share the load. Running dominates training volume. Injury risk from running volume is the primary training management challenge in duathlon.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Duathlon','D-006','Road Cycling','INCLUDED','Primary','Bike: 45–60% of race time (Standard 10/40/5: ~60min bike of ~120min total. Powerman Zofingen long-distance approaches 50% bike.)',45.0,60.0,'PACING (counter-intuitive finding): The fastest duathletes are RELATIVELY SLOWEST on the bike compared to slower athletes. They conserve on the bike to run fast in R2. This is the most important tactical insight in duathlon racing.  BIKE TARGET: 75–80% FTP / Zone 3 HR maximum. Power meter is the most reliable pacing tool (HR drifts under pre-fatigue).  FINAL 3–5 KM OF BIKE: Reduce power, shift to easier gear, increase cadence to 90–100 rpm. This reduces mechanical muscle fatigue and improves R2 running mechanics at T2.  DRAFTING: Sprint duathlon is often draft-legal (ITU format) — practice bunch riding skills. Standard+ events are non-drafting.  BIKE FIT: Same considerations as triathlon cycling. Aero position optional — many duathletes use road bikes. Tri bike appropriate for non-drafting events.  OFF-ROAD: Replace D-006 with D-008 (MTB). Full pack not required; MTB-specific skills mandatory.','→ Road Running (T2 brick): PREFERRED — most race-critical training unit → Road Running (T1 brick — Run→Bike): PREFERRED — specific to duathlon, not standard in triathlon','Base: 42–50% / Build: 42–52% / Peak: 40–50% / Taper: 35–45%  NOTE: Bike is the highest single allocation — mirrors its 57% race time dominance. Cycling carries lower injury-per-hour risk than running, supporting higher volume.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Aquathlon','D-004','Swimming','INCLUDED','Primary','Swim: 35–50% of race time (Elite 1km swim ~11–12min vs. 5km run ~15–17min → swim ~42%.)',35.0,50.0,'TRANSITION CONTEXT: Swim→Run transition (or Run→Swim→Run). No bike — transition is simpler than triathlon. Wetsuit removal (if cold water) + run shoes on + go.  WARM WATER FORMAT (≥22°C): Run first, then swim, then run. The swim interrupts running fatigue — very different physiological pattern from cold water. First run pace sets swim approach.  COLD WATER FORMAT (<22°C): Swim first, then run. Similar to triathlon T1→run sequence. Upper body swim fatigue does not significantly impair running.  SIGHTING: More critical in aquathlon than triathlon — no bike to ''reset'' if you go off course. Good sighting practice is essential.  FOR TRAINING: Pool sessions (3×/week in base) + open water sessions (2× in build/peak). Wetsuit practice in cold water conditions matches race reality in most Canadian/Northern European events.','→ Road Running (swim→run): PREFERRED — the primary aquathlon training unit → Strength: ACCEPTABLE (swim before strength on same day)','Base: 25–35% / Build: 30–38% / Peak: 28–35% / Taper: 22–28%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Aquathlon','D-002','Road Running','INCLUDED','Primary','Run: 50–65% of race time (5km run(s) dominate by small margin; widens for slower swimmers.)',50.0,65.0,'WARM WATER FORMAT: Two running legs (2.5km + 2.5km) surrounding a swim. R1 pacing similar to duathlon — don''t blow up. Swim provides partial recovery between run legs.  COLD WATER FORMAT: Single post-swim run (5km). Run after swimming — upper body fatigue from swim does NOT impair run mechanics as severely as cycling does. Transition from swim to run is smoother than bike to run.  TRAINING: Run is the dominant discipline by time. Standard running injury prevention rules apply (ACWR 0.8–1.3). Include 1 swim→run brick per week from Build phase — minimal equipment, easy to execute.  INTENSITY: Aquathlon is shorter and more intense than triathlon — Sprint/Olympic pace, not Ironman pace. VO2max-level efforts are common. Train with intervals, not just Zone 2.','→ Open Water Swimming (run→swim): PREFERRED → Strength: ACCEPTABLE after easy runs','Base: 55–65% / Build: 55–62% / Peak: 55–65% / Taper: 60–68%  NOTE: Running dominates — no bike in aquathlon. Highest injury risk per discipline. Keep ACWR in check. Supplement with swimming as active recovery on hard run days.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Aquabike','D-004','Swimming','INCLUDED','Primary','Swim: 25–35% of race time (Elite ~25min swim / ~60min bike → 29% swim. Age-group higher as bike slows more than swim.)',25.0,35.0,'IDENTICAL TO TRIATHLON T1: Same swim format, same wetsuit-removal T1, same sighting demands. Swim training and race-day swim approach are identical to triathlon.  KEY DIFFERENCE FROM TRIATHLON: No run after the bike. Athletes who struggle with running (injury, joint issues) can train the swim and bike without the run-off fatigue management. Swim training can be slightly more aggressive since post-bike run recovery isn''t a concern.  FOR ATHLETES TRANSITIONING FROM TRIATHLON: No major adjustments needed for swimming component. Bike component carries more relative weight — can push harder on bike without saving legs for a run.','→ Road Cycling (T1 — swim to bike): PREFERRED → Strength: ACCEPTABLE (upper body focus post-swim)','Base: 18–22% / Build: 18–22% / Peak: 15–20% / Taper: 15–18%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Aquabike','D-006','Road Cycling','INCLUDED','Primary','Bike: 65–75% of race time (Complementary to swim; ~71% elite.)',65.0,75.0,'DOMINANT DISCIPLINE: With no run, cycling is the entire second half of the race — no recovery between T1 and finish. Bike training takes absolute priority.  PACING DIFFERENCE FROM TRIATHLON: No run-off to conserve for. Athletes can push higher cycling intensity than in triathlon — approximately 85–88% FTP target vs. 75–82% FTP in triathlon (no need to protect legs for run).  TRI BIKE / AERO: Strong case for TT/tri bike in aquabike — long bike leg, no run-off fit considerations. Optimal aero position is more aggressive than triathlon-specific fit since hip angle doesn''t need to prioritize run mechanics.  TRAINING EMPHASIS: Long rides (Zone 2) + threshold intervals. No brick runs. Can increase total cycling volume above triathlon recommendations since running injury risk is eliminated.  ATHLETE PROFILE: Popular with athletes managing running injuries. Allows full bike training load without run impact stress.','→ No mandatory brick run → Can pair with easy swim for swim→bike simulation → Strength: ACCEPTABLE after recovery rides','Base: 60–68% / Build: 62–70% / Peak: 62–70% / Taper: 55–62%  NOTE: Bike allocation is higher than triathlon across all phases — reflects the elimination of running. No need to balance bike load against run injury risk or T2 leg preservation.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Swimrun','D-004','Swimming','INCLUDED','Primary','12–22% (swim segments) (ÖTILLÖ published 12.8% swim for fast teams; rises to ~20% for slower teams as swim pace flattens vs run pace.)',12.0,22.0,'Wetsuit + buoy. Cold water exposure (some races). Pulling strength critical.','Swim → Run brick is the swimrun-specific session. Build from mid-Build phase.','Base: 30–35% / Build: 20–25% / Peak: 18–22% / Taper: 15–18%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Swimrun','D-002','Road Running','INCLUDED','Primary','78–88% (run segments) (Complementary; ~87% for fast teams. Run in wetsuit/wet shoes.)',78.0,88.0,'Wet shoes after each swim leg. Technical terrain post-water.','Run → Swim brick (less common but valid). Practice transitions on long brick days.','Base: 45–50% / Build: 38–45% / Peak: 38–44% / Taper: 38–44%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo','D-021','Uphill Skinning','INCLUDED','Primary','Skinning: 55–70% of race time (Ascents dominate; uphill slower than downhill at equivalent vert. Bootpack included.)',55.0,70.0,'SEASONAL STRUCTURE — UNIQUE TO SKIMO:  OFF-SNOW (spring/summer/fall): Trail running and uphill hiking are the primary training modalities. The aerobic engine built off-snow transfers directly to skinning performance. Athletes without consistent snow access can train 80%+ of their skimo fitness through dry-land work. Uphill hiking with poles closely mimics the movement pattern.  ON-SNOW (winter): Skinning sessions replace uphill runs. Vertical gain per week is the load metric, not hours or distance. A 1,500m vertical week is a light week; 4,000m+ is peak individual race prep.  PACE ZONES: Uphill skinning intensity maps roughly to XC skiing zones: • Zone 1–2: sustained aerobic climbing (80%+ of training) • Zone 3–4: threshold intervals (uphill circuits, used sparingly) • Zone 5: race-intensity sprints (peak phase only)  POLE USE: Poles are essential — double-pole pushing on flatter sections, single plant on steep. Pole technique is a trainable performance variable. Practice off-season with hiking poles.  AVALANCHE SAFETY: Mandatory kit in all backcountry and many resort race formats. Transceiver, probe, shovel must be carried. Check event rules. Olympic/groomed-resort races: avalanche-controlled — kit requirements relaxed.','→ Downhill Descent (D-022): PREFERRED (every uphill ends in descent) → Boot-packing (D-023): PREFERRED (integrated in same race circuit) → Trail Running (D-001): PREFERRED as dry-land training substitute → Road Cycling (D-006): ACCEPTABLE as aerobic cross-training off-season','OFF-SNOW BASE: ~65–75% of weekly training hrs PRE-SEASON: Skinning 50–60% / Descent 20–25% / Strength 15–20% BUILD: Skinning 55–65% / Descent 20–25% / Boot-pack/transitions 5–8% / Strength 10–12% PEAK: Skinning 50–60% / Descent 22–28% / Boot-pack/transitions 8–10% / Strength 8–10% TAPER: 40–50% volume cut across skinning and descent','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo','D-022','Alpine Descent','INCLUDED','Primary','Descent: ~20–35% of race time (Individual and Team formats) Vertical race: 0% (ascent only)',20.0,35.0,'HIGHEST INJURY RISK SECTION: 65.6% of all skimo injuries occur on descent (PMC9782121). Technical descent skill is the primary injury prevention variable in this discipline.  EQUIPMENT TRADE-OFF: Skimo skis (700–750g each minimum per ISMF rules) are narrower and less stable than recreational touring skis. Athletes must adapt to reduced control. Do not assume road-to-skimo descent skills transfer without specific practice.  DESCENT TYPES BY FORMAT: • Sprint: gate course, feature-based (jumps/bumps per ISMF rules), athletic and technical • Individual/Team: natural terrain, off-piste possible, variable conditions • Vertical: NO descent — ascent only  SKIN REMOVAL BEFORE DESCENT: Transition zone only. Skins must be stowed (not dropped — penalty). Timing counts in race.  DESCENT PACING IN RACE: Not the place to take risks. Crashes = time loss + injury. A conservative descent that avoids falls beats a faster descent with a fall by a large margin. Train this decision-making.','→ Uphill Skinning (D-021): PREFERRED (always follows ascent) → Boot-packing (D-023): ACCEPTABLE (may follow before descent in some circuits)','See D-021 allocation — skinning and descent are trained as integrated units. Descent % tracks with D-021 allocation (see above).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Mountain Running / Skyrunning','D-001','Trail Running','INCLUDED','Primary - Foundation','95–100% of race time (All formats: D-001 is the umbrella discipline; uphill / downhill / scrambling rows below sub-allocate within trail running. Aerobic engine and recovery days.)',95.0,100.0,'ROLE: Easy/recovery days and aerobic volume. Standard D-001 principles apply. Mountain running builds on D-001 - does not replace it.  ALTITUDE: ISF minimum 2000m for skyrunning. VO2max drops ~1-2% per 300m above 1500m. Arrive >=2 weeks before OR <=3 days before race - not in acclimatization window days 3-10.  FOOTWEAR: Mountain running shoes (aggressive lug, stiffer toe box for rocky terrain) - test before races.  NAV: Course-marked in most events. Some long-course and Sky Extreme races require basic map reading.','-> D-024 Uphill: PREFERRED | -> D-024 Downhill: PREFERRED | -> Strength: ACCEPTABLE after easy runs','Base: 55-65% / Build: 40-50% / Peak: 35-45% / Taper: 50-60%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Mountain Running / Skyrunning','D-024','Mountain Running','INCLUDED','Primary','Uphill: ~50-65% of race time in SKY/mountain running | VK: 100% (ascent only)',50.0,65.0,'VK-SPECIFIC: Pure uphill, 30-90 min, near-VO2max throughout. High-intensity intervals on steep grades primary stimulus. Pole use common.  SKYRACE/MOUNTAIN RUNNING: Sustained threshold on climbs. Power hiking above ~25% grade often faster - train the transition.  ALTITUDE: Use RPE not pace/HR above 2500m - HR and pace both become unreliable intensity proxies at altitude.','-> D-024 Downhill: PREFERRED (race sequence) | -> D-001: PREFERRED (recovery day)','Base: 10-15% / Build: 20-30% / Peak: 25-35% / Taper: 15-20% VERTICAL TARGETS: Base 500-1000m/wk | Build 1500-2500m | Peak 2500-4000m | Taper 1000-1500m','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Fell Running','D-001','Trail Running','INCLUDED','Primary - Foundation','95–100% of race time (All categories: D-001 is the umbrella discipline; uphill / downhill / nav rows below sub-allocate. Aerobic engine and recovery days.)',95.0,100.0,'TERRAIN DIFFERENCE FROM STANDARD D-001: Fell terrain is fundamentally different from trail running terrain. Bog, heather, tussock grass, wet moorland. Soft, waterlogged ground is energy-sapping in a specific way - energy cost per km is significantly higher than same-gradient trail running. Train specifically on this terrain type where possible.  FELL-SPECIFIC BASE TRAINING: Hill reps on local fells (not treadmill or road). ''Bog bashing'' - running through heather and wet ground to condition ankles and lower legs for the specific proprioceptive demands. Most fell running clubs run weekly group training on relevant terrain - joining a club is the fastest route to fell fitness.  FOOTWEAR: Fell-specific shoes (studs/rubber lugs for wet grass and peat, not trail shoes for dry rock). Test in training - wrong footwear on wet fell = falls.','-> D-024 Uphill: PREFERRED | -> D-024 Downhill: PREFERRED | -> D-015 Nav: always active','Base: 55-65% / Build: 45-55% / Peak: 40-50% / Taper: 55-65%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Fell Running','D-024','Mountain Running','INCLUDED','Primary','Uphill: 40-60% of race time depending on category (Category A has highest uphill ratio)',40.0,60.0,'POWER HIKING SPECIFIC TO FELL: The hand-on-knee power hike is standard technique on steep UK fell terrain. Hands push directly on knees with each step - opens posture for breathing, conserves quad, moves efficiently on soft/steep ground. Practice this deliberately - not just ''walking fast''.  NO POLES: Fell running tradition and most FRA race rules prohibit or strongly discourage poles. Train without poles - upper body technique relies on arm drive, not pole push. This is a key difference from mountain running/skyrunning.  WET GROUND: Uphill running on soft/wet fell terrain has different energy cost and technique than dry scree or hard trail. Higher knee lift needed in heather. Test foot placement on tussocks (tufts of grass on wet ground) - a twisted ankle risk if you run through rather than around.','-> D-024 Downhill: PREFERRED | -> D-015 Nav: ALWAYS ACTIVE (navigate while climbing) | -> D-001: PREFERRED recovery','Base: 15-20% / Build: 20-28% / Peak: 22-30% / Taper: 15-20% VERTICAL TARGETS (lower than mountain running due to terrain energy cost): Base: 400-800m/wk | Build: 800-1800m | Peak: 1500-2500m | Taper: 600-1000m','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Fell Running','D-003','Trekking','INCLUDED','Primary - Cross-discipline','Navigation: ~5-15% of race time as active decision-making (overlaid on 100% of race - never stops)',5.0,15.0,'FELL NAV IS HARDER THAN STANDARD D-015: Featureless moorland provides few attack points. Thick mist is common - landmarks disappear. Navigation at running pace on wet, energy-sapping ground while physically fatigued is a distinct skill set that must be specifically trained.  GPS PROHIBITED: Explicitly banned by FRA rules for navigation. Map (1:25,000 or 1:50,000 OS maps in UK) and compass only. This is enforced and enforced seriously - GPS use is a disqualification.  CRITICAL SAFETY CONTEXT: Most serious incidents and fatalities in fell racing have occurred when runners left the route. Navigation errors in poor weather with insufficient kit = hypothermia risk. The mandatory kit requirement (waterproofs, whistle, emergency food) exists specifically because of this risk.  NAV TRAINING: FRA runs formal navigation courses (weekend residential, ~100GBP, members only). British Orienteering SPUNCH events and mountain marathons provide nav-under-load practice. Practice in mist and poor visibility deliberately - race-day conditions.  ROUTE CHOICE: Fell racing is partly tactical - optimal route between checkpoints varies by conditions, individual strengths (some runners prefer steep direct lines, others take faster longer routes). Route choice decisions happen at speed under physical load. Train this cognitive skill explicitly.  MOUNTAIN MARATHON FORMAT: Category MM/O events - on-sight nav where map is given at start, staggered start, score or linear format. The purest test of nav under load in fell running.','Always active - not a pairing consideration. Overlaid on all uphill and downhill running continuously.','Base: 3-5% standalone nav sessions / Build: 3-5% + nav integrated in all fell runs / Peak: 5-8% inc race-sim nav / Taper: 2-3%  NOTE: Nav training sessions are in addition to, and do not replace, the running allocation. Standalone nav (orienteering events, nav courses) is extra.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Road)','D-002','Road Running','INCLUDED','Primary','98–100% of race time (Mono-discipline.)',98.0,100.0,'Standard road marathon mechanics. Most standardized running event.','No bricks. Standalone discipline.','Base: 80–90% / Build: 82–92% / Peak: 84–94% / Taper: 84–94%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Trail)','D-001','Trail Running','INCLUDED','Primary','98–100% of race time (Mono-discipline trail; nav element folded in.)',98.0,100.0,'Trail-specific running on technical terrain. Pace slower than road equivalent.','No formal bricks; transitions to power hike on steep grades within a single session.','Base: 80–90% / Build: 82–92% / Peak: 84–94% / Taper: 84–94%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Trail)','D-002','Road Running','INCLUDED','Cross-train (*Conditional)','0–10% (situational)',0.0,10.0,'*Conditional — REPLACES Trail volume, NOT additive. Track for VO2 work, road for recovery when trail unsafe.','Standalone road sessions.','Base: 0–10% / Build: 0–8% / Peak: 0–6% / Taper: 0–8% (Conditional — zero out for sum-to-100 validation)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Mountain)','D-001','Trail Running','INCLUDED','Primary','55–70% of race time',55.0,70.0,'Mountain trail running — steep, technical, high elevation gain/loss.','No formal bricks; uphill/downhill running are integrated within sessions.','Base: 55–65% / Build: 50–60% / Peak: 47–57% / Taper: 55–65%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Mountain)','D-024','Mountain Running','INCLUDED','Primary','15–25% of race time',15.0,25.0,'Sustained climbs (Pikes Peak: 4300m / 14000ft gain). Hill repeats and treadmill incline are off-mountain proxies.','Embedded in long-run climbs; standalone hill repeat sessions.','Base: 12–18% / Build: 17–23% / Peak: 18–26% / Taper: 15–21%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling','D-006','Road Cycling','INCLUDED','Primary — Road Long Distance','95–100% of race time (Century (100 mi): 4-7 hrs; Ultra-endurance road (200+ mi): 8-16+ hrs. Mono-discipline for road-format athletes.)',95.0,100.0,'DURATION CHANGES EVERYTHING ABOVE 4 HOURS: Standard D-006 training (intervals, FTP work) builds the aerobic engine, but events over 4 hours are primarily limited by fueling, pacing discipline, and saddle endurance — not aerobic fitness.  FUELING STRATEGY: Gran Fondo / Century target: 60-90g carbs/hr from hour 1. At 6+ hours: begin introducing solid food (bars, rice cakes, real food) as liquid-only fueling becomes difficult. Train the gut on every long ride over 2 hrs.  SADDLE ENDURANCE: A specific, trainable adaptation. Build long rides progressively — don''t skip from 2-hr rides to a 7-hr event. Chamois cream, proper shorts, bike fit (saddle height + fore/aft) are the primary interventions.  PACING: Even power output (±3-5% of target watts) outperforms variable pacing for events 4+ hours. Power meter is strongly recommended. Start conservatively — the second half of a century is determined by the first hour.  ULTRA-ENDURANCE ROAD (RAAM, 500km+): Adds sleep management, crew logistics, mental fatigue, and progressive nutrition challenges. Treat like ultra running: time on bike > mileage, back-to-back riding days as key training stimulus.','-> D-008 (easy MTB day): ACCEPTABLE as cross-training -> Strength (core): ACCEPTABLE after easy rides','Base: 90-95% / Build: 88-93% / Peak: 88-93% / Taper: 88-95% KEY SESSION: Weekly long ride builds 80% of target event duration (or 70% for events >6 hrs). Final long ride: 2-3 weeks before event.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling','D-030','Gravel Cycling','INCLUDED','Primary — Gravel','95–100% of race time (50-mi gravel: 3-5 hrs; Century gravel: 5-8 hrs; Unbound 200 (ultra-gravel): 10-16 hrs. Mono-discipline for gravel-format athletes.)',95.0,100.0,'GRAVEL IS NOT ROAD CYCLING WITH DIRT: Gravel demands: - LOWER average power than road equivalent due to surface drag (5-15% energy penalty on loose gravel) - TECHNICAL HANDLING under fatigue (gravel cornering, rough washboard sections) — must be practiced specifically - SELF-SUPPORTED NUTRITION: Aid stations are sparse or non-existent at many events. Carry everything. Practice this in training: no stopping at convenience stores. - MIXED SURFACE TRANSITIONS: Smooth asphalt → loose gravel → packed dirt — power output and RPE fluctuate. Train with threshold + tempo intervals interspersed in long rides  TRIANG: The CTS framework for gravel is: muscular endurance (sustained Tempo 20-60 min intervals) as the primary quality session; long endurance rides on mixed terrain as the primary volume session. Add Tempo intervals at the END of long rides to simulate late-race demands.  ULTRA-GRAVEL (Unbound 200+): Back-to-back training days (5-7 hrs Day 1 + 3-5 hrs Day 2) are the key training stimulus. Target 70% of event duration in peak long ride. Saddle time at 8+ hours requires progressive adaptation — cannot be rushed.','-> D-008 (MTB sessions): PREFERRED for technical handling cross-training -> D-001 (trail run): ACCEPTABLE on off-bike days','Base: 82-90% D-006 / 8-15% D-008 Build: 78-88% D-006 / 10-18% D-008 Peak: 78-88% D-006 / 10-18% D-008 Taper: 85-92% D-006 / 5-12% D-008  D-008 provides technical terrain handling; gravel-specific long rides are the primary volume stimulus','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling','D-007','Time-Trial Cycling','INCLUDED','Primary — TT','95–100% of race time (10km TT: ~12-20 min; 25-mile TT: ~55-75 min; 100km TT: ~2.5-3.5 hrs. Mono-discipline for TT-format athletes.)',95.0,100.0,'PURE THRESHOLD SPORT: TT is the most physiologically simple discipline in the framework — ride as fast as possible against the clock, no drafting, no tactics beyond pacing. FTP (Functional Threshold Power) is the primary performance variable.  PACING: The most critical TT skill. Optimal strategy is even power output or very slight negative split. Going out 5% too hard costs more time in the second half than the initial speed gain — research consistently supports conservative starts (PMC5104959: manipulating starting pace ±5% had no effect on overall 16.1km TT time, but slow start produced better physiological outcomes).  AERO POSITION ENDURANCE: Specific training demand. Threshold power in TT position is typically 3-8% lower than threshold power on road bike. The aero position must be trained specifically — threshold intervals must be performed IN AERO POSITION to be race-specific. See D-007 for adaptation protocol.  KEY TRAINING SESSIONS: - TT pace intervals: 2×15 min building to 2×25-30 min at 91-105% FTP in aero - Sweet spot blocks: 88-93% FTP for volume - Race simulation: full-distance effort at target power, ideally on similar terrain - VO2max sharpening in peak phase: 5-8×3 min at 115-120% FTP  FTP TESTING: Re-test FTP every 6-8 weeks. TT is entirely FTP-dependent — training zones must be accurate.','-> Road riding (D-006 easy/recovery): PREFERRED same-day combination -> Running: ACCEPTABLE as aerobic cross-training','Base: 85-92% (road + TT bike mixed) Build: 82-90% (increasing TT-position time) Peak: 82-90% (race-simulation in full aero) Taper: 85-92%  TT POSITION ADAPTATION: Start with 20 min/session in aero (base), build to full race duration in aero (peak). Do NOT attempt race-duration aero without progressive adaptation.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling','D-031','Cross Country Cycling','INCLUDED','Primary — XC MTB','95–100% of race time (XCO Olympic: 1.5-2 hrs circuit laps; XCS Short Track: 30-45 min; XCM Marathon: 3-7 hrs. Mono-discipline for XC-MTB-format athletes.)',95.0,100.0,'XC MTB IS HIGH-INTENSITY CYCLING: Unlike road long-distance, XCO is raced at high intensity (near-VO2max) with variable power output. Technical sections require explosive surges — you cannot soft-pedal through a rock garden.  FORMAT-SPECIFIC TRAINING: - XCO (Olympic): Combine aerobic base with repeated high-intensity efforts (VO2max and anaerobic). Race simulation includes laps with full recovery between. Technical skills sessions (D-008 protocol) are mandatory. - XCS (Short Track): Most intensity-dominated. Training resembles road criterium prep: short sharp intervals, explosive starts. - XCM (Marathon): Closer to endurance road cycling. Long steady-state power + sustained technical handling under fatigue. Back-to-back riding days in peak training.  INTENSITY DISTRIBUTION: Both polarized (POL) and low-intensity (LIT) training distributions have been studied in XCO athletes (MDPI 2022). Neither was clearly superior in the short-term study; standard recommendation is 80% low-intensity / 20% high, adjusting toward more intensity in pre-race phase.  FULL SUSPENSION vs. HARDTAIL: Full suspension 29" wheels are now standard at elite level. Training bike should match race bike setup — different suspension changes power transfer and technical feel significantly.','-> D-006 (road base): PREFERRED — aerobic base building -> D-008 (technical trail): PREFERRED for skills and race-specific training -> Strength: PREFERRED after road base days','XCO/XCS: Base: 55-65% D-006 road / 30-40% D-008 MTB / 5% other Build: 45-55% D-006 / 40-50% D-008 / 5% other Peak: 40-50% D-006 / 45-55% D-008 / 5% other Taper: 50-60% D-006 / 35-45% D-008  XCM (Marathon): Base: 60-70% D-006 / 25-35% D-008 Build: 55-65% D-006 / 30-40% D-008 Peak: 50-60% D-006 / 35-45% D-008','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance / Endurance Cycling','D-008','Mountain Biking','INCLUDED','Primary — Enduro MTB','95–100% of race time (Timed stages: 3-15 min each; Total race day incl. transfers: 4-8 hrs. Mono-discipline for Enduro-format athletes; aggregate time on bike.)',95.0,100.0,'ENDURO IS TWO SPORTS IN ONE DAY: 1. TIMED DESCENT STAGES: Full-speed technical mountain bike descents. CNS-intensive, explosive, high crash risk. Performance is technical skill + short-duration power. Duration: 3-15 min per stage. These are where races are won and lost. 2. UNTIMED TRANSFERS (CLIMBS): Get from stage end to next stage start. Uphill, self-supported, aerobic. Duration: 20-60 min between stages. Fitness matters here — arriving tired at the next stage ruins performance.  TRAINING IMPLICATIONS: - DESCENT TECHNIQUE: The primary performance variable. Cornering at speed, rock gardens, drops, berms. Can only be trained on actual terrain — no substitute. Train descents at full commitment, not moderately. Fatigue management: tired technical riding = crashes. Avoid hard descent training when deeply fatigued. - TRANSFER FITNESS: Aerobic base for climbing transfers. Often underestimated by Enduro athletes who focus on descents. A good aerobic base means you arrive at stage starts fresher than competitors. - BACK-TO-BACK DAYS: Multi-day Enduro events (2-3 days common) require consecutive high-effort days. Train back-to-back in peak phase.  INJURY RISK: Enduro has the highest crash/impact injury rate of all cycling disciplines. Protective equipment (full-face helmet, knee pads, elbow pads, back protector) is mandatory training practice — never descent-train without appropriate protection.','-> D-006 (road): PREFERRED for aerobic transfer fitness base -> D-008 (technical): PREFERRED — descent stages are race-decisive -> Strength: PREFERRED to support upper body bracing for descents','Base: 55-65% D-006 (aerobic base) / 30-38% D-008 (technique) Build: 45-55% D-006 / 38-48% D-008 (more descent focus) Peak: 42-52% D-006 / 42-52% D-008 (race simulation) Taper: 52-62% D-006 / 32-42% D-008 (reduce descent intensity)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','D-004','Swimming','INCLUDED','Primary — All sub-formats','Swim: 8–15% of race time (XTERRA published 10% swim; range supports slower fields.)',8.0,15.0,'SAME PRINCIPLES AS TRIATHLON D-004: Wetsuit (where legal), sighting, mass start management.  KEY DIFFERENCE FROM TRIATHLON: XTERRA swims are often in more dynamic water (ocean surf entries, choppy lake conditions). Practice beach/dock entries and exits specifically — these are technical and take practice.  QUADRATHLON SEQUENCE: Swim immediately precedes either kayak or bike. Swim → Kayak transition is unique — upper body already fatigued from swim before grip-intensive paddle leg. Train swim-paddle bricks specifically.  TRANSITION: Exit water → transition area. In XTERRA: T1 is Swim→MTB (standard like triathlon). In Quadrathlon: T1 may be Swim→Kayak (kayak launch at water edge — time-critical).  PADDLE CAUTION: Same as D-004 — regular paddle use in swim training significantly associated with shoulder overuse injury (PMC5983428). Limit paddles to 1x/week max.','-> D-008 MTB (T1 brick): PREFERRED (XTERRA) -> D-010 Flat-water Kayak (T1 brick): PREFERRED (Quadrathlon) -> Strength: ACCEPTABLE after easy swims','Base: 15–22% / Build: 15–22% / Peak: 13–20% / Taper: 12–20% (Free-form sport — defaults reflect XTERRA-style format. Adjust per event.)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','D-008','Mountain Biking','INCLUDED','Primary — XTERRA and off-road events','MTB: 55–70% of race time (XTERRA published 65% MTB — the dominant block. Was 40-55% in v11.)',55.0,70.0,'XTERRA MTB IS DIFFERENT FROM ROAD TRIATHLON: No drop bars permitted — MTB with flat bars required. 29" full suspension or hardtail. Tire minimum 2.4" recommended by XTERRA champions.  TECHNICAL TERRAIN UNDER SWIM FATIGUE: The XTERRA bike leg starts immediately after an ocean or lake swim. Upper body is cold, wet, and pre-fatigued from swimming. Technical cornering and climbing demand more than road cycling in this context. Train swim → MTB bricks specifically, not just swim→road or isolated MTB.  TIRE PRESSURE: Race-specific. Expert recommendation: 16-18 PSI for technical courses (lower than typical). Practice race-day tire setup in training rides.  NAV CONTEXT: Courses are marked. Route choice is not a factor (vs. AR). Focus entirely on pace, technique, and power.  QUADRATHLON CONTEXT: Bike leg is typically road or gravel in Quadrathlon (not MTB) — use D-006 for Quadrathlon cycling. MTB is XTERRA-specific.','-> D-001 Trail Run (T2 brick): PREFERRED (XTERRA — Bike→Run) -> D-006 Road Cycling: PREFERRED for aerobic base training','D-008 Mountain Biking: Base 38–45% / Build 40–48% / Peak 40–48% / Taper 35–42% D-006 Road Cycling (conditional): Base 5–15% / Build 4–12% / Peak 4–10% / Taper 5–15% (See Sheet 5 for Road Cycling as separate conditional row.)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','D-001','Trail Running','INCLUDED','Primary — XTERRA and trail-based events','Trail Run: 20–30% of race time (XTERRA published 25% trail run.)',20.0,30.0,'RUNNING OFF THE MTB: XTERRA run begins after MTB — same brick dynamics as triathlon T2 (bike→run) but legs carry additional MTB-specific fatigue (more upper body stabilization, more varied power output, technical terrain impact).  FIRST MILE MANAGEMENT: Same principle as triathlon — first mile will feel biomechanically abnormal after MTB. Shorter stride, run by feel, don''t chase pace in first km. XTERRA run biomechanics recovery typically takes 1-3 km (vs. 0.5-1 mile for road triathlon) due to additional MTB leg demands.  TERRAIN: XTERRA runs are technical trail — rocks, roots, elevation changes. Not road running biomechanics. Trail-specific footwear and technique (shorter stride, arms wider, look 3-4m ahead) required.  PHYSICAL STATE AT RUN START: Swimmer''s fatigue (upper body) + MTB fatigue (full body, technical) = higher accumulated fatigue than triathlon run start. Pacing must be more conservative.','-> D-004 Swim + D-008 MTB (preceding bricks): sequence is the training unit -> D-006 Road (easy recovery): PREFERRED on non-brick days','Base: 20–26% / Build: 20–25% / Peak: 20–25% / Taper: 20–25% (Trail running default; road-event events use D-002.)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','D-010','Kayaking','INCLUDED','Primary — Quadrathlon Optional — free-format events','Quadrathlon: 4km (sprint) to 20km (long) ~15-25% of race time',15.0,25.0,'SWIM → PADDLE TRANSITION (unique to Quadrathlon): Upper body fatigued from swim before the paddle leg begins. This is the defining physical challenge of Quadrathlon vs. triathlon. Training must include swim→paddle bricks to adapt shoulder and forearm endurance to pre-fatigued state.  QUADRATHLON KAYAK SPECIFICS: - Equipment: Sit-on-top or touring kayak (not surf ski, not whitewater) for most events. Minimum 8kg per WQF rules. - PFD mandatory during paddle leg (always wear in training) - Portage: getting in/out of kayak at launch and exit is a technical skill — practice timed portage transitions - Paddle order: WQF rules allow swim→kayak→bike→run or swim→bike→kayak→run depending on venue (water access logistics)  FREE-FORMAT EVENTS: Some non-nav multisport events (Great Kindrochit, etc.) use packraft (D-009) or canoe (D-011) instead of kayak. Same paddling principles apply.  GRIP/FOREARM: Same tendon loading considerations as D-009/D-010/D-010 in AR framework — max 3 hard paddle sessions/week.','-> D-001 Trail Run (following brick): PREFERRED (Quadrathlon sequence) -> D-006 Road Cycling (following brick): PREFERRED (if Quadrathlon uses swim→bike→kayak→run order) -> Strength: ACCEPTABLE after easy paddle sessions','*Conditional — only if event includes paddle leg. When active: Base 0–22% / Build 0–22% / Peak 0–22% / Taper 0–18% (Quadrathlon / free-format with paddle leg. Redistribute from MTB or run.)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','D-011','Canoeing','INCLUDED','Primary — Quadrathlon Optional — free-format events',NULL,0.0,0.0,'SWIM → PADDLE TRANSITION (unique to Quadrathlon): Upper body fatigued from swim before the paddle leg begins. This is the defining physical challenge of Quadrathlon vs. triathlon. Training must include swim→paddle bricks to adapt shoulder and forearm endurance to pre-fatigued state.  QUADRATHLON KAYAK SPECIFICS: - Equipment: Sit-on-top or touring kayak (not surf ski, not whitewater) for most events. Minimum 8kg per WQF rules. - PFD mandatory during paddle leg (always wear in training) - Portage: getting in/out of kayak at launch and exit is a technical skill — practice timed portage transitions - Paddle order: WQF rules allow swim→kayak→bike→run or swim→bike→kayak→run depending on venue (water access logistics)  FREE-FORMAT EVENTS: Some non-nav multisport events (Great Kindrochit, etc.) use packraft (D-009) or canoe (D-011) instead of kayak. Same paddling principles apply.  GRIP/FOREARM: Same tendon loading considerations as D-009/D-010/D-010 in AR framework — max 3 hard paddle sessions/week.','-> D-001 Trail Run (following brick): PREFERRED (Quadrathlon sequence) -> D-006 Road Cycling (following brick): PREFERRED (if Quadrathlon uses swim→bike→kayak→run order) -> Strength: ACCEPTABLE after easy paddle sessions','*Conditional — only if event includes paddle leg. When active: Base 0–22% / Build 0–22% / Peak 0–22% / Taper 0–18% (Quadrathlon / free-format with paddle leg. Redistribute from MTB or run.)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','D-009','Packrafting','INCLUDED','Minor — Free-format non-nav multisport','Varies by event (0-20% of race time)',0.0,20.0,'WHEN PACKRAFTING APPEARS: Some non-nav multisport events include packraft legs as an alternative to kayak — particularly in alpine or wilderness settings where logistics favor packraft over full-size kayak.  TRAINING: Same principles as D-009 in AR context. Key difference from AR: no nav integration — just paddle the course. Focus on transition efficiency (inflate/deflate if required) and sustained paddle technique.  FREE-FORMAT EVENT PLANNING: If your target event includes packraft, confirm whether: 1. Race provides rafts (some do) or you bring your own 2. Inflation/deflation is required during race or only once at start 3. Pack weight during other legs (packraft adds 4-7 lb)','Same pairing rules as D-009 in AR context','*Conditional — free-format events with packraft leg only. When active: Base 0–10% / Build 0–12% / Peak 0–12% / Taper 0–10%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','D-006','Road Cycling','INCLUDED','Conditional','5–15% (XTERRA road base) 0–35% (Quadrathlon road bike events) 0–40% (free-format road events)',5.0,15.0,'Used as: (1) road base aerobic for XTERRA athletes, (2) primary bike leg for Quadrathlon with road bike, (3) substitute for D-008 in non-MTB free-format events.','Pair with Run for traditional duathlon-style brick (in road events). Not paired with Swim in T1.','Base: 5–15% / Build: 4–12% / Peak: 4–10% / Taper: 5–15% (Conditional — varies by event format)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Cross-Country / Nordic Skiing','D-028','Cross-Country Skiing','INCLUDED','Primary','98–100% of race discipline (Mono; only non-ski time is start-zone setup.)',98.0,100.0,'SEASONAL STRUCTURE: - Off-snow (May-Nov): Roller skiing (most specific substitute), running, cycling, double-pole erg - On-snow (Dec-Apr): Primary training modality  TECHNIQUE SPECIALIZATION: Focus on race technique (classic for Vasaloppet/Birkebeiner; skate for most FIS events). Skiathlon requires both.  KEY OFF-SNOW SESSION: 3-5 hr double-pole erg or roller ski session. This is the primary long-distance training stimulus even off-snow.  VOLUME CONTEXT: World-class annual training = 861 hrs. 50-60% as double poling. Recreational competitive: 8-16 hrs/week peak.','D-028 is the only racing discipline. Strength and roller skiing complement.','Base: 70–80% / Build: 75–85% / Peak: 80–90% / Taper: 80–90% (Off-snow Base only — when no snow available: 50–60% roller skiing, 20–30% run/cycle)','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Canoe / Kayak Marathon','D-010','Kayaking','INCLUDED','Primary (*Conditional — K1/K2 variant)','88–96% paddling primary discipline (Portages: 4–12% of time; 6–8 of several hundred meters each.)',88.0,96.0,'RACE FORMAT IS WHAT MAKES THIS DIFFERENT FROM STANDARD D-010 — same physical training discipline, with marathon-specific race-prep work layered on:  ICF COMPETITION (up to 30km): Race pace, drafting tactics, portage speed, final sprint. Resembles road marathon training structure.  ULTRA-DISTANCE: Time on water, back-to-back paddle days, portage fitness, multi-day nutrition. Resembles ultra marathon training structure.  PORTAGE: Practice running with boat specifically. Portage entry/exit (sloped dock, beach) takes practice. Falls at portage are common among inexperienced athletes. In ICF events, portage positioning can make or break a race.  GROUP TACTICS: Wash-riding saves 10-20% energy. Practicing draft positioning in group paddles is as important as aerobic fitness for performance.','-> Running: ACCEPTABLE for portage fitness and aerobic cross-training -> Strength: ACCEPTABLE after easy paddle sessions','Base: 80-88% / Build: 82-90% / Peak: 82-90% / Taper: 85-92%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Canoe / Kayak Marathon','D-011','Canoeing','INCLUDED','Primary (*Conditional — C1/C2 variant)','88–96% paddling primary discipline (Portages: 4–12% of time. C1/C2 marathon variant.)',88.0,96.0,'C-variant (single-blade) of marathon paddling. Substantially different muscle pattern from K-variant.  C1: Solo, kneeling stance, single-blade J-stroke. C2: Pair (sit/kneel mixed). Different boat handling, different injury profile.  ICF COMPETITION (up to 30km): Race pace, drafting tactics, portage speed, final sprint. Resembles road marathon training structure.  ULTRA-DISTANCE: Time on water, back-to-back paddle days, portage fitness, multi-day nutrition. Resembles ultra marathon training structure.  PORTAGE: Practice running with boat specifically. Portage entry/exit (sloped dock, beach) takes practice. Falls at portage are common among inexperienced athletes. In ICF events, portage positioning can make or break a race.  GROUP TACTICS: Wash-riding saves 10-20% energy. Practicing draft positioning in group paddles is as important as aerobic fitness for performance.','-> Running: ACCEPTABLE for portage fitness and aerobic cross-training -> Strength: ACCEPTABLE after easy paddle sessions','Base: 80-88% / Build: 82-90% / Peak: 82-90% / Taper: 85-92%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Open Water Marathon Swimming','D-004','Swimming','INCLUDED','Primary','98–100% of race discipline (Mono; in-water feeding seconds-long.)',98.0,100.0,'RACE FORMAT IS WHAT MAKES THIS DIFFERENT FROM STANDARD D-004 — same physical training discipline, but with marathon-specific race-prep work layered on:  DURATION AND FEEDING CHANGE EVERYTHING vs. D-004:  FEEDING PROTOCOL (mandatory from 10km+): Deviate from race line at each pontoon (approx 2.5km). Roll on back, receive cup, drink, roll forward. Practice this 15-20 times before first race. Time lost if efficient: 8-15 seconds. Tactical decision: feed or stay on optimal line.  CARBOHYDRATE TARGET: Up to 90g/hr from multitransportable sources (liquid + gel). Train gut with every long OW session.  COLD WATER ACCLIMATIZATION: Begin 8-10 weeks before cold-water race. Short exposures (10-15 min at target temperature) with gradual extension. FINA minimum = 16C; channel events can be 13-15C.  DRAFTING THROUGHOUT: Full-race pack dynamics. Position on feet or hip of faster swimmer. Sustained tactical positioning is a trainable race skill across 2+ hours.','Standalone discipline. Open water group swims for tactical training.','Base: 80-88% / Build: 80-88% / Peak: 80-88% / Taper: 82-90%','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
INSERT INTO layer0.discipline_pairing (discipline_id_a,discipline_id_b,pairing_rating,rationale,source,etl_version,etl_run_at) VALUES ('D-001','D-002','PREFERRED',NULL,'matrix','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
