INSERT INTO layer0.phase_load_allocation (sport_name,discipline_id,discipline_name,role,base_pct_low,base_pct_high,build_pct_low,build_pct_high,peak_pct_low,peak_pct_high,taper_pct_low,taper_pct_high,notes_conditions,default_inclusion,prescription_note,audit_log,raw_notes,row_category,etl_version,etl_run_at) VALUES ('Adventure Racing','D-001','Trail Running','Primary',12.0,15.0,12.0,15.0,10.0,14.0,12.0,15.0,'High injury-per-hour risk — quality over quantity. Long run 1×/week is primary stimulus. Scales lower than its race time % would suggest. TAPER 12–15%: 2 short quality runs (≤60 min each); absolute time ~50% below peak. No long run in taper. Frequency maintained over volume. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]','included','High injury-per-hour risk — quality over quantity.','Long run 1×/week is primary stimulus. | Scales lower than its race time % would suggest. | TAPER 12–15%: 2 short quality runs (≤60 min each); | absolute time ~50% below peak. | No long run in taper. | Frequency maintained over volume. | [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. | Values patched and confirmed.]','High injury-per-hour risk — quality over quantity. Long run 1×/week is primary stimulus. Scales lower than its race time % would suggest. TAPER 12–15%: 2 short quality runs (≤60 min each); absolute time ~50% below peak. No long run in taper. Frequency maintained over volume. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-003','Trekking','Primary',15.0,20.0,18.0,22.0,18.0,22.0,12.0,17.0,'Highest weekly-hour contributor. Long hike (4–7 hrs) is the most AR-specific training. Scales to near race-duration in peak. TAPER 12–17%: One medium pack hike (2–3 hrs, full weight) — long hike eliminated. Largest absolute-hour reduction of any discipline in taper; % drop reflects this. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]','included','Highest weekly-hour contributor.','Long hike (4–7 hrs) is the most AR-specific training. | Scales to near race-duration in peak. | TAPER 12–17%: One medium pack hike (2–3 hrs, full weight) — long hike eliminated. | Largest absolute-hour reduction of any discipline in taper; | % drop reflects this. | [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. | Values patched and confirmed.]','Highest weekly-hour contributor. Long hike (4–7 hrs) is the most AR-specific training. Scales to near race-duration in peak. TAPER 12–17%: One medium pack hike (2–3 hrs, full weight) — long hike eliminated. Largest absolute-hour reduction of any discipline in taper; % drop reflects this. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-006','Road Cycling','Primary',20.0,25.0,22.0,28.0,20.0,25.0,17.0,22.0,'Highest volume by % — mirrors race split (~40–55% of race distance). Low injury risk per hour enables high volume. Aerobic base for all other disciplines. TAPER 17–22%: 2.2–2.9 hrs at 13 hr taper week; 2–3 short rides (45–75 min) maintaining aerobic touch. No VO2 or threshold work in final 7 days. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]','included','Highest volume by % — mirrors race split (~40–55% of race distance).','Low injury risk per hour enables high volume. | Aerobic base for all other disciplines. | TAPER 17–22%: 2.2–2.9 hrs at 13 hr taper week; | 2–3 short rides (45–75 min) maintaining aerobic touch. | No VO2 or threshold work in final 7 days. | [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. | Values patched and confirmed.]','Highest volume by % — mirrors race split (~40–55% of race distance). Low injury risk per hour enables high volume. Aerobic base for all other disciplines. TAPER 17–22%: 2.2–2.9 hrs at 13 hr taper week; 2–3 short rides (45–75 min) maintaining aerobic touch. No VO2 or threshold work in final 7 days. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-008','Mountain Biking','Primary',8.0,12.0,10.0,15.0,12.0,16.0,8.0,12.0,'Scales toward peak as skills consolidate. CNS recovery cap: max 2 hard technical sessions/week at any phase. TAPER 8–12%: 1 easy technical ride (60–90 min); no new skills, no high CNS demand. Maintains neuromuscular priming without fatigue accumulation. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]','included','Scales toward peak as skills consolidate.','CNS recovery cap: max 2 hard technical sessions/week at any phase. | TAPER 8–12%: 1 easy technical ride (60–90 min); | no new skills, no high CNS demand. | Maintains neuromuscular priming without fatigue accumulation. | [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. | Values patched and confirmed.]','Scales toward peak as skills consolidate. CNS recovery cap: max 2 hard technical sessions/week at any phase. TAPER 8–12%: 1 easy technical ride (60–90 min); no new skills, no high CNS demand. Maintains neuromuscular priming without fatigue accumulation. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-009','Packrafting','Primary',5.0,8.0,8.0,10.0,8.0,10.0,5.0,8.0,'Limited by water access and tendon loading. Paddle erg substitutes in base. Transition drills embedded in longer sessions.','included','Limited by water access and tendon loading.','Paddle erg substitutes in base. | Transition drills embedded in longer sessions.','Limited by water access and tendon loading. Paddle erg substitutes in base. Transition drills embedded in longer sessions.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-010','Kayaking','Primary (*Conditional)',5.0,8.0,8.0,10.0,8.0,10.0,5.0,8.0,'*CONDITIONAL — INTERCHANGEABLE WITH PACKRAFTING. Replaces packraft volume when race uses kayak as primary paddle discipline; not additive. On-water preferred over erg in peak. If race uses kayak, weight slightly higher (9–12%) in peak.','included','Replaces packraft volume when race uses kayak as primary paddle discipline;','*CONDITIONAL — INTERCHANGEABLE WITH PACKRAFTING. | not additive. | On-water preferred over erg in peak. | If race uses kayak, weight slightly higher (9–12%) in peak.','*CONDITIONAL — INTERCHANGEABLE WITH PACKRAFTING. Replaces packraft volume when race uses kayak as primary paddle discipline; not additive. On-water preferred over erg in peak. If race uses kayak, weight slightly higher (9–12%) in peak.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-011','Canoeing','Primary (*Conditional)',2.0,5.0,5.0,8.0,6.0,8.0,3.0,5.0,'*CONDITIONAL — REPLACES kayak/packraft volume when race uses canoe; not additive. Only if race-confirmed. Partner training required.','excluded','not additive.','*CONDITIONAL — REPLACES kayak/packraft volume when race uses canoe; | Only if race-confirmed. | Partner training required.','*CONDITIONAL — REPLACES kayak/packraft volume when race uses canoe; not additive. Only if race-confirmed. Partner training required.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-012','Rock Climbing','Secondary',3.0,5.0,3.0,5.0,4.0,6.0,2.0,3.0,'Sessions short (60–90 min), high tendon demand. 2 sessions/week max. Dead hang + pull-up work in strength training is additional.','included','Sessions short (60–90 min), high tendon demand.','2 sessions/week max. | Dead hang + pull-up work in strength training is additional.','Sessions short (60–90 min), high tendon demand. 2 sessions/week max. Dead hang + pull-up work in strength training is additional.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-013','Abseiling','Minor',0.0,1.0,1.0,2.0,1.0,2.0,0.0,1.0,'Technique acquisition. Once solid: 1 session per 4–6 weeks is maintenance. Not a high-volume discipline.','included','Technique acquisition.','Once solid: 1 session per 4–6 weeks is maintenance. | Not a high-volume discipline.','Technique acquisition. Once solid: 1 session per 4–6 weeks is maintenance. Not a high-volume discipline.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-014','Via Ferrata','Minor',0.0,1.0,1.0,2.0,1.0,2.0,0.0,1.0,'Same as abseiling. Physical prep is embedded in climbing training.','included','Same as abseiling.','Physical prep is embedded in climbing training.','Same as abseiling. Physical prep is embedded in climbing training.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-004','Swimming','Minor',0.0,2.0,1.0,2.0,1.0,3.0,1.0,2.0,'Recovery discipline and safety skill. Pool sessions = active recovery. Open water: 2–4 sessions in build/peak.','included','Recovery discipline and safety skill.','Pool sessions = active recovery. | Open water: 2–4 sessions in build/peak.','Recovery discipline and safety skill. Pool sessions = active recovery. Open water: 2–4 sessions in build/peak.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-017','Snowshoeing','Minor (*Conditional)',0.0,0.0,1.0,2.0,1.0,2.0,0.0,0.0,'*CONDITIONAL — Winter/mountain races only; not additive in non-winter race plans. Hip abductor work embedded in strength training.','excluded','not additive in non-winter race plans.','*CONDITIONAL — Winter/mountain races only; | Hip abductor work embedded in strength training.','*CONDITIONAL — Winter/mountain races only; not additive in non-winter race plans. Hip abductor work embedded in strength training.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-018','Mountaineering','Minor (*Conditional)',0.0,0.0,1.0,2.0,1.0,2.0,0.0,1.0,'*CONDITIONAL — Race-relevant only; not additive in non-mountain race plans. Physical prep covered by hiking volume. Guided sessions count.','excluded','not additive in non-mountain race plans.','*CONDITIONAL — Race-relevant only; | Physical prep covered by hiking volume. | Guided sessions count.','*CONDITIONAL — Race-relevant only; not additive in non-mountain race plans. Physical prep covered by hiking volume. Guided sessions count.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','D-019','Paddle Rafting','Minor',0.0,0.0,0.0,1.0,1.0,2.0,0.0,0.0,'1–2 guided sessions in build/peak. Not volume-based.','included','1–2 guided sessions in build/peak.','Not volume-based.','1–2 guided sessions in build/peak. Not volume-based.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing',NULL,'Strength Training','Accessory',8.0,10.0,6.0,8.0,5.0,7.0,3.0,5.0,'Higher in base (movement foundation). Never zero — maintenance 2×/week in build/peak. Pull-emphasis (paddle+climb) + single-leg lower (pack carry).','included','Higher in base (movement foundation).','Never zero — maintenance 2×/week in build/peak. | Pull-emphasis (paddle+climb) + single-leg lower (pack carry).','Higher in base (movement foundation). Never zero — maintenance 2×/week in build/peak. Pull-emphasis (paddle+climb) + single-leg lower (pack carry).','strength','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing',NULL,'Mobility / Recovery','Foundation',3.0,5.0,3.0,5.0,3.0,5.0,6.0,10.0,'Absolute time roughly constant throughout training; % rises in taper as total volume drops. TAPER 6–10%: 0.8–1.3 hrs at 13 hr taper week; 2–3 × 20–25 min sessions or daily 10–15 min. Absolute time at or slightly above peak — recovery priority increases as volume drops. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]','included','Absolute time roughly constant throughout training;','% rises in taper as total volume drops. | TAPER 6–10%: 0.8–1.3 hrs at 13 hr taper week; | 2–3 × 20–25 min sessions or daily 10–15 min. | Absolute time at or slightly above peak — recovery priority increases as volume drops. | [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. | Values patched and confirmed.]','Absolute time roughly constant throughout training; % rises in taper as total volume drops. TAPER 6–10%: 0.8–1.3 hrs at 13 hr taper week; 2–3 × 20–25 min sessions or daily 10–15 min. Absolute time at or slightly above peak — recovery priority increases as volume drops. [AUDIT 2026-05-06: Taper feasibility verified — see R19 note. Values patched and confirmed.]','mobility','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing',NULL,'WEEKLY TOTAL TARGET','—',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'WEEKLY TARGET HOURS: BASE: ~18 hrs (peak base week) BUILD: ~22–28 hrs (peak build week) PEAK: ~28–35 hrs (peak week) TAPER: ~12–14 hrs  For 48–56 hr expedition race preparation. Reduce 20–30% if life constraints limit training. Consistency at 80% beats sporadic perfection.  [AUDIT 2026-05-06 — TAPER FEASIBILITY PATCH] Adjusted stack (conditionals zeroed, one paddle discipline only):   BASE: 77–109% ✓   BUILD: 88–120% ✓   PEAK: 89–122% ✓   TAPER: 69–101% ✓ Taper HIGH stack = 101% — feasibility confirmed (≥100% required). Taper LOW stack = 69% — wide band expected; AR athletes cannot simultaneously maximize all disciplines. Taper total volume: 12–14 hrs (≈40% of 28–35 hr peak) — within 40–60% taper cut literature norm. Discipline distribution at 13 hr midpoint (high-band %s, one paddle):   XC Cycling 22% = 2.9 hrs | Hiking 17% = 2.2 hrs | Trail Run 15% = 2.0 hrs   MTB 12% = 1.6 hrs | Mobility 10% = 1.3 hrs | Packraft 8% = 1.0 hrs   Orienteering 5% = 0.7 hrs | Strength 5% = 0.7 hrs | Rock Climb 3% = 0.4 hrs   Swimming 2% = 0.3 hrs | Abseil/Fixed Rope 1% each = 0.1 hrs each All primary disciplines maintain a training touch. No discipline zeroed unless conditional. Sources: Bosquet et al. (2007) taper meta-analysis (Sports Med 37:182–197) — 41–60% volume cut,   frequency preservation; Mujika & Padilla (2003) taper review (J Sports Sci 21:149–161);   Pyne et al. (2009) — multi-sport event taper maintains all discipline touch points. Patch values confirmed correct. ''[TAPER feasibility patch — pending AR audit]'' flags retired.','included','WEEKLY TARGET HOURS:','BASE: ~18 hrs | (peak base week) | BUILD: ~22–28 hrs | (peak build week) | PEAK: ~28–35 hrs | (peak week) | TAPER: ~12–14 hrs | For 48–56 hr expedition race preparation. | Reduce 20–30% if life constraints limit training. | Consistency at 80% beats sporadic perfection. | [AUDIT 2026-05-06 — TAPER FEASIBILITY PATCH] | Adjusted stack (conditionals zeroed, one paddle discipline only): | BASE: 77–109% ✓   BUILD: 88–120% ✓   PEAK: 89–122% ✓   TAPER: 69–101% ✓ | Taper HIGH stack = 101% — feasibility confirmed (≥100% required). | Taper LOW stack = 69% — wide band expected; | AR athletes cannot simultaneously maximize all disciplines. | Taper total volume: 12–14 hrs (≈40% of 28–35 hr peak) — within 40–60% taper cut literature norm. | Discipline distribution at 13 hr midpoint (high-band %s, one paddle): | XC Cycling 22% = 2.9 hrs | Hiking 17% = 2.2 hrs | Trail Run 15% = 2.0 hrs | MTB 12% = 1.6 hrs | Mobility 10% = 1.3 hrs | Packraft 8% = 1.0 hrs | Orienteering 5% = 0.7 hrs | Strength 5% = 0.7 hrs | Rock Climb 3% = 0.4 hrs | Swimming 2% = 0.3 hrs | Abseil/Fixed Rope 1% each = 0.1 hrs each | All primary disciplines maintain a training touch. | No discipline zeroed unless conditional. | Sources: Bosquet et al. | (2007) taper meta-analysis (Sports Med 37:182–197) — 41–60% volume cut, | frequency preservation; | Mujika & Padilla (2003) taper review (J Sports Sci 21:149–161); | Pyne et al. | (2009) — multi-sport event taper maintains all discipline touch points. | Patch values confirmed correct. | ''[TAPER feasibility patch — pending AR audit]'' flags retired.','WEEKLY TARGET HOURS:
INSERT INTO layer0.phase_load_weekly_totals (sport_name,phase,weekly_low_hours,weekly_high_hours,weekly_target_text,weekly_unit,etl_version,etl_run_at) VALUES ('Adventure Racing','Base',18.0,18.0,'WEEKLY TARGET HOURS:
INSERT INTO layer0.team_formats (sport_name,formats_available,team_format_types,unified_team_description,relay_specialist_description,training_implication_unified,training_implication_relay,key_distinctions_notes,etl_version,etl_run_at) VALUES ('SPORT-BY-SPORT FORMAT MATRIX',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Adventure Racing','Unified Team (mandatory) + Relay at some events','UNIFIED TEAM (primary) RELAY (minority)','All members complete every discipline together. Team cannot separate during the race — mandatory proximity rules apply. The team''s pace is the slowest member''s pace in each discipline. One member navigates; all benefit or suffer from nav decisions.','Some events offer relay categories where teams split legs by discipline (e.g., Team A paddles; Team B hikes). Uncommon. Not recognized for main championship standings at ARWS level.','All members train all disciplines (trail run, MTB, paddle, nav, climb). No specialization within unified team. Navigate at the team''s combined aerobic ceiling. Weakest discipline of any member = team liability. Team training sessions (group MTB, group paddle) are mandatory.','Relay category: each member specializes in 1-2 disciplines. A relay paddler can skip MTB training. However: relay AR is treated as a lesser category at most championships. Bridge training (each knows a backup) is wise.','The fundamental AR rule: ''the team finishes together or not at all.'' This is the defining feature of unified team racing. No AR athlete can afford to be weak in any discipline — the team pays the price.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Triathlon','Individual + Relay (3-person)','INDIVIDUAL (primary) RELAY (common)','N/A — standard triathlon is individual. No unified team format.','3-person relay: Swimmer does swim leg, exits water, tags cyclist. Cyclist completes bike leg, tags runner. Runner finishes. Each athlete specializes in one discipline. Very common at mass-participation events.','N/A','Pure specialization. Relay swimmer: train swim only + OW conditions. Relay cyclist: train bike only. Relay runner: train run + brick run feel (legs after extended rest). Transition handoff mechanics matter: T1/T2 tag zone timing.','Relay triathlon is used by many athletes as an introduction to multisport before attempting full individual triathlon. Also used by injured athletes who can do some but not all three disciplines.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Duathlon Aquathlon Aquabike','Individual + Relay (some events)','INDIVIDUAL (primary)','N/A','Relay formats exist at some events (e.g., duathlon relay: one runs R1, one cycles, one runs R2). Less standardized than triathlon relay.','N/A','Same specialization logic as triathlon relay: each member trains their assigned discipline only.','Relay formats are informal and event-specific. Check event rules before assuming relay is offered.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Swimrun','Pairs — Unified (mandatory at ORTELOFF/OTILLO)','UNIFIED PAIRS (mandatory)','Both partners swim and run every section together. A tether between partners is optional but permitted. Neither partner can DNF without ending the race for both. Pace = the slower partner''s pace in every swim and run section.','N/A — Swimrun has no relay format. Both must do all disciplines.','Both partners must train swimming AND running to competitive standard. Tether practice is a specific additional skill. The pairing''s combined weakness dictates race ceiling. Many swimrun pairs deliberately train together to synchronize pace and breathing.','N/A','The swimrun pairing is arguably the most intimate unified team format — athletes are physically connected during racing. Partner selection is a performance-critical decision, not just a social one.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Skimo (Ski Mountaineering)','Individual + Team (pairs) + Relay','INDIVIDUAL (primary) UNIFIED TEAM (pairs) RELAY','Team format: 2 athletes race together and must finish together. Must stay within 30 seconds of each other on ascent and 10 seconds on descent. Both complete every skinning, boot-packing, and descent section.','Relay format: alternating loops, each athlete races 2 laps. Each racer does their own laps solo. Mixed relay (1 male + 1 female) is an Olympic format.','Team pairs: both athletes must be capable in skinning, boot-packing, and technical descent. The stronger athlete manages pace to stay within mandatory separation limits. Cannot drop a weaker partner.','Relay: each athlete specializes in their own laps. Train individual skimo performance. Relay handoff mechanics and transition speed matter.','Olympic skimo at Milan-Cortina 2026 features Sprint (individual) and Mixed Relay. Team pairs format is a traditional skimo format popular in European racing but not Olympic.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Mountain Running / Skyrunning','Individual (primary) + Team relay (some events)','INDIVIDUAL (primary)','N/A for standard events. Some mountain marathon events have pairs formats (e.g., team classification).','Team relay formats exist at some events: members each run one segment of a multi-stage mountain course. Each specializes in their stage terrain.','N/A','Relay: each runner trains their assigned stage. Stage may be uphill-only, downhill-heavy, or mixed — train accordingly.','Unlike AR or swimrun, mountain running relay formats are informal and uncommon at championship level. Most major events (VK, Skyrace) are individual.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Fell Running','Individual (primary) + Mandatory Pairs for Mountain Marathon','INDIVIDUAL (primary) UNIFIED PAIRS (Mountain Marathon)','Mountain Marathon (OMM, KIMM): mandatory pairs format. Both partners navigate, run, and complete every section together. Overnight self-sufficient camp. Neither can continue without the other.','N/A — no relay format in fell running.','Mountain Marathon pairs: both partners must navigate and run all sections. Nav decisions are shared (though one often leads). Both carry mandatory kit and overnight gear. Pace synchronization, shared nav stress, and camp logistics are additional training dimensions.','N/A','Mountain Marathon is one of the most demanding unified pairs formats — 2 days of navigation on fells, overnight bivvy, no support. Often used as AR preparation by adventure racers.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Marathon (Road and Trail)','Individual (primary) + Relay (4-6 runners)','INDIVIDUAL (primary) RELAY','N/A','Marathon relay: 4-6 runners each cover a designated segment of the 42.2km course. Segments are typically 5-10km. Each runner specializes in their segment distance.','N/A','Relay runners: train for their specific segment distance and terrain. A relay runner covering a 5km segment trains very differently from a full marathon runner. Relay is often used as a team fitness challenge rather than a competitive performance format.','Marathon relays are common at community and fundraising events. Not a recognized World Athletics championship format. Very different performance demands from individual marathon.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Ultramarathon (Road and Trail)','Individual (primary) + Relay (24-hr teams, RAA M relay)','INDIVIDUAL (primary) RELAY (ultra-relay)','N/A for individual ultra. RAAM has a team relay category (4-8 person teams alternating riders across 3,000+ miles) that functions as a near-unified team (the bike is always moving — team is always ''racing'').','24-hr track ultra relay: teams of 4-8 runners alternate laps. Each runner runs when it''s their turn, rests when it''s not. Ragnar-style relays: teams of 6-12, each runs 3 legs across a point-to-point course.','N/A','24-hr/ultra relay: each runner trains for repeated running under fatigue (their legs are separated by rest periods, but those rest periods may be only 30-90 min). Train quality running on tired legs. Ragnar runners: train their target leg distances (typically 3-8 miles per leg, 3 legs total). Not ultra-level training. Sleep management (running at 2 AM after 3 hrs of van sleep) is a specific preparation.','RAGNAR-STYLE is the most common relay format for the general public. Teams of typically 6 or 12 share a van, cover 150-200 miles of running over 24-36 hours, each running 3 legs. It is the entry point to team endurance racing for many athletes who then progress to AR, multisport, or ultra.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Long Distance Cycling','Individual (primary) + Team TT + RAAM relay','INDIVIDUAL (primary) SYNCHRONIZED TEAM (Team TT) RELAY (RAAM)','Team TT: all riders complete the course together in a synchronized pace line. The team''s time is taken on the Nth finisher. Dropped riders hurt the team''s result. All ride simultaneously — not relay.','RAAM relay (4-8 person): alternating riders across 3,000 miles. Each rides consecutive 30-60 min segments then rests in support vehicle. The bike is never stationary — relay is continuous.','Team TT: all riders train the same aerobic and threshold demands. Pace line technique (drafting, sharing the lead, protecting weakest rider) is a specific co-training skill. All riders must be within ~5% of each other''s FTP to be effective.','RAAM relay: each rider needs short-segment aerobic power + rapid recovery ability (ride hard, rest, repeat across many hours). The repeated effort cycling is different from a single long ride. Sleep deprivation management is critical — riders nap in vehicle between segments.','Team TT is the only major cycling format where being dropped from your own team is a team failure, not individual. Echelon and pace line discipline require specific co-training. Unlike relay, no one sits out a Team TT.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Off-Road / Adventure Multisport (Non-Nav)','Individual (primary) + Relay (most XTERRA events)','INDIVIDUAL (primary) RELAY (common)','N/A — XTERRA and quadrathlon are primarily individual events.','XTERRA Relay (3-person): one swims, one MTBs, one trail runs. Each specializes in their discipline. Quadrathlon Relay (4-person): one per discipline (swim, kayak, bike, run). General non-nav multisport: relay formats at most events.','N/A','XTERRA relay swimmer: swim-only training + OW conditions. Relay MTB rider: MTB-only training. Relay runner: trail run-only training. Quadrathlon relay: one discipline per person, no cross-training required. Handoff mechanics at transition are important.','XTERRA relay is the most common entry point for athletes who are strong in one multisport discipline but not all three. A competitive open water swimmer who doesn''t cycle can contribute meaningfully to a relay team.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Cross-Country / Nordic Skiing','Individual + Relay (4-person) + Team Sprint (pairs)','INDIVIDUAL (primary) RELAY TEAM SPRINT','N/A — no unified team format in XC skiing.','Relay (4-person): each skier skis one leg (classic or skate depending on relay format). Team Sprint (pairs): alternating heats of 2 athletes. Each athlete races multiple intervals in the sprint heat format.','N/A','XC ski relay member: train one technique predominantly (if assigned a classic leg, focus on classic). Relay length matches individual race distances — training volume is similar to individual event prep. The relay baton handoff (physical tag) is a specific skill requiring timing and coordination.','XC ski relay is the premier team format in Nordic skiing. Olympic relay (4x5km or 4x7.5km) is a flagship event. The final leg is often skied by the team''s best skier — role assignment strategy matters.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Canoe / Kayak Marathon','Individual (K1/C1) + Doubles (K2/C2) + Club relay','INDIVIDUAL (primary) DOUBLES (K2/C2) RELAY (informal)','K2 (kayak double) and C2 (canoe double): both athletes paddle together in the same boat for the entire race. Unified doubles format — cannot separate. Portages are carried together.','Club relay formats: team members alternate paddling segments. Not a standard ICF format. Common at ultra-distance grassroots events.','N/A','K2/C2 doubles: both athletes train paddling together. Stroke synchronization (matching catch and pull timing) is a specific co-training requirement — off-sync paddling loses efficiency and can capsize. Front paddler sets pace; rear paddler adjusts. Train together from base phase. Physical size/power matching matters for K2 efficiency.','K2/C2 is the doubles paradigm in its clearest form — two athletes in one boat, neither can race without the other, and their physical coordination is a performance variable.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Open Water Marathon Swimming','Individual (primary) + Relay (channel swims)','INDIVIDUAL (primary) RELAY (channel)','N/A — OW marathon swimming is primarily individual.','Channel relay (e.g., English Channel relay): team of 6 swimmers alternates at fixed intervals (typically 1 hr each). Each swimmer enters cold, dark, potentially rough water after hours in a boat. The boat is always moving — continuous relay.','N/A','Channel relay swimmer: train for their assigned 1-hour cold water swim under fatigue (having been on a boat for hours, potentially seasick, sleep-deprived). Cold water acclimatization is mandatory. Feeding during the swim. Psychological readiness to enter cold open water on demand at any hour. Very different from individual 10km race preparation.','English Channel relay is one of the most demanding relay contexts physically and psychologically — swimmers may enter water at 3 AM, in rough seas, after 5 hours on a pitching boat. The challenge is less about swimming fitness and more about environmental readiness.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('RAGNAR / ULTRA-RELAY FORMAT — General Concept (applies across multiple sports)',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('WHAT IT IS: A relay format where 6-12 athletes share a vehicle and alternate covering segments of a long course over 24-36 hours. Most commonly running (Ragnar Trail, Hood to Coast), but the format extends to cycling (Ragnar X cycling), ultra distance, and some multisport events. Each athlete runs 3+ legs distributed across the 24-36 hour window, separated by rest periods in the vehicle — which may be only 1-3 hours of broken sleep.  TRAINING DISTINCTION FROM STANDARD RELAY: The primary challenge is not athletic fitness — most Ragnar participants have sufficient base fitness. The primary challenges are: (1) Running a moderate-intensity effort (5-8 miles) on very little sleep, often at 2-4 AM. (2) Recovering quickly enough in a cramped van to run again 4-8 hours later. (3) Nutrition management across 24-36 hours without normal meal structure.  TRAINING RECOMMENDATION FOR RAGNAR/ULTRA-RELAY: Include at least 2 back-to-back training runs separated by 4-6 hours of rest (not sleep). Practice eating and sleeping in short windows. Run one leg at 2-3 AM in training to calibrate night-run pacing. This preparation is more logistics and adaptation than fitness — athletes with solid base running fitness are limited by these factors, not aerobic capacity.',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('STRATEGIC DECISIONS FOR TEAM ATHLETES — Summary',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Decision / Issue',NULL,NULL,'Principle',NULL,NULL,'Practical Recommendation',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Which format am I racing?',NULL,NULL,'Identify clearly: Unified (everyone does everything), Relay (I do my leg only), Doubles (paired in same craft), Aggregate (individual racing with team scoring). This is the most fundamental training direction decision you will make.',NULL,NULL,'Check race rules carefully. Some events offer multiple formats. Confirm before committing to a training plan.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Role assignment (relay)',NULL,NULL,'In relay formats, assign legs based on each member''s strongest discipline. The fastest overall relay team is not always the one with the highest individual averages — it''s the one with the best role-to-strength matching. A 1:45 swimmer + a 350W cyclist + a 3:00/mile runner beats three generalists averaging 2:10 / 280W / 3:45.',NULL,NULL,'Consider backup roles: who can cover another leg if someone is injured? ''Bridge training'' (each member has a functional second discipline at 80% competency) reduces DNF risk from single-point-of-failure injuries.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Training with teammates (unified)',NULL,NULL,'Unified team members should train together regularly in the disciplines where team pace synchronization matters most: group MTB rides, group paddles. Discovering that one member is 40% slower on the paddle 2 weeks before race day is too late to address.',NULL,NULL,'Schedule combined training at least monthly. Identify the team''s discipline ceiling (the discipline where the gap between fastest and slowest is largest) — that''s where to invest the most shared training time.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Transition / handoff mechanics',NULL,NULL,'In relay formats, the transition is a distinct performance variable. The fastest individual leg splits mean little if the transition adds 30 seconds. Practice the handoff with your actual teammates under conditions similar to the race (tired, race-day pressure).',NULL,NULL,'For XTERRA relay: practice the swim exit / tag-to-bike sequence. For XC ski relay: the physical shoulder tag in ski boots on a groomed course. For AR: the transition between disciplines (pack swap, gear handoff) must be practiced, not assumed.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('The weakest-link principle (unified team)',NULL,NULL,'In any unified team format, the team''s overall performance is capped by its weakest member in each discipline. This is not a motivational observation — it is a structural constraint. Pre-race discipline testing (assess each member''s capability in each discipline) should be part of any serious unified team preparation.',NULL,NULL,'If the team has a significant weakness in one discipline, that discipline deserves disproportionate training focus for the weakest member. A team of four excellent runners who all paddle poorly will lose the paddling section to teams who addressed their own discipline gaps.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
INSERT INTO layer0.cross_sport_properties (property_id,property_name,description,scope,ranking_text,estimated_values,source_evidence,source_text,confidence,notes,etl_version,etl_run_at) VALUES ('LIT_RATIO_001','LIT (Low-Intensity Training) Ratio — mid-prep','Estimated proportion of mid-preparation training time spent at low intensity (Z1+Z2 in 5-zone model, or below first ventilatory threshold). Based on credible-range mid-points; not single-athlete values.','Running family','Ultramarathon (Road) > Marathon (Road) > Ultramarathon (Trail) ≈ Marathon (Trail) > Marathon (Mountain) > Mountain Running / Skyrunning > Fell Running','UltraR ~85-90% | MarR ~80-85% | UltraT ~80% | MarT ~80% | MarM ~75-80% | MtnRun ~77% | Fell ~70-75%','Casado et al. 2022 (PMC8975965); Knaier et al. 2024 (PMC11065819); Stöggl & Sperlich 2015 (PMC4621419); Roche analysis of Jornet 2022 (Trail Runner Magazine); Koop, Training Essentials for Ultrarunning 2nd ed.; FRA literature on S/M race format','Casado et al. 2022 (PMC8975965); Knaier et al. 2024 (PMC11065819); Stöggl & Sperlich 2015 (PMC4621419); Roche analysis of Jornet 2022 (Trail Runner Magazine); Koop, Training Essentials for Ultrarunning 2nd ed.; FRA literature on S/M race format','Medium','Marathon (Road) is the LIT-ratio leader of the marathon family per Casado/Knaier ≥80% LIT. Globally, Ultramarathon (Road) likely sits slightly higher because intensity ceilings drop with race duration. Mountain Running and Fell Running run lower LIT due to higher Z3 (threshold) work. Ranking values are credible-range mid-points; individual athlete distributions vary by ±5pp.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
INSERT INTO layer0.discipline_substitutes (target_id,target_name,substitute_id,substitute_name,fidelity,constraints,category,substitute_covers,etl_version,etl_run_at) VALUES ('D-001','Trail Running','D-003','Trekking',0.85,'Same musculoskeletal pattern, terrain, and gait transitions. Lower cardiac intensity per minute, but in AR/multisport these are interchangeable in race execution. Add weighted vest to hike to capture pack-load tolerance.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-001','Trail Running','D-002','Road Running',0.75,'Aerobic and gait transfer excellent. Loses technical surface skill, ankle stability training, terrain reading. Best base-building substitute when trails inaccessible.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-001','Trail Running','D-024','Mountain Running',0.7,'Subset case — covers trail run training when consistent climb is available. Higher cardiac demand.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-001','Trail Running','D-008','Mountain Biking',0.35,'Cross-training only — for use when running is restricted (injury/recovery). Aerobic transfer good; no impact loading.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-002','Road Running','D-001','Trail Running',0.85,'Same gait. Slightly slower pacing on uneven surface. Loses pace-specific intensity work unless terrain is non-technical.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-002','Road Running','D-008','Mountain Biking',0.35,'Cross-training only when running restricted.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-002','Road Running','D-006','Road Cycling',0.35,'Cross-training only when running restricted.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-003','Trekking','D-001','Trail Running',0.8,'Same surface and gait pattern. Higher cardiac intensity. Add weighted vest if hiking is the loaded variant — otherwise loses pack tolerance training.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-003','Trekking','D-024','Mountain Running',0.65,'Captures vertical gain stimulus at higher intensity.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-003','Trekking','D-017','Snowshoeing',0.6,'Same gait, similar cardiac load. Snow-only.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-017','Snowshoeing','D-003','Trekking',0.75,'Best off-snow substitute. Hiking with weight captures cardiac demand and gait. Loses snow-specific technique (poles, balance).','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-017','Snowshoeing','D-024','Mountain Running',0.5,'Captures cardiac stress on incline. Different gait.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-017','Snowshoeing','D-001','Trail Running',0.45,'Aerobic transfer; loses snow-specific gait and balance.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-017','Snowshoeing','D-021','Uphill Skinning',0.7,'Same surface (snow), uphill travel under load. Different gear (skis with skins vs snowshoes). Ski equipment requirement may not be available.','Foot+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-017','Snowshoeing','D-018','Mountaineering',0.6,'Approach hiking in snow conditions transfers directly. Less efficient than snowshoeing on flat snow but covers the same physical demand.','Foot+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-024','Mountain Running','D-001','Trail Running',0.85,'Same gait when sustained climb is available. Less vertical-specific stimulus on rolling terrain.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-024','Mountain Running','D-003','Trekking',0.7,'Lower intensity, same vertical pattern. Pole use transfers if used.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-024','Mountain Running','D-021','Uphill Skinning',0.7,'Same vertical pattern. Snow-only. Standard skimo off-season transfer pair.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-024','Mountain Running','D-002','Road Running',0.5,'Hill repeats give vertical stimulus but lose sustained climb adaptation.','Foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-006','Road Cycling','D-007','Time-Trial Cycling',0.85,'Same aerobic demand; trains race-specific position. TT bike is stiff/aggressive, not for long unsupported rides. Tri bike has nutrition storage and more stability. Road bike + clip-on aerobars = low-cost compromise.','Cycling',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-006','Road Cycling','D-008','Mountain Biking',0.8,'Aerobic and pedaling mechanics transfer well. Heavier, slower, less aero. AR context: effectively full-fidelity (race rule mandates MTB; most riding non-technical). Pure road racing context: drops to 0.55-0.6.','Cycling',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-007','Time-Trial Cycling','D-006','Road Cycling',0.9,'Regular road bike trains all aerobic + cycling fitness. Loses TT-specific position adaptation. Add clip-on aerobars to partially close the gap.','Cycling',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-008','Mountain Biking','D-006','Road Cycling',0.75,'Aerobic and pedaling transfer well. Loses technical handling, balance, descent skill, suspension management. AR context: effectively 0.85 (most race riding non-technical); reserve technical work for race-prep peak. Pure XC MTB / Enduro: drops to 0.5-0.6.','Cycling',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-009','Packrafting','D-010','Kayaking',0.8,'Same paddle technique (both double-blade). Kayak is faster, narrower, less stable. Trains paddle muscle pattern and aerobic stimulus well. Loses packraft-specific portage technique.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-009','Packrafting','D-011','Canoeing',0.55,'Single vs double-blade is different muscle pattern; aerobic transfer good. Use only when no kayak/packraft access.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-010','Kayaking','D-009','Packrafting',0.7,'Same paddle technique. Packraft is slower and more stable — loses kayak-specific speed and handling.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-010','Kayaking','D-011','Canoeing',0.55,'Different paddle technique (single-blade); cardiovascular and core transfer.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-010','Kayaking','D-019','Paddle Rafting',0.5,'Captures river-reading, whitewater familiarity, team paddling dynamics. Solo whitewater skills (brace, roll) are different.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-011','Canoeing','D-019','Paddle Rafting',0.6,'Single-blade paddle technique transfers; different boat dynamics.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-011','Canoeing','D-010','Kayaking',0.55,'Different paddle technique (double-blade); cardiovascular and core transfer.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-011','Canoeing','D-009','Packrafting',0.5,'Different paddle and boat.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-019','Paddle Rafting','D-010','Kayaking',0.7,'Per Library: "river kayak/packraft base provides adequate physical foundation." Solo paddling builds the underlying fitness; raft team dynamics are race-specific add-on.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-019','Paddle Rafting','D-009','Packrafting',0.7,'Same logic.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-019','Paddle Rafting','D-011','Canoeing',0.6,'Single-blade technique transfers somewhat.','Water/Paddle',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-012','Rock Climbing','D-027','Obstacle Course Racing',0.45,'Builds grip strength, pull strength, body tension on apparatus (monkey bars, cargo nets, rope climbs, peg boards). Different movement patterns from technical sequencing on rock. Useful supplementary stimulus when no climbing access.','Vertical',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-012','Rock Climbing','D-014','Via Ferrata',0.4,'Shares grip and pull demands in exposed environment. Different movement pattern (fixed cable vs free climbing). Builds harness familiarity and exposure tolerance.','Vertical',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-013','Abseiling','D-014','Via Ferrata',0.5,'Builds harness familiarity and exposure tolerance in similar vertical environment. Doesn''t train descent technique or friction control specifically.','Vertical',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-013','Abseiling','D-012','Rock Climbing',0.4,'Different system (ascent vs descent) but shares harness/exposure familiarity. Many climbers learn abseiling as part of standard rope work.','Vertical',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-014','Via Ferrata','D-012','Rock Climbing',0.6,'Strong overlap on grip and pull demands. Different movement (free climbing technique vs fixed-cable sequencing + clip-unclip rhythm). Builds the underlying physical base reliably.','Vertical',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-014','Via Ferrata','D-013','Abseiling',0.4,'Shared harness/exposure familiarity. Different physical demands (descent vs ascent).','Vertical',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-014','Via Ferrata','D-027','Obstacle Course Racing',0.4,'Grip and pull demands transfer (monkey bars, cargo nets). Sequencing logic doesn''t transfer.','Vertical',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-021','Uphill Skinning',0.7,'Strongest single substitute. Both involve sustained uphill snow/alpine travel under load. Trains aerobic system, leg strength, and cold/altitude tolerance directly. Doesn''t train technical climbing or roped glacier work. Best snow-season substitute.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-003','Trekking',0.65,'Year-round workhorse substitute. Trains the loaded uphill component — the bulk of mountaineering''s physical demand. Doesn''t capture snow surface, altitude exposure, glacier travel, or roped work.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-024','Mountain Running',0.6,'Aerobic + vertical training transfers strongly. Add weighted vest to capture load tolerance — without the pack, lower-fidelity.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-012','Rock Climbing',0.55,'Captures technical climbing component when mountaineering route includes climbing pitches. Doesn''t train winter-specific skills. Most useful for routes with substantial rock pitches.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-014','Via Ferrata',0.5,'Builds harness familiarity, grip on exposed terrain, sequencing in a vertical environment. Doesn''t train roped glacier or alpine technique. Useful base for athletes new to vertical exposure.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-022','Alpine Descent',0.5,'Snow descent technique transfers if mountaineering route includes ski descent. Different gear (skis vs crampons) but cold/snow surface familiarity carries over.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-017','Snowshoeing',0.5,'Snow travel under load. Less efficient than skinning, more accessible (no skis required). No descent component.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','Mountaineering','D-013','Abseiling',0.4,'Many mountaineering routes include abseil descents. Skill substitute only — doesn''t build the physical demands. Useful for athletes new to rope work.','Vertical+Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-021','Uphill Skinning','D-024','Mountain Running',0.85,'Strongest off-snow substitute. Per Library: "Athletes without consistent snow access can build full skimo aerobic fitness off-snow." Add poles to capture upper-body pole-push pattern. Loses snow surface and skin-edge engagement.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-021','Uphill Skinning','D-003','Trekking',0.8,'Year-round substitute. Trains cardiac + leg strength + load tolerance. With poles, even better. Lower stride frequency than skinning.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-021','Uphill Skinning','D-017','Snowshoeing',0.7,'Snow uphill travel — same surface, different technique. Useful when skis unavailable but snow accessible. No descent component.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-021','Uphill Skinning','D-018','Mountaineering',0.65,'Similar uphill-under-load pattern in snow/alpine terrain. Less aerobically efficient (heavier boots, technical work).','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-021','Uphill Skinning','D-001','Trail Running',0.6,'Aerobic transfer; lighter (no load). Lower fidelity without poles or weighted vest.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-021','Uphill Skinning','D-008','Mountain Biking',0.45,'Lower-body aerobic transfer; loses upper body pole work and load element. Cross-train when running restricted.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-022','Alpine Descent','D-024','Mountain Running',0.4,'Shares eccentric quad loading on descent. Different surface, different mechanics. Per PMC7674385, prior eccentric exposure is the only proven prep when no snow. Best off-snow option but fidelity is genuinely low.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-022','Alpine Descent','D-018','Mountaineering',0.4,'If route includes technical snow descent, partial skill overlap. Different gear (crampons vs skis).','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-028','Cross-Country Skiing','D-021','Uphill Skinning',0.55,'Shares aerobic + pole work + snow surface. Different gait (kick-and-glide vs skinning). Skimo-XC crossover is real but limited by gait specificity.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-028','Cross-Country Skiing','D-024','Mountain Running',0.55,'Aerobic + pole work transfer. No snow surface or skiing-specific gait. Off-snow base option per Library.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-028','Cross-Country Skiing','D-001','Trail Running',0.4,'Aerobic transfer; no upper body or pole work. Cardiovascular base only.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-028','Cross-Country Skiing','D-006','Road Cycling',0.4,'Aerobic transfer; no upper body. Cross-train for the cardiovascular component.','Winter',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-027','Obstacle Course Racing','D-012','Rock Climbing',0.6,'Strong overlap on grip strength, pull strength, and body tension on apparatus. Different specific patterns but the underlying upper body and grip demands transfer well. Bidirectional with D-012 → D-027.','Multi-discipline',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-027','Obstacle Course Racing','D-014','Via Ferrata',0.4,'Harness familiarity, sequencing logic, grip in exposed work. Partial overlap. Bidirectional with Vertical.','Multi-discipline',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-027','Obstacle Course Racing','D-024','Mountain Running',0.35,'Captures cardiovascular base and leg strength. Doesn''t train upper body or coordination work. Use for the running-between-obstacles component.','Multi-discipline',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-027','Obstacle Course Racing','D-001','Trail Running',0.35,'Covers running-between-obstacles component. Trail surface adds variability and balance demands close to OCR running sections.','Multi-discipline',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-027','Obstacle Course Racing','D-002','Road Running',0.3,'Cardiovascular base only — covers running component on road. Loses surface variability of trail.','Multi-discipline',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
INSERT INTO layer0.discipline_training_gaps (discipline_id,discipline_name,gap_type,notes,multi_substitute_candidate,etl_version,etl_run_at) VALUES ('D-022','Alpine Descent','no_off_environment_substitute','No off-snow substitute exists for downhill skiing skill. Best fallback (D-024 at 0.4) is eccentric loading proxy only. When athlete has no snow access, plan-gen should flag this as an explicit training gap and recommend in-season concentrated snow exposure.',FALSE,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
INSERT INTO layer0.modality_groups (group_id,group_name,group_kind,description,etl_version,etl_run_at) VALUES ('paddle_flatwater','Flatwater paddle','paddle','Disciplines whose training stimulus is paddle-stroke on flat/moving non-technical water (kayak, canoe, packraft).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('paddle_whitewater','Whitewater paddle','paddle','Disciplines whose training stimulus is paddle-stroke on technical/whitewater. Member overlap with paddle_flatwater is expected (packraft, kayak).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('foot','Foot','foot','All foot-impact training-stimulus disciplines: trail running, road running, hiking/trekking, orienteering, mountain running, OCR. Cross-credit between members.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('bike_pavement','Bike on pavement','bike','Cycling disciplines on paved/gravel road surfaces (road, TT/tri bike).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('bike_offroad','Bike off-road','bike','Cycling disciplines on technical trail / mountain surfaces (mountain biking, gravel, cross-country).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('snow_travel','Snow Travel (on foot)','snow','Snow disciplines moving by foot (snowshoeing, mountaineering on snow).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('snow_glide','Skiing','snow','Snow disciplines moving by gliding (XC/Nordic skiing, skimo ascent + descent).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('climb','Roped climbing','climb','All rope-protected vertical disciplines: rock climbing, abseiling, via ferrata.','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('swim_openwater','Open-water swim','swim','Swimming disciplines in open water or pool training equivalents (open water swim, pool sprint, swimming in river crossing context).','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
