  ('D-010','paddle_whitewater',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-011','paddle_flatwater',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-012','climb',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-013','climb',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-014','climb',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-017','snow_travel',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-018','snow_travel',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-019','paddle_flatwater','Team raft, flatwater-only modality','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-021','snow_glide','Ski-equipment based; glide-phase between strides','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-022','snow_glide',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-024','foot',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-027','foot','Running base with obstacle interruptions','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-028','snow_glide',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('D-030','bike_pavement','Gravel cycling pools with road training','0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
