  ('EX122','Hip Hinge Under Pack (Practice Drill)','Technical / Skill',ARRAY['Hinge'],ARRAY['Glutes','Hamstrings','Erector Spinae'],ARRAY['Core','Hip Flexors'],ARRAY['Backpack'],ARRAY[]::TEXT[],'Lumbar — rounding under pack weight especially when fatigued; Hip — impingement at depth',ARRAY['Lower back','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX003", "exercise_name": "Romanian Deadlift (Barbell)"}, {"exercise_id": "EX019", "exercise_name": "Barbell Hip Thrust"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Practice picking up and setting down pack with proper hip hinge mechanics; lumbar injury risk at fatigue point is often at pack pickup','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX123','Pack Fit Optimization Drill','Technical / Skill',ARRAY['Carry'],ARRAY['Shoulder Girdle','Hip Belt — load transfer'],ARRAY['Core','Lumbar'],ARRAY['Backpack'],ARRAY[]::TEXT[],'Shoulder — trap fatigue if hip belt carries too little load; Lumbar — compression if hip belt carries too much; Hip Crest — pressure sores',ARRAY['Shoulder','Lower back','Hip crest (iliac crest)'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX009", "exercise_name": "Farmer Carry"}, {"exercise_id": "EX010", "exercise_name": "Rucking (Weighted Hike)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'80% load on hip belt; 20% on shoulders; sternum strap for stability not load; adjust every 30–60 min in race conditions','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX124','Power Hiking Technique','Technical / Skill',ARRAY['Locomotion'],ARRAY['Hip Flexors','Glutes','Core'],ARRAY['Calves','Shoulders','Arms'],ARRAY['Backpack','Trekking poles'],ARRAY[]::TEXT[],'Hip Flexor — repetitive high flexion angle; Achilles — high cadence on incline',ARRAY['Hip Flexor','Achilles'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX048", "exercise_name": "Hill Repeats"}, {"exercise_id": "EX050", "exercise_name": "Treadmill Incline Walk (Loaded Pack)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Shorten stride, increase cadence, use arms and poles actively; in AR the run-to-power-hike transition is a key efficiency decision','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX125','Quad-Eccentric Walk (Controlled Descent)','Technical / Skill',ARRAY['Locomotion','Single-Leg'],ARRAY['Quadriceps (eccentric)','Tibialis Anterior'],ARRAY['Hip Stabilisers','Ankle Stabilisers'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Knee — primary injury site; patellofemoral and IT band under repeated downhill; Ankle — inversion risk on loose terrain',ARRAY['Knee','Ankle'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX117", "exercise_name": "Loaded Step-Down (Eccentric Box)"}, {"exercise_id": "EX020", "exercise_name": "Nordic Hamstring Curl"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Step-over-step with slow controlled lowering; scan ahead for foot placement; knee slightly inward from neutral = quad fatigue signal','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX126','Freestyle Pull (With Buoy)','Aerobic / Endurance',ARRAY['Pull-H','Rotation'],ARRAY['Latissimus Dorsi','Triceps','Anterior Deltoid'],ARRAY['Core','Obliques','Rotator Cuff'],ARRAY['Pull buoy'],ARRAY['Pool'],'Shoulder — anterior impingement with dropped elbow catch; Wrist — ulnar deviation stress at hand entry',ARRAY['Shoulder','Wrist'],ARRAY[]::TEXT[],'{"standard": ["Swim buoy improvised (water bottle between thighs)", "Arm-only lane swimming"], "improvised": []}'::jsonb,'[{"substitute_text": "Swim buoy improvised (water bottle between thighs)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "Arm-only lane swimming", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX090", "exercise_name": "Paddling Ergometer Session"}, {"exercise_id": "EX078", "exercise_name": "Single-Arm DB Row"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Elbow leads the catch (EVF — early vertical forearm); rotate from core not shoulder; arm is a paddle not a propeller','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX127','Band Swimming Shoulder Prehab (Y-T-W-L)','Activation / Primer',ARRAY['Pull-H'],ARRAY['Rotator Cuff','Lower Traps','Serratus Anterior','Rhomboids'],ARRAY['Mid Traps','Posterior Capsule'],ARRAY['Resistance band','Bench'],ARRAY[]::TEXT[],'Shoulder — impingement if range forced; Neck — upper trap substitution if weights too heavy',ARRAY['Shoulder','Neck'],ARRAY[]::TEXT[],'{"standard": ["Light DB prone (2\u20133 lb)", "Theraband at reduced resistance", "light water bottles in each hand for Y-T-W-L pattern"], "improvised": ["Lie face down on bed edge (arms hanging)"]}'::jsonb,'[{"substitute_text": "Light DB prone (2\u20133 lb)", "equipment_required": [["Dumbbell"]], "is_improvised": false}, {"substitute_text": "Theraband at reduced resistance", "equipment_required": [["Resistance band"]], "is_improvised": false}, {"substitute_text": "Lie face down on bed edge (arms hanging)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "light water bottles in each hand for Y-T-W-L pattern", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX082", "exercise_name": "External Rotation (Band / Cable)"}, {"exercise_id": "EX081", "exercise_name": "Band Face Pull"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Prone on incline; form letters with arms using light band or 2–5 lb; prevents swimming shoulder; also excellent paddle prehab','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX128','Kicking Drill (Flutter / Frog)','Aerobic / Endurance',ARRAY['Locomotion','Hip-Ext'],ARRAY['Glutes','Hip Flexors','Quads'],ARRAY['Hamstrings','Ankles','Core'],ARRAY['Kickboard'],ARRAY['Pool'],'Knee — breaststroke kick medial stress; Ankle — plantar flexion demand; Hip Flexor — repetitive flexion',ARRAY['Knee','Ankle','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": ["Kickboard improvised (pool noodle)", "Kick drill without board"], "improvised": []}'::jsonb,'[{"substitute_text": "Kickboard improvised (pool noodle)", "equipment_required": [["Kickboard"]], "is_improvised": true}, {"substitute_text": "Kick drill without board", "equipment_required": [], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX025", "exercise_name": "Single-Leg Calf Raise (Loaded)"}, {"exercise_id": "EX039", "exercise_name": "Glute Bridge"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Flutter for freestyle — minimal knee bend; frog for breast — external rotation from hip; crossover to packrafting kick when partially in water','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX129','Swim-Specific Rotational Core (Dry Land)','Strength',ARRAY['Rotation','Anti-Rotation'],ARRAY['Obliques','Transverse Abdominis','Core'],ARRAY['Hip Flexors','Serratus'],ARRAY['Cable machine'],ARRAY[]::TEXT[],'Lumbar — rotation under load; Hip Flexor — strain if fast without warm-up',ARRAY['Lower back','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX088", "exercise_name": "Russian Twist (DB / Med Ball)"}, {"exercise_id": "EX011", "exercise_name": "Pallof Press"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Prone hip rotation holds; side-lying rotation; mimics body roll in freestyle that drives efficient catch; transfers to paddle mechanics','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX130','Rappel Device Operation Drill','Technical / Skill',ARRAY['Pull-V'],ARRAY['Grip','Brake Hand Forearm','Core'],ARRAY['Shoulder Stabilisers','Triceps'],ARRAY['Climbing — roped'],ARRAY[]::TEXT[],'Shoulder — passive position under load if brake arm not engaged; Wrist — extension stress on brake hand; Finger — rope friction burn if gloves absent',ARRAY['Shoulder','Wrist','Fingers'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX005", "exercise_name": "Dead Hang"}, {"exercise_id": "EX102", "exercise_name": "Pinch Grip (Plate / Block)"}]'::jsonb,'EX131','Wall Walk Descent Technique',NULL,NULL,NULL,'Practice slow controlled lowering in brake mode before committing to full rappel; GriGri in rappel mode differs from belay mode — practice explicitly; keep brake hand below device at all times','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX131','Wall Walk Descent Technique','Technical / Skill',ARRAY['Locomotion','Single-Leg'],ARRAY['Quadriceps (eccentric)','Ankle Stabilisers','Core'],ARRAY['Hip Stabilisers','Shoulder Stabilisers'],ARRAY['Climbing — roped'],ARRAY['Rock Wall'],'Knee — high eccentric quad load walking down vertical face; Ankle — dorsiflexion load with feet flat on wall; Shoulder — passive load if not pulling in toward wall',ARRAY['Knee','Ankle','Shoulder'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX021", "exercise_name": "Bulgarian Split Squat (DB)"}, {"exercise_id": "EX033", "exercise_name": "Depth Drop"}]'::jsonb,NULL,NULL,'EX130','Rappel Device Operation Drill',NULL,'Feet flat on wall (not tiptoes); hips square to wall; slight lean back against harness tension; walk in controlled steps not bounds; the instinct to lean in must be overridden','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX138','Rest Position & Shake-Out Drill','Technical / Skill',ARRAY['Isometric'],ARRAY['Forearm Flexors (recovery)','Shoulder Stabilisers'],ARRAY['Core','Hip Extensors'],ARRAY['Pull-up bar'],ARRAY['Rock Wall'],'Elbow — hyperextension if arm fully locks out during shake; Shoulder — impingement if weight not distributed to footwork',ARRAY['Elbow','Shoulder'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX005", "exercise_name": "Dead Hang"}, {"exercise_id": "EX106", "exercise_name": "Lock-Off Hold (90\u00b0, 120\u00b0)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Find the most straight-arm position possible; shift weight onto feet; let arm hang loose; shake from shoulder not wrist; target: 30–60s shake before crux moves; the ability to recover mid-route often determines AR climbing speed more than raw strength','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX139','On-Wall Breathing Control','Breathwork',ARRAY['Anti-Extension'],ARRAY['Diaphragm','Intercostals','Core'],ARRAY['Cervical Stabilisers'],ARRAY['Hangboard'],ARRAY['Rock Wall'],'Cervical — breath-holding increases neck tension and raises blood pressure; Forearm — oxygen debt from breath-holding accelerates pump',ARRAY['Neck','Forearm'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX193", "exercise_name": "Shooting Breath Control & Stance"}, {"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Exhale on the hard move, inhale on the easy one; do not hold breath through crux — it accelerates forearm pump by 30–40%; practice breathing pattern on easy routes until automatic before applying to limit climbing','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX140','Open Water Sighting Drill','Technical / Skill',ARRAY['Locomotion','Pull-H'],ARRAY['Neck Extensors','Anterior Deltoid','Hip Flexors'],ARRAY['Core','Glutes','Aerobic System'],ARRAY[]::TEXT[],ARRAY['Open Water Body','Pool'],'Neck — extension stress on sighting lift; Hip — sinking if timing is off; Shoulder — if head held too long above water',ARRAY['Neck','Hip','Shoulder'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX059", "exercise_name": "Neck Isometric Hold"}, {"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Lift eyes just above water surface (crocodile eyes, not chin) every 6–10 strokes; sight on inhale side; pick a large target (not a buoy); in AR packraft transitions often require sighting while swimming with gear','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX142','Bilateral Breathing Drill','Technical / Skill',ARRAY['Locomotion'],ARRAY['Aerobic System','Neck Rotators'],ARRAY['Obliques','Core'],ARRAY[]::TEXT[],ARRAY['Pool','Open Water'],'Neck — rotation demand increases with bilateral pattern; Shoulder — breathing to weaker side may alter stroke symmetry initially',ARRAY['Neck','Shoulder'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX126", "exercise_name": "Freestyle Pull (With Buoy)"}, {"exercise_id": "EX016", "exercise_name": "Thoracic Rotation Drill"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Breathe every 3 strokes (alternating sides); builds symmetrical stroke and allows navigation sighting from either side in open water; mandatory skill if current or wind pushes from one direction in AR water legs','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX144','Hike-a-Bike Carry Drill','Technical / Skill',ARRAY['Locomotion','Carry'],ARRAY['Trapezius','Core','Glutes','Quads'],ARRAY['Erector Spinae','Forearms','Hip Flexors'],ARRAY['Mountain bike','Backpack'],ARRAY[]::TEXT[],'Shoulder — bike frame edge pressure on trapezius; Lumbar — asymmetric load with bike on one shoulder; Knee — step-over technique on uneven terrain',ARRAY['Shoulder','Lower back','Knee'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX009", "exercise_name": "Farmer Carry"}, {"exercise_id": "EX050", "exercise_name": "Treadmill Incline Walk (Loaded Pack)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Carry bike on shoulder (top tube) or push-drag based on terrain angle; practice clip-out and dismount sequence to automatic; in AR hike-a-bike sections often decide races — the athlete who transitions fast and carries efficiently gains minutes per section','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX148','Crampon Walking Technique','Technical / Skill',ARRAY['Locomotion'],ARRAY['Ankle Stabilisers','Tibialis Anterior','Peroneal Muscles'],ARRAY['Quadriceps','Glutes','Hip Stabilisers'],ARRAY['Mountaineering'],ARRAY[]::TEXT[],'Ankle — over-pronation or supination on steep ice; Knee — medial stress with duck-foot French technique; Achilles — front-pointing demand on steep terrain',ARRAY['Ankle','Knee','Achilles'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX025", "exercise_name": "Single-Leg Calf Raise (Loaded)"}, {"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'French technique (flat-foot) on moderate angles — all points contact simultaneously; front-pointing on steep ice — front two points, calf demand increases sharply; kick each step deliberately — do not shuffle; crampons on approach boots behave differently than on mountaineering boots — practice in actual gear','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX149','Ice Axe Self-Arrest','Technical / Skill',ARRAY['Anti-Extension'],ARRAY['Shoulder Stabilisers','Core','Hip Extensors'],ARRAY['Forearms','Grip','Latissimus Dorsi'],ARRAY['Mountaineering'],ARRAY[]::TEXT[],'Shoulder — impact on arrest if arm position wrong; Wrist — spike contact with hard snow or ice; Ribs — body impact in fall',ARRAY['Shoulder','Wrist','Rib'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX009", "exercise_name": "Farmer Carry"}, {"exercise_id": "EX082", "exercise_name": "External Rotation (Band / Cable)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Safety-critical; practice from multiple starting positions (head-up face-down, head-down face-up, face-up); arrest position: pick into slope, adze near cheek, weight on toes and pick; build to automatic — arrest decision window on steep terrain is under 2 seconds','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX150','Rest Step Technique','Technical / Skill',ARRAY['Isometric'],ARRAY['Quadriceps (isometric)','Calf Complex'],ARRAY['Glutes','Hip Flexors','Erector Spinae'],ARRAY['Mountaineering','Backpack'],ARRAY[]::TEXT[],'Knee — hyperextension if locking out aggressively; Hip Flexor — step pause in flexed position; Lumbar — pack load transfer during pause',ARRAY['Knee','Hip Flexor','Lower back'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX037", "exercise_name": "Wall Sit"}, {"exercise_id": "EX021", "exercise_name": "Bulgarian Split Squat (DB)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Step up; lock out back leg completely (skeleton takes load, not muscle); breathe; step again; pace is set by breath recovery not leg strength at altitude; rest step allows sustained pace that would otherwise be impossible above 3000m; practice until rhythmic without conscious effort','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX152','Post-Hole Recovery Gait','Technical / Skill',ARRAY['Locomotion'],ARRAY['Hip Flexors','Glutes','Quadriceps'],ARRAY['Core','Ankle Stabilisers'],ARRAY[]::TEXT[],ARRAY['Deep Snow or Sand'],'Hip Flexor — extreme lift demand per step; Knee — torque on extract from consolidated snow; Ankle — instability in variable depth holes',ARRAY['Hip Flexor','Knee','Ankle'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX021", "exercise_name": "Bulgarian Split Squat (DB)"}, {"exercise_id": "EX025", "exercise_name": "Single-Leg Calf Raise"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'High knee lift to clear hole; minimize knee twisting on extract; pace down to sustainable rhythm immediately — post-holing is 4–6× the energy cost of hard-pack walking; in AR context the decision when to put on snowshoes vs continue post-holing is a critical pace management call','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX153','Snowshoe Gait Technique','Technical / Skill',ARRAY['Locomotion'],ARRAY['Hip Abductors','Glute Medius','Hip Flexors'],ARRAY['Quadriceps','Ankle Stabilisers','Core'],ARRAY['Snowshoes','Trekking poles','Backpack'],ARRAY[]::TEXT[],'Hip — abductor fatigue from wider-than-normal stance; IT Band — lateral stress from altered gait; Knee — medial stress if shuffling rather than lifting',ARRAY['Hip','IT Band','Knee'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX017", "exercise_name": "Lateral Band Walk"}, {"exercise_id": "EX023", "exercise_name": "Lateral Lunge (DB or BW)"}]'::jsonb,'EX154','Plunge Step Descent (Snowshoe)',NULL,NULL,NULL,'Slightly wider stance than normal walking; lift each snowshoe clear of the other rather than dragging; poles provide rhythm and reduce leg load 20–30% on ascent; gait adapts within 30–60 min of first use — first snowshoe outing is not the time to go long','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX154','Plunge Step Descent (Snowshoe)','Technical / Skill',ARRAY['Locomotion','Single-Leg'],ARRAY['Quadriceps (eccentric)','Ankle Stabilisers','Tibialis Anterior'],ARRAY['Glutes','Hip Stabilisers','Core'],ARRAY['Snowshoes','Trekking poles'],ARRAY[]::TEXT[],'Knee — high eccentric quad load; Ankle — instability on icy underlayer under soft snow; Hip — lateral sway if poles not used',ARRAY['Knee','Ankle','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX117", "exercise_name": "Loaded Step-Down (Eccentric Box)"}, {"exercise_id": "EX033", "exercise_name": "Depth Drop"}]'::jsonb,'EX155','Snowshoe Sidehill Traverse & Kickturn','EX153','Snowshoe Gait Technique',NULL,'Heel-first strike on descent; drive heel into slope; poles planted slightly ahead for balance; plunge step is the most efficient descent technique in snowshoes and has the highest fall risk on hard-pack — test conditions before committing to steep descent','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX155','Snowshoe Sidehill Traverse & Kickturn','Technical / Skill',ARRAY['Locomotion','Single-Leg'],ARRAY['Hip Abductors','Glute Medius','Ankle Evertors'],ARRAY['Core','Hip Stabilisers'],ARRAY['Snowshoes','Trekking poles'],ARRAY[]::TEXT[],'Ankle — eversion demand edge-setting on sidehill; Knee — medial stress on lower leg in traverse; Hip — abductor fatigue on sustained sidehill travel',ARRAY['Ankle','Knee','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX023", "exercise_name": "Lateral Lunge (DB or BW)"}, {"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}]'::jsonb,NULL,NULL,'EX154','Plunge Step Descent (Snowshoe)',NULL,'Edge the uphill frame of snowshoe into slope on traverse; kickturn (180° direction reversal) requires removing uphill snowshoe — practice before steep terrain; consistent edge-setting prevents slipping and reduces energy cost on slopes','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX156','Sweep Stroke Technique Drill','Technical / Skill',ARRAY['Locomotion','Rotation'],ARRAY['Obliques','Lats','Anterior Deltoid'],ARRAY['Core','Triceps','Shoulder Stabilisers'],ARRAY['Kayak','Canoe','Packraft'],ARRAY[]::TEXT[],'Shoulder — end-range stress on wide arc; Wrist — ulnar deviation if grip angle wrong at finish',ARRAY['Shoulder','Wrist'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX087", "exercise_name": "Cable High-to-Low Chop"}, {"exercise_id": "EX088", "exercise_name": "Russian Twist (DB / Med Ball)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Full arc from bow to stern (kayak) or bow to mid-ship (canoe); torso rotation drives arc — not arm reach; used for turning and course correction; the wider the arc the more turning power but slower the boat','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX157','Draw Stroke & Pry Technique','Technical / Skill',ARRAY['Rotation','Pull-H'],ARRAY['Posterior Deltoid','Lats','Obliques'],ARRAY['Biceps','Rotator Cuff','Core'],ARRAY['Kayak','Canoe'],ARRAY[]::TEXT[],'Shoulder — posterior impingement if blade angled incorrectly under load; Wrist — extension stress at recovery; Elbow — hyperextension if arm locks during pry',ARRAY['Shoulder','Wrist','Elbow'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX082", "exercise_name": "External Rotation (Band / Cable)"}, {"exercise_id": "EX011", "exercise_name": "Pallof Press"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Draw: plant blade parallel to boat, pull water under hull toward paddle; Pry: lever blade off gunwale to push boat away; both are lateral boat control — essential for docking, eddying, and avoiding obstacles; draws are shoulder-safe; pries load the elbow more','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX158','Whitewater Line Reading','Technical / Skill',ARRAY['Locomotion'],ARRAY['Cognitive Load','Visual Processing','Neck Extensors'],ARRAY['Aerobic System'],ARRAY['Kayak','Canoe','Raft'],ARRAY['River'],'Neck — sustained forward gaze at rapid approach; Cognitive — decision overload under time pressure; Wrist — reactive grip tightening on unexpected hydraulics',ARRAY['Neck','Wrist'],ARRAY['Cognitive'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}, {"exercise_id": "EX059", "exercise_name": "Neck Isometric Hold"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Scout from high ground if possible; identify entry point, line through rapid, exit eddy; read water surface features — V-shapes point downstream safe lines; pillows indicate submerged rocks; pour-overs indicate hydraulics to avoid; in AR context a bad line choice can cost gear, boat, or the race','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX159','Wet Exit & Re-entry (Kayak)','Technical / Skill',ARRAY['Rotation','Anti-Extension'],ARRAY['Hip Flexors','Core','Shoulder Stabilisers'],ARRAY['Obliques','Lats','Grip'],ARRAY['Kayak'],ARRAY['Pool or Flat Water'],'Shoulder — impact risk if bracing during capsize; Wrist — extension load on cockpit rim push; Neck — tuck position critical to avoid impact; Hip — flexibility demand on quick exit from cockpit',ARRAY['Shoulder','Wrist','Neck','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}, {"exercise_id": "EX082", "exercise_name": "External Rotation (Band / Cable)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Tuck forward before capsize; slap hull with both hands (signal for help and body position anchor); pop skirt at handle — never pull sides; push-out with hands on cockpit rim; re-entry: heel hook or cowboy scramble depending on boat width; practice until automatic — panic wet exits cause drowning','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX160','Seated Paddling Position Endurance','Isometric',ARRAY['Anti-Extension','Hinge'],ARRAY['Erector Spinae','Glutes','Hip Flexors'],ARRAY['Transverse Abdominis','Lats','Scapular Stabilisers'],ARRAY['Kayak','Foam pad'],ARRAY[]::TEXT[],'Lumbar — sustained flexion in low-back cockpit seats; Hip Flexor — chronic shortening in seated posture; Sciatica — piriformis compression from hard seat; Sacrum — point pressure on long flat water legs',ARRAY['Lower back','Hip Flexor','SI joint'],ARRAY['Neurological'],'{"standard": ["folded towel as seat pad", "add band around feet and pull to simulate paddle load"], "improvised": ["Sit on floor with legs extended against wall"]}'::jsonb,'[{"substitute_text": "Sit on floor with legs extended against wall", "equipment_required": [], "is_improvised": true}, {"substitute_text": "folded towel as seat pad", "equipment_required": [], "is_improvised": true}, {"substitute_text": "add band around feet and pull to simulate paddle load", "equipment_required": [["Resistance band"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}, {"exercise_id": "EX011", "exercise_name": "Pallof Press (Band/Cable)"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Practice sustained flat-water paddling without backrest; load hip flexors and lumbar in paddling posture through boat-specific endurance; seat pad selection matters — 4-hour legs on a hard plastic seat without conditioning causes movement breakdown; do not conflate erg fitness with boat-seat tolerance','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX162','Tandem Canoe Coordination Drill','Technical / Skill',ARRAY['Locomotion','Rotation'],ARRAY['Aerobic System','Cognitive Load'],ARRAY['Obliques','Lats','Core'],ARRAY['Canoe'],ARRAY[]::TEXT[],'Shoulder — timing mismatch with partner causes reactive over-stroke; Wrist — rate mismatch forces grip compensation; Cognitive — communication breakdown under fatigue',ARRAY['Shoulder','Wrist'],ARRAY['Cognitive'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX090", "exercise_name": "Paddling Ergometer Session"}, {"exercise_id": "EX091", "exercise_name": "Forward Stroke Technique Drill"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Bow sets the pace, stern matches and steers; call stroke changes before executing; practice side switches on command (hut-hut call); synchronised power is 15–20% more efficient than asynchronous; in AR a mismatched tandem team loses far more to coordination failure than fitness deficits','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX163','Canoe Portage Yoke Carry','Technical / Skill',ARRAY['Carry'],ARRAY['Trapezius','Cervical Stabilisers','Core','Glutes'],ARRAY['Erector Spinae','Shoulder Girdle','Quads'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Cervical Spine — direct compression under hull on yoke; Trapezius — point pressure with unpadded yoke; Shoulder — imbalanced carry without centred yoke; Lumbar — rotation mismatch when on trail with boat obscuring footing',ARRAY['Neck','Trapezius','Shoulder','Lower back'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX009", "exercise_name": "Farmer Carry"}, {"exercise_id": "EX095", "exercise_name": "Portage Carry Simulation"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Centre the yoke precisely on cervical vertebrae — off-centre causes neck muscle strain; tipping up a canoe solo requires specific technique (gunwale flick from low position); vision is obstructed — shorter strides on rough portage trail; in tandem AR portage one person can carry the canoe while the other carries the packs to halve portage time','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX164','High-Side Command Response Drill','Technical / Skill',ARRAY['Locomotion','Balance / Proprioception'],ARRAY['Glutes','Quads','Core','Hip Stabilisers'],ARRAY['Calf','Ankle Stabilisers','Grip'],ARRAY['Packraft'],ARRAY[]::TEXT[],'Ankle — rapid weight shift risk on inflated tube; Knee — lateral stress if high-side is executed with straight legs; Wrist — grip on tube handle under sudden load',ARRAY['Ankle','Knee','Wrist'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX044", "exercise_name": "BOSU Single-Leg Squat"}, {"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Safety-critical; high-side means move body weight immediately to the downstream tube when the raft is wrapping — delayed response lets the current pin the raft; practice the movement on flat water until it is reflexive; in AR team context a slow high-side response is the most common cause of raft wraps and gear loss','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX165','Raft Paddle Synchronisation & Power Phase','Technical / Skill',ARRAY['Rotation','Carry'],ARRAY['Obliques','Lats','Core'],ARRAY['Glutes','Anterior Deltoid','Triceps'],ARRAY['Packraft'],ARRAY[]::TEXT[],'Shoulder — catching water out of sync with team creates asymmetric torque on individual paddlers; Wrist — bracing on out-of-sync high-torque strokes',ARRAY['Shoulder','Wrist'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX090", "exercise_name": "Paddling Ergometer Session"}, {"exercise_id": "EX087", "exercise_name": "Cable High-to-Low Chop"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Guide calls stroke rate; all blades enter simultaneously; power phase is short and vertical — not a long sweep; synchronisation at 70% effort outperforms individual 100% effort at different timing; in AR rafting legs the guide role is critical and should be trained explicitly, not assumed','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX166','Ferry & Eddy Turn Technique','Technical / Skill',ARRAY['Rotation','Balance / Proprioception'],ARRAY['Obliques','Hip Flexors','Core'],ARRAY['Lats','Shoulder Stabilisers','Ankle (hip rotation in boat)'],ARRAY['Kayak','Canoe'],ARRAY['Moving Water'],'Hip — rotation demand in cockpit to initiate lean; Shoulder — brace position on eddy entry; Wrist — high brace load in fast eddy entry',ARRAY['Hip','Shoulder','Wrist'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX082", "exercise_name": "External Rotation (Band / Cable)"}, {"exercise_id": "EX092", "exercise_name": "Bracing Stroke Drill"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Ferry: cross current at upstream angle to move laterally without losing ground; eddy turn: hit eddy line at speed, lean and look into eddy, let current pivot the bow; lean is critical — upriver lean on eddy entry = capsize; these are the two most used whitewater navigation techniques in AR river legs','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX167','Ocean / Surf Zone Entry & Exit','Technical / Skill',ARRAY['Locomotion','Balance / Proprioception'],ARRAY['Core','Hip Stabilisers','Shoulder Stabilisers'],ARRAY['Glutes','Obliques','Grip'],ARRAY['Kayak'],ARRAY['Ocean or Surf'],'Shoulder — brace timing in breaking surf; Wrist — impact if brace is late; Spine — axial loading if dropped stern-first into trough; Cognitive — wave timing errors',ARRAY['Shoulder','Wrist','Spine (general)'],ARRAY['Cognitive'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX159", "exercise_name": "Wet Exit & Re-entry (Kayak)"}, {"exercise_id": "EX044", "exercise_name": "BOSU Single-Leg Squat"}]'::jsonb,NULL,NULL,NULL,NULL,NULL,'Time entry to paddle out between sets; punch through waves bow-first with forward momentum; on exit: surf wave straight, exit on beach before wave recedes; in AR ocean legs surf zone entry and exit are the highest injury risk moments — speed through the zone reduces exposure time; practice is essential, skill does not transfer from flat water','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX168','Skinning Uphill Technique','Technical / Skill',ARRAY['Locomotion'],ARRAY['Hip Flexors','Glutes','Calves','Tibialis Anterior'],ARRAY['Core','Erector Spinae','Hamstrings'],ARRAY['Touring/AT ski setup'],ARRAY[]::TEXT[],'Achilles — sustained dorsiflexion demand in walk mode; Hip Flexor — repetitive high flexion under pack; Lumbar — forward lean with heavy pack; Ankle — boot stiffness limits natural gait pattern',ARRAY['Achilles','Hip Flexor','Lower back','Ankle'],ARRAY[]::TEXT[],'{"standard": ["Nordic ski machine (if available)", "Ski erg (if available)"], "improvised": []}'::jsonb,'[{"substitute_text": "Nordic ski machine (if available)", "equipment_required": [["Ski erg"]], "is_improvised": false}, {"substitute_text": "Ski erg (if available)", "equipment_required": [["Ski erg"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX050", "exercise_name": "Treadmill Incline Walk (Loaded Pack)"}, {"exercise_id": "EX010", "exercise_name": "Rucking (Weighted Hike)"}]'::jsonb,'EX170','SkiMo Race Transition Drill',NULL,NULL,NULL,'Glide each ski forward with minimal lift — not a snowshoe step; weight transfers fully onto each ski; pole push from behind hip not out front; heel rises freely in walk mode but toe stays fixed to binding; on steep terrain switch to herringbone or switchbacks; efficiency is almost entirely technique — wasted motion compounds over 1000m+ vertical','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX169','Ski Kick-Turn on Slope','Technical / Skill',ARRAY['Single-Leg','Balance / Proprioception'],ARRAY['Hip Abductors','Glute Medius','Ankle Stabilisers','Core'],ARRAY['Hip Stabilisers','Quadriceps'],ARRAY['Touring/AT ski setup'],ARRAY[]::TEXT[],'Ankle — lateral stress during 180° rotation on slope; Knee — torque if ski catches on uneven surface; Hip — abductor demand holding ski in lifted position during rotation',ARRAY['Ankle','Knee','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX023", "exercise_name": "Lateral Lunge (DB or BW)"}, {"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}]'::jsonb,'EX171','Touring Ski Descent Technique',NULL,NULL,NULL,'Plant uphill pole; lift and swing uphill ski 180° first — place it pointed opposite direction; transfer weight; swing downhill ski to match; common error is rushing and catching a ski tip — causes fall on steep terrain; the ski kick-turn is distinct from the snowshoe kick-turn because of ski length and binding pivot; practice on moderate slope before committing to steep','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX170','SkiMo Race Transition Drill','Technical / Skill',ARRAY['Carry'],ARRAY['Grip','Forearms','Cognitive Load','Fine Motor Control'],ARRAY['Shoulder Girdle','Core','Hip Flexors'],ARRAY['Touring/AT ski setup'],ARRAY[]::TEXT[],'Finger — cold-induced loss of dexterity with skin adhesive and crampon clips; Wrist — repetitive buckle and clip manipulation; Cognitive — sequence errors under fatigue and cold are the primary risk',ARRAY['Fingers','Wrist'],ARRAY['Cognitive'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX005", "exercise_name": "Dead Hang"}, {"exercise_id": "EX009", "exercise_name": "Farmer Carry"}]'::jsonb,NULL,NULL,'EX168','Skinning Uphill Technique',NULL,'Race transition sequence: skin removal (fold glue-to-glue to preserve adhesive), ski crampon attach or remove, boot buckle mode change (walk to ski or reverse), pole basket swap if required; time the full sequence — SkiMo races are often decided in transitions; cold hands are the primary limiter — practice with gloves; standardise your sequence and never deviate under race pressure','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX171','Touring Ski Descent Technique','Technical / Skill',ARRAY['Locomotion','Single-Leg'],ARRAY['Quadriceps (eccentric)','Glutes','Ankle Stabilisers','Core'],ARRAY['Hip Stabilisers','Hamstrings','Tibialis Anterior'],ARRAY['Touring/AT ski setup'],ARRAY[]::TEXT[],'Knee — high eccentric quad load; ACL — valgus collapse on icy crust; Ankle — boot stiffness vs flex demand on variable snow; Hip — lateral instability on breakable crust; Lumbar — forward lean sustained under pack load',ARRAY['Knee','ACL','Ankle','Hip','Lower back'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX021", "exercise_name": "Bulgarian Split Squat (DB)"}, {"exercise_id": "EX117", "exercise_name": "Loaded Step-Down"}]'::jsonb,NULL,NULL,'EX172','Lateral Ski Edge Control Drill',NULL,'Touring skis are lighter and less damp than resort skis — they react faster to terrain changes; lean forward into the boot cuff; weight on downhill ski; short radius turns on steep terrain; in SkiMo the descent is usually the fastest section but also highest fall risk under accumulated fatigue; conserve legs for the next ascent — don''t race the descent unless the course demands it','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX172','Lateral Ski Edge Control Drill','Technical / Skill',ARRAY['Balance / Proprioception'],ARRAY['Hip Abductors','Glute Medius','Ankle Evertors','Tibialis Posterior'],ARRAY['VMO','Core','Peroneal Muscles'],ARRAY['Touring/AT ski setup'],ARRAY['Groomed Slope'],'Knee — medial collapse (valgus) if glute med fires late; Ankle — eversion stress on hard-pack; ACL — dynamic valgus on reactive edge changes',ARRAY['Knee','Ankle','ACL'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX017", "exercise_name": "Lateral Band Walk"}, {"exercise_id": "EX044", "exercise_name": "BOSU Single-Leg Squat"}]'::jsonb,'EX171','Touring Ski Descent Technique',NULL,NULL,NULL,'Traverse slope on uphill edges; practice lateral weight shift from edge to edge without skidding; the edging demand in SkiMo is less about carved turns and more about secure footing on traverses and skin tracks; glute med and ankle evertors are the primary stabilisers — both need to be pre-activated before ski days; this drill exposes weaknesses that straight-line skinning hides','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX173','Tuck Position Isometric Hold (SkiMo Descent)','Isometric',ARRAY['Squat','Anti-Extension'],ARRAY['Quadriceps (VMO','Rectus Femoris)','Glutes','Core'],ARRAY['Erector Spinae','Hip Flexors','Shoulder Stabilisers'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Knee — patellar tendon load at sustained flexion; Lumbar — flexion if core disengages; Hip Flexor — sustained compression in tuck',ARRAY['Knee','Lower back','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": ["add backpack for pack-weight simulation"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "add backpack for pack-weight simulation", "equipment_required": [["Backpack"], ["Weighted vest"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX037", "exercise_name": "Wall Sit"}, {"exercise_id": "EX067", "exercise_name": "MTB Attack Position Hold"}]'::jsonb,'EX171','Touring Ski Descent Technique','EX037','Wall Sit',NULL,'Feet shoulder-width; hips above knee height (SkiMo tuck is higher than race tuck); arms forward; hold 30–90s building to 2min; add pack weight to replicate AR load; distinct from MTB attack position (EX067) — ski tuck requires more forward shin angle and less hip hinge; the descent tuck is held for minutes at a time in SkiMo — quad endurance in this position is a direct race limiter','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX174','Aero / TT Position Hold','Isometric',ARRAY['Hinge','Anti-Extension'],ARRAY['Cervical Extensors','Hip Flexors','Erector Spinae','Forearm Flexors'],ARRAY['Core','Shoulder Stabilisers','Trapezius','VMO'],ARRAY['TT / triathlon bike','Road bike','Cycling trainer'],ARRAY[]::TEXT[],'Cervical Spine — sustained hyperextension to see forward; Lumbar — sustained flexion under aero tuck; Hip Flexor — extreme compression at high cadence in aero; Elbow — ulnar nerve compression on aero pads; Shoulder — restricted rotation from elbow-pad position',ARRAY['Neck','Lower back','Hip Flexor','Elbow','Shoulder'],ARRAY[]::TEXT[],'{"standard": ["Road bike with clip-on aero bars", "Handlebar spacer reduction (position change)"], "improvised": []}'::jsonb,'[{"substitute_text": "Road bike with clip-on aero bars", "equipment_required": [["Road bike"]], "is_improvised": false}, {"substitute_text": "Handlebar spacer reduction (position change)", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX067", "exercise_name": "MTB Attack Position Hold"}, {"exercise_id": "EX037", "exercise_name": "Wall Sit"}]'::jsonb,NULL,NULL,'EX067','MTB Attack Position Hold',NULL,'Distinct from MTB attack position (EX067) — aero tuck is far more aggressive: elbows on pads, back flat or slightly rounded, head extended upward to see forward; hold position for progressive durations (10 min → 30 min → 60 min) before attempting race distance; most triathlon bike-related injuries originate from aero position not being trained gradually; pair with thoracic rotation drill (EX016) and couch stretch (EX076) immediately post-ride','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX175','Brick Run Drill (Bike-to-Run Transition)','Technical / Skill',ARRAY['Locomotion'],ARRAY['Hip Flexors','Quadriceps','Glutes','Calves'],ARRAY['Hamstrings','Core','Ankle Stabilisers'],ARRAY['Road bike','Cycling trainer'],ARRAY[]::TEXT[],'Hip Flexor — locked-short from cycling position, restricts running stride immediately; Quad — eccentric load onset earlier than in fresh running; Achilles — gait alteration in first 5–10 min increases load; Calf — cramping risk when switching from cycling to running muscle recruitment',ARRAY['Hip Flexor','Quad','Achilles','Calf'],ARRAY[]::TEXT[],'{"standard": ["Stationary bike then treadmill (trainer sub)"], "improvised": []}'::jsonb,'[{"substitute_text": "Stationary bike then treadmill (trainer sub)", "equipment_required": [["Treadmill"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX073", "exercise_name": "Threshold Intervals (Bike)"}, {"exercise_id": "EX178", "exercise_name": "Tempo Run (Flat / Road)"}]'::jsonb,'EX174','Aero / TT Position Hold (hold position longer before the run)','EX049','Strides (Flying Sprints) after easy spin',NULL,'Ride 20–60 min then immediately run 10–20 min without rest; the first 3–8 min of the run feel like running with concrete legs — this is normal and trainable; shorten stride initially, increase cadence, let the gait open up naturally; do not fight the heavy-leg sensation by overstriding; train this transition at least twice per week in race prep; the brick is the most important and most skipped triathlon-specific workout','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX176','Triathlon Transition Practice (T1 & T2)','Technical / Skill',ARRAY['Locomotion','Carry'],ARRAY['Cognitive Load','Fine Motor Control','Grip'],ARRAY['Aerobic System (heart rate management during transition)'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Finger — dexterity loss under fatigue and adrenaline; Ankle — trip risk in transition area; Cognitive — sequence errors cost far more than physical errors in transition',ARRAY['Fingers','Ankle'],ARRAY['Cognitive'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX180", "exercise_name": "Walk-Run Interval Method"}, {"exercise_id": "EX094", "exercise_name": "Packraft Inflation / Deflation Drill"}]'::jsonb,NULL,NULL,'EX141','Wetsuit Swimming Technique (practice in isolation first)',NULL,'T1 sequence: exit water, wetsuit strip (pull cord at neck, peel to waist, step out), run to bike, helmet on and buckled before touching bike, shoes on (or run in socks to mount), mount line; T2 sequence: dismount before line, rack bike, helmet off, run shoes on, race belt on, exit; time both sequences weekly; elite triathletes lose 10–15s per transition error; practice in race conditions including wetsuit — never first time on race day','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX178','Tempo Run (Flat / Road)','Interval / Tempo',ARRAY['Locomotion'],ARRAY['Aerobic System','Glutes','Hamstrings','Hip Flexors'],ARRAY['Calves','Core','Tibialis Anterior'],ARRAY['Treadmill'],ARRAY['Road','Flat Trail'],'Hamstring — sprint mechanics if pace exceeds threshold; Achilles — sustained effort on road surface; IT Band — if gait breaks down under sustained effort; Hip Flexor — fatigue at threshold pace sustained beyond aerobic tolerance',ARRAY['Hamstring','Achilles','IT Band','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": ["Track (surface sub for road)", "Treadmill at 0\u20131% grade", "parking lot loops"], "improvised": ["Hotel or building hallway if treadmill unavailable"]}'::jsonb,'[{"substitute_text": "Track (surface sub for road)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "Treadmill at 0\u20131% grade", "equipment_required": [["Treadmill"]], "is_improvised": false}, {"substitute_text": "Hotel or building hallway if treadmill unavailable", "equipment_required": [], "is_improvised": true}, {"substitute_text": "parking lot loops", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX073", "exercise_name": "Threshold Intervals (Bike)"}, {"exercise_id": "EX048", "exercise_name": "Hill Repeats"}]'::jsonb,'EX179','Marathon Pace Run (longer duration at slightly easier effort)','EX049','Strides (Flying Sprints)',NULL,'Sustained effort at lactate threshold — approximately 1-hour race effort; 20–40 min continuous at RPE 7–8; distinct from strides (too short) and hill repeats (terrain-specific); the defining marathon training stimulus for flat-course speed; on road keep cadence 170–180 spm; on trail allow natural cadence variation; do not confuse with marathon pace — tempo is faster','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX179','Marathon Pace Run','Interval / Tempo',ARRAY['Locomotion'],ARRAY['Aerobic System','Glutes','Hamstrings','Calves'],ARRAY['Core','Hip Flexors','Tibialis Anterior'],ARRAY['Treadmill'],ARRAY['Road','Flat Trail'],'Hip Flexor — accumulated fatigue at sustained extended effort; IT Band — friction increases with volume at race pace; Plantar Fascia — road impact over sustained distance; Achilles — loading at extended duration below threshold',ARRAY['Hip Flexor','IT Band','Plantar Fascia','Achilles'],ARRAY[]::TEXT[],'{"standard": ["Track or treadmill at goal pace"], "improvised": []}'::jsonb,'[{"substitute_text": "Track at goal pace", "equipment_required": [], "is_improvised": true}, {"substitute_text": "Treadmill at goal pace", "equipment_required": [["Treadmill"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX178", "exercise_name": "Tempo Run (Flat / Road)"}, {"exercise_id": "EX075", "exercise_name": "Sweet Spot Training (Bike)"}]'::jsonb,'EX178','Tempo Run (shorter but faster)','EX178','Tempo Run',NULL,'Sustained running at goal marathon pace — 10–20 sec/mile slower than tempo; 8–20 miles depending on training phase; the primary race-specificity stimulus; teaches the body to sustain goal pace without accumulating excessive fatigue; the most important single run workout in marathon training; do on road or hard-pack trail for surface specificity; ultra athletes use this at shorter distances to build the aerobic base before extending to ultra pacing','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX180','Walk-Run Interval Method (Ultra Pacing)','Technical / Skill',ARRAY['Locomotion'],ARRAY['Aerobic System','Glutes','Hip Flexors','Quads'],ARRAY['Calves','Hamstrings','Core'],ARRAY['Treadmill'],ARRAY['Trail','Road'],'Hip Flexor — walk-run transitions load the hip flexor repetitively at the walk-to-run acceleration; Quad — eccentric fatigue accumulates differently in planned walk breaks vs continuous running; Cognitive — discipline to walk when the body wants to run is psychologically counterintuitive early in a race',ARRAY['Hip Flexor','Quad'],ARRAY['Cognitive'],'{"standard": ["Garmin run/walk alert (interval timer sub)"], "improvised": []}'::jsonb,'[{"substitute_text": "Garmin run/walk alert (interval timer sub)", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX178", "exercise_name": "Tempo Run (Flat / Road)"}, {"exercise_id": "EX124", "exercise_name": "Power Hiking Technique"}]'::jsonb,'EX179','Marathon Pace Run (extend run intervals progressively)','EX124','Power Hiking Technique (walk breaks as primary locomotion)',NULL,'Systematic planned walk breaks at a fixed ratio — e.g. run 9 min / walk 1 min, or run to aid station / walk through it; not about being too slow to run continuously — it is a deliberate energy management strategy; walk breaks initiated early and maintained consistently allow sustained pace far later in the race than running to breakdown; practice the specific ratio trained in training on race day — do not change ratios mid-race; most important ultra skill after aerobic base; also applicable in marathon for 50+ age groups or hot weather racing','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX183','Running with Poles (Trail / Ultra)','Technical / Skill',ARRAY['Locomotion','Push-H'],ARRAY['Triceps','Anterior Deltoid','Core','Hip Flexors'],ARRAY['Lat','Upper Back','Glutes'],ARRAY['Trekking poles'],ARRAY['Trail'],'Wrist — extension load on plant at running pace; Shoulder — fatigue from sustained arm drive faster than hiking; Elbow — hyperextension if arms lock on plant; Rib — side stitch from altered breathing pattern with pole arm drive',ARRAY['Wrist','Shoulder','Elbow','Rib'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX118", "exercise_name": "Trekking Pole Push Drill"}, {"exercise_id": "EX085", "exercise_name": "Med Ball Rotational Throw"}]'::jsonb,'EX051','Uphill Running Technique Drill (add poles)','EX118','Trekking Pole Push Drill (hiking pace)',NULL,'Distinct from hiking pole technique (EX118) which is at walking pace — running poles require faster plant rhythm, shorter swing arc, and higher cadence coordination with stride; plant beside foot not ahead of it; elbows stay bent — do not reach forward; poles add 5–10% speed on uphills and reduce quad load 20% on descents; legal in most trail ultras above 50k; counterproductive below marathon distance for most athletes — the coordination overhead costs more than the benefit','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX184','Road Cycling Descending Technique','Technical / Skill',ARRAY['Locomotion'],ARRAY['Forearms','Core','Hip Stabilisers','Quadriceps (eccentric braking)'],ARRAY['Glutes','Shoulder Stabilisers','Ankle Stabilisers'],ARRAY['Road bike'],ARRAY['Descent Road'],'Shoulder/Wrist — crash impact at high speed; Neck — sustained forward lean into wind; Finger — brake modulation fatigue on long descents; Elbow — hyperextension if locking out in tuck; Hip — position lock in tuck causing hip flexor cramp on subsequent climbing',ARRAY['Shoulder','Wrist','Neck','Fingers','Elbow','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX037", "exercise_name": "Wall Sit"}, {"exercise_id": "EX033", "exercise_name": "Depth Drop (Eccentric Landing Practice)"}]'::jsonb,NULL,NULL,'EX147','Loose Surface Threshold Braking (same speed management concept at lower speed)',NULL,'Distinct from MTB descending (EX052) — road descending is higher speed, no suspension, smooth surface: tuck low with elbows bent, weight back behind saddle, look well ahead; brake before corners not in them; feather both brakes progressively — don''t grab; on long mountain descents control speed in short bursts then coast to prevent brake fade and finger fatigue; choose the line before entering the corner; countersteering at speed is the critical advanced skill','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX185','Climb Pacing & Cadence Management','Technical / Skill',ARRAY['Locomotion'],ARRAY['Aerobic System','Quadriceps','Glutes','Hip Flexors'],ARRAY['Hamstrings','Calves','Core'],ARRAY['Road bike','Mountain bike','Cycling trainer','Treadmill'],ARRAY[]::TEXT[],'Hip Flexor — high cadence seated climbing compresses hip flexors sustainedly; Knee — low cadence grinding increases patellofemoral load; Cardiac — standing efforts spike heart rate 10–15 bpm and must be rationed on long climbs; Achilles — increased dorsiflexion demand when standing',ARRAY['Hip Flexor','Knee','Achilles'],ARRAY['Cardiac'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX215", "exercise_name": "Extreme Gradient Uphill Pacing"}, {"exercise_id": "EX048", "exercise_name": "Hill Repeats"}]'::jsonb,'EX184','Road Cycling Descending Technique (descend faster as pacing improves on climbs)','EX186','High Cadence Spin Drill (build cadence before applying to climbs)',NULL,'The highest-leverage technical cycling skill for long-distance events; seated spinning (85–95 rpm) conserves leg muscles but raises cardiovascular cost; standing grinding (60–70 rpm) recruits more muscle but spikes HR and glycogen; on long climbs default to seated spin, stand briefly to stretch or surge only; cadence choice is a fuel management decision — low cadence burns more glycogen; practice maintaining 85–90 rpm on grades over 6% before defaulting to grinding','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX186','High Cadence Spin Drill','Technical / Skill',ARRAY['Locomotion','Balance / Proprioception'],ARRAY['Hip Flexors','Quadriceps','Glutes','Hamstrings'],ARRAY['Core','Ankle Stabilisers'],ARRAY['Road bike','Mountain bike','Cycling trainer'],ARRAY[]::TEXT[],'Hip Flexor — repetitive high-velocity flexion; Saddle — bounce if cadence control lost; Knee — tracking stress if pedaling mechanics break at high rpm',ARRAY['Hip Flexor','Knee'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX070", "exercise_name": "Single-Leg Cycling Drill (Trainer)"}, {"exercise_id": "EX073", "exercise_name": "Threshold Intervals"}]'::jsonb,'EX185','Climb Pacing & Cadence Management (apply high cadence to actual climbs)','EX070','Single-Leg Cycling Drill (pedaling smoothness at moderate cadence first)',NULL,'Distinct from single-leg drill (EX070) which addresses pedaling smoothness; high cadence drill targets neuromuscular coordination at 100–120 rpm; seated, no bounce — if the pelvis rocks the cadence is too high; start at 90 rpm, add 5 rpm weekly; 4–6 × 60s at target cadence with full recovery; improves economy at all cadences below the target; the primary off-season cycling neuromuscular drill','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX194','Laser-Run Drill (Run-to-Shoot Transition)','Technical / Skill',ARRAY['Locomotion'],ARRAY['Aerobic System','Diaphragm','Forearm Stabilisers','Cognitive Load'],ARRAY['Core','Shoulder Stabilisers','Grip','Visual System'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Cardiac — elevated HR from running impairs shooting precision; must be managed not eliminated; Shoulder — weapon arm fatigues from sustained extension when HR is elevated; Cognitive — decision to shoot vs wait for HR to drop is a race management skill; Diaphragm — respiratory distress disrupts the breath-pause-fire window',ARRAY['Shoulder','Diaphragm'],ARRAY['Cardiac','Cognitive'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX193", "exercise_name": "Shooting Breath Control & Stance"}, {"exercise_id": "EX178", "exercise_name": "Tempo Run (Flat / Road)"}]'::jsonb,NULL,NULL,'EX193','Shooting Breath Control & Stance (shooting technique at rest before under HR load)',NULL,'Run 800m–1km at race effort (RPE 8–9), then immediately attempt 5 shots on target; the laser-run format requires athletes to manage HR recovery at the firing line — not rest until precise, but shoot while managing recovery; HR drops fastest with deliberate slow breathing not passive waiting; practice the specific transition: stop running, take weapon, find target, control breath, fire; repeat run-shoot 3–5 times per session; this combined stimulus is unique to modern pentathlon and cannot be replicated by training running and shooting separately','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX195','Rope Climb','Strength',ARRAY['Pull-V','Single-Leg'],ARRAY['Latissimus Dorsi','Biceps','Forearms','Grip'],ARRAY['Core','Hip Flexors','Shoulder Stabilisers'],ARRAY['Climbing — roped'],ARRAY[]::TEXT[],'Shoulder — anterior impingement if catch is too wide or arm pulls behind body plane; Elbow — medial epicondyle under high load climb; Grip — pulley stress on fingers during fatigue; Skin — rope friction burns without proper technique; Lumbar — rotation if core doesn''t brace',ARRAY['Shoulder','Elbow','Lower back'],ARRAY['Skin'],'{"standard": ["Rope segment on pull-up bar (texture sim)", "Towel pull-up (grip sim)", "knotted bedsheet over sturdy beam"], "improvised": ["Towel draped over playground bar (grip texture sim)"]}'::jsonb,'[{"substitute_text": "Rope segment on pull-up bar (texture sim)", "equipment_required": [["Pull-up bar"]], "is_improvised": false}, {"substitute_text": "Towel pull-up (grip sim)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "Towel draped over playground bar (grip texture sim)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "knotted bedsheet over sturdy beam", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX006", "exercise_name": "Pull-Up (BW)"}, {"exercise_id": "EX005", "exercise_name": "Dead Hang"}]'::jsonb,'EX107','One-Arm Assisted Hang (unilateral upper body control beyond rope climb)','EX006','Pull-Up (BW) (vertical pulling base before rope technique)',NULL,'Arm-over-arm with feet locked on rope using J-hook or S-wrap technique — feet provide 30–40% of the force; without feet the upper body load is nearly double; learn the foot lock before going high; on descent lower hand-under-hand — do not slide (friction burns, loss of control); at obstacle race pace the goal is fewest pulls not fastest pulls; 3–5 pulls from ground to top is the target for efficiency; builds directly from dead hang (EX005) and pull-up (EX006)','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX196','Obstacle Vault & Wall Traversal','Technical / Skill',ARRAY['Push-V','Single-Leg'],ARRAY['Triceps','Anterior Deltoid','Core','Hip Flexors','Glutes'],ARRAY['Wrist Extensors','Shoulder Stabilisers','Quads'],ARRAY['Plyo box'],ARRAY[]::TEXT[],'Wrist — EXTENSION LOAD on wall plant — flag for wrist-injured athletes; Shoulder — anterior stress at arm-bearing position; Elbow — hyperextension if arm locks during vault; Hip — impingement at top of vault if hip flexion insufficient; Rib — impact if vault under-rotated',ARRAY['Wrist','Shoulder','Elbow','Hip','Rib'],ARRAY[]::TEXT[],'{"standard": ["Low box (height progression)", "Mat over obstacle (impact sim)"], "improvised": []}'::jsonb,'[{"substitute_text": "Low box (height progression)", "equipment_required": [["Plyo box"]], "is_improvised": false}, {"substitute_text": "Mat over obstacle (impact sim)", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX006", "exercise_name": "Pull-Up (BW)"}, {"exercise_id": "EX007", "exercise_name": "Box Jump"}]'::jsonb,'EX195','Rope Climb (vertical obstacle after mastering lateral vault)','EX007','Box Jump (explosive lower body for obstacle approach)',NULL,'Speed vault (lazy vault): lead hand on obstacle, swing both legs to same side; safety vault: both hands, both legs together over; wall: jump to grab top, press body up using triceps and hip flexor pull, swing legs over; the choice of vault style depends on obstacle height and fatigue level — practice multiple variants; wrist extension warning applies here — for wrist-injured athletes substitute burpee penalty or modified step-over technique','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX197','Double Brick / Run-Bike-Run Pacing Drill','Technical / Skill',ARRAY['Locomotion'],ARRAY['Aerobic System','Glutes','Quadriceps','Hip Flexors'],ARRAY['Hamstrings','Calves','Core'],ARRAY['Road bike','Mountain bike'],ARRAY['Road','Trail'],'Hip Flexor — pre-fatigued from run 1 before bike leg; Quad — eccentric fatigue on run 2 begins earlier than in triathlon due to run 1; Cardiac — pacing error on run 1 elevates HR ceiling for the entire event; Hamstring — injury risk on run 2 increases when form breaks under compound fatigue',ARRAY['Hip Flexor','Quad','Hamstring'],ARRAY['Cardiac'],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX175", "exercise_name": "Brick Run Drill"}, {"exercise_id": "EX073", "exercise_name": "Threshold Intervals (Bike)"}]'::jsonb,NULL,NULL,'EX175','Brick Run Drill (bike-to-run only before adding full double brick)',NULL,'Distinct from the triathlon brick (EX175) in a critical way: run 1 pre-fatigues the legs before the bike — the fatigue compound is leg-dominant throughout, not upper-body swim fatigue then leg fatigue; the defining tactical skill is run 1 pacing conservatism; going 5–10% too hard on run 1 costs 15–20% on run 2; practice sequence: run 20–40 min at controlled effort (RPE 6–7), bike 30–60 min at race effort, run 10–20 min immediately; note how much harder the second run feels relative to standalone running at the same pace — this calibrates race day pacing decisions','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX199','SwimRun Water Entry & Exit Technique','Technical / Skill',ARRAY['Locomotion','Balance / Proprioception'],ARRAY['Hip Stabilisers','Ankle Stabilisers','Core','Glutes'],ARRAY['Quads (eccentric on exit scramble)','Tibialis Anterior'],ARRAY[]::TEXT[],ARRAY['Open Water'],'Ankle — inversion risk on submerged rocky entry; Knee — twisting risk on algae-covered exit rocks; Shoulder — impact if diving entry on shallow bottom; Neck — hyperextension if flat entry with head up; Hip — adductor strain on wide-leg scramble exits',ARRAY['Ankle','Knee','Shoulder','Neck','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}, {"exercise_id": "EX159", "exercise_name": "Wet Exit & Re-entry (Kayak)"}]'::jsonb,NULL,NULL,'EX159','Wet Exit & Re-entry (water safety and comfort before speed transitions)',NULL,'Entry: run to water''s edge at pace, assess depth quickly, transition to dolphin dive or high-step wade depending on depth; never dive without knowing bottom — SwimRun venues often have rocky shallow entries; exit: reduce pace approaching shore, high-step to avoid submerged obstacles, transition weight to hands if scrambling steep rocky exit; the run-to-swim and swim-to-run transitions in SwimRun happen 20–40 times per race — each one costs 3–8 seconds; efficient entry/exit technique is practiced as a specific skill and is race-time material; practice at the race venue if possible','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX200','Rowing Drive Sequence Drill','Technical / Skill',ARRAY['Hinge','Pull-H'],ARRAY['Quadriceps','Glutes','Erector Spinae','Rhomboids','Biceps'],ARRAY['Hamstrings','Core','Forearms'],ARRAY['Rowing ergometer'],ARRAY[]::TEXT[],'Lumbar — early back swing before legs finish creates shear force; Knee — patellar tendon stress at full compression at the catch; Shoulder — early arm pull disrupts drive sequence; Wrist — wrist curl at finish causes tendinitis',ARRAY['Lower back','Knee','Shoulder','Wrist'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX079", "exercise_name": "Seated Cable Row (Narrow Grip)"}, {"exercise_id": "EX003", "exercise_name": "Romanian Deadlift"}]'::jsonb,'EX204','On-Water Boat Balance Drill (apply drive sequence to moving shell)','EX201','Catch Position Hold (establish position before adding drive)',NULL,'The defining rowing technical skill: legs drive first (80% extended) before back swings, arms pull last; this sequence is unintuitive and reverting to arms-first under fatigue is the most common rowing fault; on the erg, think ''legs→pause→back→arms'' until automatic; a correct drive sequence produces 2–3× more power with less oxygen cost than an arm-dominated stroke; distinct from paddle sports where the catch is initiated by torso rotation — rowing catch is a leg-loaded press','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX201','Catch Position Hold (Rowing)','Isometric',ARRAY['Squat','Anti-Extension'],ARRAY['Quadriceps','Core','Erector Spinae','Lats'],ARRAY['Hip Flexors','Ankle Dorsiflexors','Shoulder Stabilisers'],ARRAY['Rowing ergometer'],ARRAY[]::TEXT[],'Lumbar — flexion under load if core not braced at full compression; Knee — patellar tendon at full knee flexion; Ankle — extreme dorsiflexion demand with heels down at catch; Hip Flexor — compression at full forward lean',ARRAY['Lower back','Knee','Ankle','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": [], "improvised": ["Sit on floor with back against wall, knees fully compressed, arms extended \u2014 hold position"]}'::jsonb,'[{"substitute_text": "Sit on floor with back against wall, knees fully compressed, arms extended \u2014 hold position", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}, {"exercise_id": "EX045", "exercise_name": "Ankle Mobility Drill (Wall)"}]'::jsonb,'EX200','Rowing Drive Sequence Drill (initiate drive from full catch position)','EX089','Hollow Body Hold (core compression without rowing-specific position)',NULL,'The catch is where most rowing injuries occur: full knee compression, shins vertical, body leaned forward ~15° past vertical, arms extended to blade entry; hold position for 10–20s; most rowers have insufficient ankle dorsiflexion or core strength to hold a correct catch — this drill identifies and addresses both; do not confuse with the dead hang or isometric holds elsewhere in the DB — this is a full-body compressed position unique to rowing','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX203','Rowing Erg Interval Session','Interval / Tempo',ARRAY['Locomotion','Hinge'],ARRAY['Quadriceps','Glutes','Erector Spinae','Lats','Rhomboids'],ARRAY['Hamstrings','Core','Biceps','Forearms'],ARRAY['Rowing ergometer'],ARRAY[]::TEXT[],'Lumbar — high volume erg work with poor drive sequencing creates cumulative shear; Knee — patellar tendon under high stroke rate; Wrist — overuse tendinitis at high stroke volume; Shoulder — impingement if catch is too wide',ARRAY['Lower back','Knee','Wrist','Shoulder'],ARRAY[]::TEXT[],'{"standard": ["Ski erg", "Arm bike (upper body ergometer)"], "improvised": []}'::jsonb,'[{"substitute_text": "Ski erg", "equipment_required": [["Ski erg"]], "is_improvised": false}, {"substitute_text": "Arm bike (upper body ergometer)", "equipment_required": [["Arm bike / UBE"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX090", "exercise_name": "Paddling Ergometer Session"}, {"exercise_id": "EX073", "exercise_name": "Threshold Intervals (Bike)"}]'::jsonb,NULL,NULL,'EX200','Rowing Drive Sequence Drill (technique before intervals)',NULL,'4×2000m at race pace with 3–5 min rest; or 6×500m at max effort; the erg is the primary rowing training tool when water is unavailable and the primary fitness testing tool in rowing — the Concept2 2000m time is the universal performance metric; drag factor should match boat feel (110–130 for most); erg fitness translates well to on-water but not perfectly — boat balance and blade work are not trained on the erg','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX212','Scrambling Technique (Moving Terrain)','Technical / Skill',ARRAY['Locomotion','Pull-V','Push-V'],ARRAY['Glutes','Hip Flexors','Quadriceps','Forearms','Shoulder Stabilisers'],ARRAY['Core','Hip Stabilisers','Finger Flexors','Triceps'],ARRAY[]::TEXT[],ARRAY['Rocky Terrain','Steep Hill','Boulders'],'Ankle — inversion on sloped rock surface; Wrist — EXTENSION LOAD on palm-down mantle positions — flag for wrist-injured athletes; Shoulder — anterior stress on overhead reaches; Hip — impingement at extreme high-step; Finger — friction abrasion without gloves; Knee — medial stress on awkward body position holds',ARRAY['Ankle','Wrist','Shoulder','Hip','Fingers','Knee'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX006", "exercise_name": "Pull-Up (BW)"}, {"exercise_id": "EX028", "exercise_name": "Pistol Squat / Assisted Pistol"}, {"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}]'::jsonb,'EX113','Movement on Route (apply scrambling speed to actual climbing terrain)','EX116','Mantling Technique (static mantle before dynamic scramble)',NULL,'Scrambling bridges trail running and rock climbing: you are moving through steep terrain using hands for balance and upward progress, not ascending a single route; the key distinction from hiking is commitment and three-point contact — always two hands or two feet on rock while moving the third; look at feet, not hands, for placement; move one limb at a time; test holds before weighting; on descent, face into the rock on steep sections — do not face outward until the gradient allows it; in Sky Running this section is moved through at race pace — practice builds the movement vocabulary to do so safely; WRIST NOTE: palm-pressing on rock loads wrist extension — athletes with wrist injury should use fist placement on harder moves','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX213','Scree Running Descent Technique','Technical / Skill',ARRAY['Locomotion','Single-Leg'],ARRAY['Quadriceps (eccentric)','Glutes','Ankle Stabilisers','Tibialis Anterior'],ARRAY['Hip Stabilisers','Core','Hamstrings'],ARRAY[]::TEXT[],ARRAY['Scree Field','Loose Rocky Slope'],'Ankle — inversion on sliding rock; Knee — valgus if quad fails mid-slide; Achilles — sudden deceleration when rock stops moving; Hip — lateral sway on uneven scree slide; Shin — anterior compartment impact if foot catches',ARRAY['Ankle','Knee','Achilles','Hip','Shin'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX033", "exercise_name": "Depth Drop"}, {"exercise_id": "EX035", "exercise_name": "Ankle Hops / Pogo Jumps"}, {"exercise_id": "EX044", "exercise_name": "BOSU Single-Leg Squat"}]'::jsonb,'EX214','Fell Descent (once scree commitment established, grass commitment follows)','EX052','Downhill Running Technique (trail descent mechanics before scree commitment)',NULL,'Scree running requires committing to movement the brain resists — the surface moves under you and that is the technique, not the enemy; lean slightly back, weight on heels, let feet sink and slide with each step; small rapid steps on fine scree, larger deliberate steps on boulder scree; look 3–4 steps ahead not at current foot; control direction through hip and knee angle not braking; the critical skill is reading scree type from above: fine scree runs like sand (commit and slide), large boulders require individual foot placement (treat like rocky trail); the mistake is over-braking — rigid resistance to scree movement causes falls; practice on low-consequence slopes before race terrain','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX214','Fell Descent Technique (Steep Grass, Bog, Heather)','Technical / Skill',ARRAY['Locomotion','Single-Leg'],ARRAY['Quadriceps (eccentric)','Glutes','Ankle Stabilisers','Tibialis Anterior'],ARRAY['Hip Stabilisers','Core','Peroneal Muscles'],ARRAY[]::TEXT[],ARRAY['Fell Terrain'],'Ankle — inversion in heather tussocks and hidden bog holes; Knee — medial stress on steep grass traverse; IT Band — lateral friction from grass-tilt running; Achilles — deceleration on sudden bog entry; Shin — tussock trip causing anterior tibialis strain; Hip — rapid lateral adjustment on hidden terrain features',ARRAY['Ankle','Knee','IT Band','Achilles','Shin','Hip'],ARRAY[]::TEXT[],'{"standard": [], "improvised": []}'::jsonb,'[]'::jsonb,'[{"exercise_id": "EX117", "exercise_name": "Loaded Step-Down (Eccentric Box)"}, {"exercise_id": "EX020", "exercise_name": "Nordic Hamstring Curl"}, {"exercise_id": "EX035", "exercise_name": "Ankle Hops"}]'::jsonb,'EX213','Scree Running (both require commitment — scree is more forgiving to learn first)','EX052','Downhill Running Technique (trail descent before fell-specific technique)',NULL,'Fell descent is categorically different from scree and trail descent; steep grass requires heel-planting rather than forefoot striking — the heel digs in for grip; lean forward slightly more than instinct suggests on steep grass to stay balanced; bog reading: dark green is usually firm, bright green and sphagnum moss indicate soft bog — avoid; if entering bog, commit to one step through rather than hesitating (hesitation causes sinking); heather tussocks require either running the tops (fast, high fall risk) or weaving between (slow but stable) — in races the tops are faster if you have the ankle strength; the defining fell running skill is commitment: hesitation on steep grass causes more falls than speed','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX215','Extreme Gradient Uphill Pacing (VK / Sky Technique)','Technical / Skill',ARRAY['Locomotion'],ARRAY['Glutes','Quadriceps','Hip Flexors','Calves','Core'],ARRAY['Hamstrings','Erector Spinae','Triceps (hands-on-thighs)'],ARRAY['Treadmill'],ARRAY['Steep Mountain'],'Hip Flexor — extreme sustained flexion at 40–70% grade; Cardiac — HR spikes rapidly at extreme grade and must be managed actively; Lumbar — forward lean load at sustained steep grade; Achilles — heel-drop on each step at steep grade; Quad — eccentric load on any descent section within a VK course',ARRAY['Hip Flexor','Lower back','Achilles','Quad'],ARRAY['Cardiac'],'{"standard": ["Treadmill at maximum grade (15%)", "Stair climber at max rate"], "improvised": []}'::jsonb,'[{"substitute_text": "Treadmill at maximum grade (15%)", "equipment_required": [["Treadmill"]], "is_improvised": false}, {"substitute_text": "Stair climber at max rate", "equipment_required": [["Stair climber"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX048", "exercise_name": "Hill Repeats"}, {"exercise_id": "EX037", "exercise_name": "Wall Sit"}, {"exercise_id": "EX050", "exercise_name": "Treadmill Incline Walk (Loaded Pack)"}]'::jsonb,'EX212','Scrambling Technique (extreme gradient transitions to hands-on-terrain)','EX048','Hill Repeats (6–10% grade before extreme gradient VK training)',NULL,'At 40%+ grade running becomes biomechanically and energetically inferior to power hiking for most athletes — the transition point is highly individual and must be trained; the hands-on-thighs technique (pressing palms down on thighs with each step) reduces hip flexor demand and adds 15–20% more power per step; at VK grade (1000m gain in <2km), steps are tiny and cadence is high — think shuffle not stride; on switchbacks take the inside line and maintain rhythm through the turn; HR at VK effort is near maximal throughout — the skill is sustaining forward progress at this HR rather than lowering it; the three-step-breathe pattern (three steps per full breath) is used by elite mountain runners to regulate intensity automatically — train this pattern until it replaces conscious monitoring','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX216','Plank (Front)','Isometric',ARRAY['Anti-Extension'],ARRAY['Transverse Abdominis','Rectus Abdominis','Erector Spinae'],ARRAY['Glutes','Shoulder Stabilisers','Quadriceps'],ARRAY['Weighted vest'],ARRAY[]::TEXT[],'Shoulder — anterior stress if protracted too far; Lumbar — hyperextension if core disengages (the failure mode this exercise exposes); Wrist — extension load in hand position (use forearm plank for wrist issues)',ARRAY['Shoulder','Lower back','Wrist'],ARRAY[]::TEXT[],'{"standard": ["Forearm plank (wrist sub)", "TRX plank", "Stability ball plank", "forearm plank on carpet or towel for elbow comfort"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "Forearm plank (wrist sub)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "TRX plank", "equipment_required": [["TRX / suspension trainer"]], "is_improvised": false}, {"substitute_text": "Stability ball plank", "equipment_required": [["Stability ball"]], "is_improvised": false}, {"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "forearm plank on carpet or towel for elbow comfort", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}, {"exercise_id": "EX219", "exercise_name": "Side Plank"}]'::jsonb,'EX089','Hollow Body Hold','EX218','Bird-Dog',NULL,'The foundational anti-extension exercise; all advanced core work (Hollow Body, Pallof Press, Ab Wheel) assumes the athlete can hold a plank; elbows under shoulders, straight line ear–shoulder–hip–ankle; squeeze glutes to prevent lumbar sag; progress by time (30s → 60s → 90s) then add load or instability','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX217','Dead Bug','Activation / Primer',ARRAY['Anti-Extension'],ARRAY['Transverse Abdominis','Rectus Abdominis'],ARRAY['Hip Flexors','Obliques','Erector Spinae'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Lumbar — extension if core loses contact with floor (the failure mode this exercise exposes and corrects); Hip Flexor — fatigue at high rep if core compensates',ARRAY['Lower back','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": ["bed or carpet for back comfort"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "bed or carpet for back comfort", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX216", "exercise_name": "Plank (Front)"}, {"exercise_id": "EX218", "exercise_name": "Bird-Dog"}]'::jsonb,'EX221','Mountain Climber','EX216','Plank (Front)',NULL,'Supine; arms extended toward ceiling, knees at 90°; lower opposite arm and leg toward floor while maintaining lower back flat on floor; the lumbar stays pressed into the floor — if it lifts, the rep is void; teaches the core bracing pattern used in every running stride and paddle stroke; progress: opposite limbs → same-side limbs → add band or light weight','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX218','Bird-Dog','Activation / Primer',ARRAY['Anti-Extension','Anti-Rotation'],ARRAY['Erector Spinae','Glutes','Transverse Abdominis'],ARRAY['Hamstrings','Shoulder Stabilisers','Obliques'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Lumbar — rotation if core doesn''t brace during limb extension; Hip — extension range limited by hip flexor tightness; Shoulder — anterior stress at full arm reach',ARRAY['Lower back','Hip','Shoulder'],ARRAY[]::TEXT[],'{"standard": ["towel under knees for comfort on hard floor"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "towel under knees for comfort on hard floor", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX217", "exercise_name": "Dead Bug"}, {"exercise_id": "EX216", "exercise_name": "Plank (Front)"}]'::jsonb,'EX240','Bear Crawl','EX216','Plank (Front)',NULL,'Quadruped position; extend opposite arm and leg simultaneously without rotating the hips or shoulders; a water bottle balanced on the lower back should not fall — if it does, the movement is compensated; builds the anti-rotation and anti-extension pattern that stabilises running, cycling, and paddling simultaneously; the simplest multi-plane core exercise in the DB','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX219','Side Plank','Isometric',ARRAY['Anti-Lateral-Flexion'],ARRAY['Obliques (Internal and External)','Glute Medius','Quadratus Lumborum'],ARRAY['Transverse Abdominis','Hip Abductors','Shoulder Stabilisers'],ARRAY['Weighted vest'],ARRAY[]::TEXT[],'Shoulder — anterior impingement if elbow not directly under shoulder; Lumbar — lateral flexion if hip sags (the failure this exercise exposes); Neck — lateral strain if head drops toward floor',ARRAY['Shoulder','Lower back','Neck'],ARRAY[]::TEXT[],'{"standard": ["Forearm side plank (wrist sub)", "TRX side plank", "forearm version on carpet or towel"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "Forearm side plank (wrist sub)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "TRX side plank", "equipment_required": [["TRX / suspension trainer"]], "is_improvised": false}, {"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "forearm version on carpet or towel", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX216", "exercise_name": "Plank (Front)"}, {"exercise_id": "EX243", "exercise_name": "Suitcase Carry"}]'::jsonb,'EX243','Suitcase Carry','EX216','Plank (Front)',NULL,'The foundational anti-lateral-flexion exercise; this movement pattern was entirely absent from the DB until now; elbow under shoulder, straight line ear–shoulder–hip–ankle; hips stacked, top hip slightly forward to prevent rolling; directly trains the lateral trunk stability needed for pack carry, single-arm paddle strokes, suitcase carry, and any asymmetric loading; progress by time then add hip abduction (lift top leg)','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX220','Superman / Back Extension (BW)','Strength',ARRAY['Anti-Flexion','Hip-Ext'],ARRAY['Erector Spinae','Glutes','Posterior Deltoids'],ARRAY['Hamstrings','Rhomboids','Lower Trapezius'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Lumbar — hyperextension at top if range is excessive; Cervical — neck strain if head extends beyond neutral; Hip Flexor — compression on prone position',ARRAY['Lower back','Neck','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": ["Stability ball back extension", "GHD back extension", "Prone cobra (lower load)", "bed or floor", "pillow under hips for comfort"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "Stability ball back extension", "equipment_required": [["Stability ball"]], "is_improvised": false}, {"substitute_text": "GHD back extension", "equipment_required": [["Glute ham developer (GHD)"]], "is_improvised": false}, {"substitute_text": "Prone cobra (lower load)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "bed or floor", "equipment_required": [], "is_improvised": true}, {"substitute_text": "pillow under hips for comfort", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX003", "exercise_name": "Romanian Deadlift (Barbell)"}, {"exercise_id": "EX218", "exercise_name": "Bird-Dog"}]'::jsonb,'EX003','Romanian Deadlift (Barbell)','EX218','Bird-Dog',NULL,'Prone; lift arms and legs off floor simultaneously; hold 2–3s at top; control the range — the goal is spinal extension to neutral, not hyperextension beyond; builds the posterior chain endurance needed for sustained riding position, rowing back swing, and pack carry posture; a foundational back health exercise that supports every sport in the DB','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX221','Mountain Climber','Plyometric',ARRAY['Anti-Extension','Locomotion'],ARRAY['Hip Flexors','Core','Quadriceps'],ARRAY['Glutes','Calves','Shoulder Stabilisers'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Shoulder — fatigue if arms not locked; Lumbar — extension if core disengages at speed; Hip Flexor — strain if ramped too fast without warm-up; Wrist — extension load in hand position',ARRAY['Shoulder','Lower back','Hip Flexor','Wrist'],ARRAY[]::TEXT[],'{"standard": [], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX217", "exercise_name": "Dead Bug"}, {"exercise_id": "EX238", "exercise_name": "Burpee"}]'::jsonb,'EX238','Burpee','EX216','Plank (Front)',NULL,'Plank position; alternate driving knees toward chest rapidly; maintain plank integrity — hips should not pike or sag; simultaneously trains hip flexor dynamic, core anti-extension, and metabolic conditioning; used in your Core A circuit; the dynamic counterpart to the static plank; progress by speed then add band resistance','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX222','Ab Wheel Rollout','Strength',ARRAY['Anti-Extension'],ARRAY['Rectus Abdominis','Transverse Abdominis','Lats'],ARRAY['Erector Spinae','Shoulder Stabilisers','Hip Flexors'],ARRAY['Ab wheel','Barbell'],ARRAY[]::TEXT[],'Lumbar — hyperextension under load if core strength insufficient (the primary risk — this exercise is deceptively hard); Shoulder — anterior stress at full extension; Wrist — extension load on wheel grip',ARRAY['Lower back','Shoulder','Wrist'],ARRAY[]::TEXT[],'{"standard": ["Barbell rollout (barbell with plates sub for ab wheel)", "Stability ball rollout", "plastic bag under hands on carpet", "office chair with wheels on hard floor"], "improvised": ["Towel on smooth floor (slide out and back)"]}'::jsonb,'[{"substitute_text": "Barbell rollout (barbell with plates sub for ab wheel)", "equipment_required": [["Barbell", "Squat rack"]], "is_improvised": false}, {"substitute_text": "Stability ball rollout", "equipment_required": [["Stability ball"]], "is_improvised": false}, {"substitute_text": "Towel on smooth floor (slide out and back)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "plastic bag under hands on carpet", "equipment_required": [], "is_improvised": true}, {"substitute_text": "office chair with wheels on hard floor", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX216", "exercise_name": "Plank (Front)"}, {"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}]'::jsonb,NULL,NULL,'EX216','Plank (Front)',NULL,'Kneeling; roll wheel forward maintaining rigid core; the lower back must not sag at any point — if it does, shorten the range immediately; one of the highest-load anti-extension exercises in the DB; progression from plank: if you can''t hold a 90s plank, you can''t safely do rollouts; the eccentric phase (rolling out) is the hard part — don''t collapse at full extension','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX223','Hanging Knee Raise / Toes-to-Bar','Strength',ARRAY['Anti-Extension','Pull-V'],ARRAY['Rectus Abdominis','Hip Flexors','Obliques'],ARRAY['Grip','Forearms','Lats'],ARRAY['Pull-up bar'],ARRAY[]::TEXT[],'Shoulder — anterior stress in dead hang position; Lumbar — excessive swing if kipping without control; Grip — forearm fatigue limits set duration before core fails; Hip Flexor — overload if substituting for core engagement',ARRAY['Shoulder','Lower back','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": ["Ab straps (grip sub)", "Captain''s chair knee raise", "playground bar", "lie on floor for reverse crunch (regression)"], "improvised": ["Doorframe-mount pull-up bar"]}'::jsonb,'[{"substitute_text": "Ab straps (grip sub)", "equipment_required": [["Ab straps"]], "is_improvised": false}, {"substitute_text": "Captain''s chair knee raise", "equipment_required": [], "is_improvised": true}, {"substitute_text": "Doorframe-mount pull-up bar", "equipment_required": [], "is_improvised": true}, {"substitute_text": "playground bar", "equipment_required": [], "is_improvised": true}, {"substitute_text": "lie on floor for reverse crunch (regression)", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX225", "exercise_name": "V-Sit Hold"}, {"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}]'::jsonb,NULL,NULL,'EX225','V-Sit Hold',NULL,'Hang from bar; raise knees to chest (regression) or toes to bar (progression); control the descent — no swinging; grip endurance and core flexion are trained simultaneously, which directly transfers to climbing (bringing feet to holds) and OCR rig obstacles; if grip fails before core, use ab straps; used in your Core B circuit','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX224','Bicycle Crunch','Strength',ARRAY['Rotation','Anti-Extension'],ARRAY['Obliques','Rectus Abdominis'],ARRAY['Hip Flexors','Transverse Abdominis'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Lumbar — flexion under rotation if performed too fast; Cervical — neck strain if pulling on head; Hip Flexor — dominates if core is weak',ARRAY['Lower back','Neck','Hip Flexor'],ARRAY[]::TEXT[],'{"standard": [], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX088", "exercise_name": "Russian Twist (DB / Med Ball)"}, {"exercise_id": "EX011", "exercise_name": "Pallof Press"}]'::jsonb,'EX087','Cable High-to-Low Chop','EX088','Russian Twist (DB / Med Ball)',NULL,'Supine; opposite elbow to opposite knee in alternating pattern; the power comes from torso rotation not neck pulling — hands behind head support the head only, never pull; slow and controlled reps build more oblique strength than fast reps; used in your Core B circuit; the rotational core endurance that sustains paddle stroke mechanics over hours','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX225','V-Sit Hold','Isometric',ARRAY['Anti-Extension'],ARRAY['Rectus Abdominis','Hip Flexors','Transverse Abdominis'],ARRAY['Obliques','Quadriceps'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Lumbar — compression if pelvis anteriorly tilted; Hip Flexor — strain if holding beyond core capacity; Cervical — strain if head juts forward',ARRAY['Lower back','Hip Flexor','Neck'],ARRAY[]::TEXT[],'{"standard": [], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX089", "exercise_name": "Hollow Body Hold"}, {"exercise_id": "EX227", "exercise_name": "Compression Tuck Hold"}]'::jsonb,'EX226','L-Sit (Between Chairs / Parallettes)','EX089','Hollow Body Hold',NULL,'Seated; lift legs and torso to form a V shape; arms extended alongside legs or forward; maintain posterior pelvic tilt — the lower back should not round; builds the flexion-dominant core stability used in kayak and packraft seating position; progression from hollow body hold (EX089); used in your Core B circuit','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX226','L-Sit (Between Chairs / Parallettes)','Isometric',ARRAY['Anti-Extension','Push-V'],ARRAY['Rectus Abdominis','Hip Flexors','Triceps'],ARRAY['Transverse Abdominis','Shoulder Stabilisers','Lats'],ARRAY['Parallettes','Dip bars'],ARRAY[]::TEXT[],'Shoulder — anterior stress under bodyweight support; Wrist — extension load if on flat surface (use parallettes for wrist issues); Hip Flexor — extreme demand at full L position; Elbow — tricep fatigue under bodyweight hold',ARRAY['Shoulder','Wrist','Hip Flexor','Elbow'],ARRAY[]::TEXT[],'{"standard": ["Dip bars", "Gymnastics rings", "Sturdy chairs", "countertop corner", "stairwell railing supports"], "improvised": ["Two sturdy chairs"]}'::jsonb,'[{"substitute_text": "Dip bars", "equipment_required": [["Dip bars"]], "is_improvised": false}, {"substitute_text": "Gymnastics rings", "equipment_required": [["Gymnastic rings"]], "is_improvised": false}, {"substitute_text": "Sturdy chairs", "equipment_required": [], "is_improvised": true}, {"substitute_text": "Two sturdy chairs", "equipment_required": [], "is_improvised": true}, {"substitute_text": "countertop corner", "equipment_required": [], "is_improvised": true}, {"substitute_text": "stairwell railing supports", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX225", "exercise_name": "V-Sit Hold"}, {"exercise_id": "EX227", "exercise_name": "Compression Tuck Hold"}]'::jsonb,NULL,NULL,'EX225','V-Sit Hold',NULL,'Support bodyweight on hands with legs extended horizontally; the compression strength (hip flexors pulling legs up, triceps pressing body up, core bracing the middle) is unique to this exercise; directly builds the body tension used in climbing and the seated paddling compression used in packrafting; used in your Core C circuit; progress: tuck L-sit → one leg extended → full L','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX227','Compression Tuck Hold','Isometric',ARRAY['Anti-Extension'],ARRAY['Hip Flexors','Rectus Abdominis','Transverse Abdominis'],ARRAY['Quadriceps','Obliques'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Lumbar — compression if pelvis anteriorly tilts; Hip Flexor — extreme demand at sustained hold; Quad — isometric demand at top of lift',ARRAY['Lower back','Hip Flexor','Quad'],ARRAY[]::TEXT[],'{"standard": [], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX225", "exercise_name": "V-Sit Hold"}, {"exercise_id": "EX226", "exercise_name": "L-Sit"}]'::jsonb,'EX226','L-Sit (Between Chairs / Parallettes)','EX225','V-Sit Hold',NULL,'Seated on floor; hands beside hips or slightly forward; draw knees to chest and hold with feet off the ground; the compression pattern (bringing knees toward chest using hip flexors against core bracing) is the specific demand of climbing, paddling cockpit position, and boat re-entry; used in your Core C circuit; progress by extending legs or lifting higher','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX228','Push-Up (Bodyweight)','Strength',ARRAY['Push-H'],ARRAY['Pectorals','Triceps','Anterior Deltoid'],ARRAY['Core','Serratus Anterior','Shoulder Stabilisers'],ARRAY['Weighted vest'],ARRAY[]::TEXT[],'Wrist — extension load (use fist push-up for wrist issues); Shoulder — anterior stress if elbows flare beyond 45°; Lumbar — sag if core disengages; Elbow — medial stress with close grip',ARRAY['Wrist','Shoulder','Lower back','Elbow'],ARRAY[]::TEXT[],'{"standard": ["Incline push-up (regression)", "Deficit push-up (progression)", "Band-resisted push-up", "chair seat for incline push-up (regression)", "chair seat for decline push-up (progression)", "countertop for very easy regression"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "Incline push-up (regression)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Deficit push-up (progression)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Band-resisted push-up", "equipment_required": [["Resistance band"]], "is_improvised": false}, {"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "chair seat for incline push-up (regression)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "chair seat for decline push-up (progression)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "countertop for very easy regression", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX229", "exercise_name": "Bench Press"}, {"exercise_id": "EX110", "exercise_name": "Antagonist Push-Up"}]'::jsonb,'EX229','Bench Press (Barbell / DB)','EX216','Plank (Front)',NULL,'The foundational horizontal push; elbows at 45° not flared; maintain plank from head to heel; lower chest to ground; full lockout at top; builds the pushing base needed for vaults (EX196), mantling (EX116), and general upper body conditioning; distinct from EX110 (climbing antagonist) which is framed specifically as post-climbing balance work — this entry is the standalone general strength exercise; hotel-friendly; fist position for wrist-injured athletes','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX229','Bench Press (Barbell / DB)','Strength',ARRAY['Push-H'],ARRAY['Pectorals (Sternal and Clavicular)','Triceps','Anterior Deltoid'],ARRAY['Serratus Anterior','Core (bracing)','Lats (eccentric control)'],ARRAY['Barbell','Dumbbell','Bench','Squat rack'],ARRAY[]::TEXT[],'Shoulder — anterior capsule stress at bottom of ROM; Wrist — extension load under heavy bar; Elbow — medial stress at narrow grip; Lumbar — hyperextension if arch excessive; Chest/Rib — rib injury if bar bounces',ARRAY['Shoulder','Wrist','Elbow','Lower back','Chest','Rib'],ARRAY[]::TEXT[],'{"standard": ["DB floor press (no bench)", "Landmine press (angle variant)", "push-up with backpack for load"], "improvised": ["Floor press with gallon jugs or filled bags"]}'::jsonb,'[{"substitute_text": "DB floor press (no bench)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Landmine press (angle variant)", "equipment_required": [["Landmine attachment"]], "is_improvised": false}, {"substitute_text": "Floor press with gallon jugs or filled bags", "equipment_required": [], "is_improvised": true}, {"substitute_text": "push-up with backpack for load", "equipment_required": [["Backpack"], ["Weighted vest"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX228", "exercise_name": "Push-Up (Bodyweight)"}, {"exercise_id": "EX242", "exercise_name": "Single-Arm DB Bench Press"}]'::jsonb,'EX242','Single-Arm DB Bench Press','EX228','Push-Up (Bodyweight)',NULL,'The primary horizontal push under load; retract and depress scapulae; drive feet into floor; lower bar to mid-chest; press to lockout; builds the press strength base for vault obstacles, mantling, and fall recovery from prone; DB version allows greater ROM and trains stabiliser demand; builds from push-up (EX228) as the loaded progression','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX230','Conventional Deadlift (Barbell)','Strength',ARRAY['Hinge'],ARRAY['Glutes','Hamstrings','Erector Spinae','Quadriceps'],ARRAY['Core','Lats','Forearms','Trapezius'],ARRAY['Barbell'],ARRAY[]::TEXT[],'Lumbar — rounding under heavy load (the primary deadlift risk); Knee — valgus at initiation; Bicep — rupture risk with mixed grip at heavy load; Wrist — grip failure under heavy load; Shin — barbell contact',ARRAY['Lower back','Knee','Biceps','Wrist','Shin'],ARRAY[]::TEXT[],'{"standard": ["Trap bar deadlift", "Sumo deadlift", "DB deadlift (lighter load sub)", "not a true substitute but patterns the hinge"], "improvised": ["Filled suitcase or heavy duffel bag from floor"]}'::jsonb,'[{"substitute_text": "Trap bar deadlift", "equipment_required": [["Trap bar"]], "is_improvised": false}, {"substitute_text": "Sumo deadlift", "equipment_required": [["Barbell", "Squat rack"]], "is_improvised": false}, {"substitute_text": "DB deadlift (lighter load sub)", "equipment_required": [["Dumbbell"]], "is_improvised": false}, {"substitute_text": "Filled suitcase or heavy duffel bag from floor", "equipment_required": [], "is_improvised": true}, {"substitute_text": "not a true substitute but patterns the hinge", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX003", "exercise_name": "Romanian Deadlift (Barbell)"}, {"exercise_id": "EX019", "exercise_name": "Barbell Hip Thrust"}]'::jsonb,'EX232','Hang Clean (Barbell / KB)','EX003','Romanian Deadlift (Barbell)',NULL,'Distinct from RDL (EX003): the conventional deadlift starts from the floor with more quad involvement at initiation; the RDL starts from standing and emphasises hamstring loading through the eccentric; the deadlift is the standard posterior chain strength test and the most transferable single lift to real-world picking-up-heavy-things; brace hard before breaking the floor; back neutral throughout; bar stays against legs','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX231','Front Squat (Barbell / KB)','Strength',ARRAY['Squat','Anti-Extension'],ARRAY['Quadriceps','Glutes','Core (anti-extension demand)'],ARRAY['Erector Spinae','Upper Back','Hip Flexors'],ARRAY['Barbell','Kettlebell'],ARRAY[]::TEXT[],'Wrist — extension load in clean grip rack (cross-arm grip as alternative); Knee — anterior stress at depth; Thoracic — mobility restriction limits rack position; Lumbar — flexion if thoracic extension fails (butt wink under load)',ARRAY['Wrist','Knee','Upper back','Lower back'],ARRAY[]::TEXT[],'{"standard": ["KB front rack squat (one or two KBs)", "Cross-arm grip front squat", "DB goblet squat (EX002)", "backpack held at chest (goblet position)"], "improvised": ["Gallon jugs in front rack position"]}'::jsonb,'[{"substitute_text": "KB front rack squat (one or two KBs)", "equipment_required": [["Kettlebell"]], "is_improvised": false}, {"substitute_text": "Cross-arm grip front squat", "equipment_required": [], "is_improvised": false}, {"substitute_text": "DB goblet squat (EX002)", "equipment_required": [["Dumbbell"]], "is_improvised": false}, {"substitute_text": "Gallon jugs in front rack position", "equipment_required": [], "is_improvised": true}, {"substitute_text": "backpack held at chest (goblet position)", "equipment_required": [["Backpack"], ["Weighted vest"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX002", "exercise_name": "Goblet Squat (DB/KB)"}, {"exercise_id": "EX001", "exercise_name": "Back Squat (Barbell)"}]'::jsonb,'EX001','Back Squat (Barbell)','EX002','Goblet Squat (DB/KB)',NULL,'Distinct from back squat (EX001): front load demands more thoracic extension, more core anti-extension bracing, and more quad involvement; directly transfers to the upright loaded posture of pack carry and rucking; if thoracic mobility prevents barbell front rack, use cross-arm grip or KB front rack (one or two KBs); builds the specific upright squat strength that back squat alone does not; also the safer squat to fail — bar drops forward not backward','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX232','Hang Clean (Barbell / KB)','Power',ARRAY['Hinge','Hip-Ext'],ARRAY['Glutes','Hamstrings','Trapezius','Quadriceps'],ARRAY['Calves','Core','Forearms','Shoulder Stabilisers'],ARRAY['Barbell','Kettlebell'],ARRAY[]::TEXT[],'Wrist — extension load on the catch; Shoulder — anterior stress at rack position; Lumbar — flexion if hip hinge form breaks; Knee — valgus on landing/catch if feet position wrong; Elbow — tricep strain if catch position is too narrow',ARRAY['Wrist','Shoulder','Lower back','Knee','Elbow'],ARRAY[]::TEXT[],'{"standard": ["KB clean (single-arm sub EX245)", "DB hang clean", "Muscle clean (reduced load technique)", "broomstick for pattern practice without load"], "improvised": ["Gallon jug or filled bag for improvised KB/DB clean"]}'::jsonb,'[{"substitute_text": "KB clean (single-arm sub EX245)", "equipment_required": [["Kettlebell"]], "is_improvised": false}, {"substitute_text": "DB hang clean", "equipment_required": [["Dumbbell"]], "is_improvised": false}, {"substitute_text": "Muscle clean (reduced load technique)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Gallon jug or filled bag for improvised KB/DB clean", "equipment_required": [], "is_improvised": true}, {"substitute_text": "broomstick for pattern practice without load", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX031", "exercise_name": "Kettlebell Swing (Two-Hand)"}, {"exercise_id": "EX245", "exercise_name": "Single-Arm KB Clean"}]'::jsonb,NULL,NULL,'EX031','Kettlebell Swing (Two-Hand)',NULL,'Triple extension (ankle, knee, hip) in one explosive movement; the most sport-transferable Olympic lift variant; hang position (bar at mid-thigh) removes the technical complexity of pulling from the floor; builds the exact explosive hip extension pattern used in jumping, sprinting, standing pedal surges, and scrambling; KB single-arm clean (EX240) is the asymmetric variant; progress: KB clean → barbell hang clean → power clean from floor','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX233','Lateral Raise (DB / Band)','Strength',ARRAY['Abduction'],ARRAY['Lateral Deltoid'],ARRAY['Supraspinatus','Anterior Deltoid','Trapezius'],ARRAY['Dumbbell','Kettlebell','Resistance band'],ARRAY[]::TEXT[],'Shoulder — supraspinatus impingement above 90° if internal rotation present; Neck — upper trap compensation if weight too heavy; Elbow — stress if arms fully locked',ARRAY['Shoulder','Neck','Elbow'],ARRAY[]::TEXT[],'{"standard": ["Cable lateral raise", "Plate lateral raise"], "improvised": []}'::jsonb,'[{"substitute_text": "Cable lateral raise", "equipment_required": [["Cable machine"]], "is_improvised": false}, {"substitute_text": "Plate lateral raise", "equipment_required": [["Weight plates"]], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX081", "exercise_name": "Band Face Pull"}, {"exercise_id": "EX098", "exercise_name": "DB Shoulder Press"}]'::jsonb,'EX098','DB Shoulder Press','EX066','Band Pull-Apart',NULL,'Raise arms to shoulder height — not above; slight forward lean prevents supraspinatus impingement; the lateral deltoid has no direct target elsewhere in the DB; overhead stability for pack carry, paddle recovery arc, and climbing reach all load the lateral deltoid; keep weight moderate — the lateral delt is a small muscle and heavy weights force trap compensation which is counterproductive','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX234','Hammer Curl (DB)','Strength',ARRAY['Pull-H'],ARRAY['Brachioradialis','Biceps Brachii (long head)','Brachialis'],ARRAY['Forearm Flexors','Wrist Stabilisers'],ARRAY['Dumbbell'],ARRAY[]::TEXT[],'Elbow — medial epicondyle stress with heavy load; Wrist — deviation if not kept neutral; Shoulder — anterior stress if swinging',ARRAY['Elbow','Wrist','Shoulder'],ARRAY[]::TEXT[],'{"standard": ["Cable hammer curl", "Band hammer curl", "loaded grocery bag with rigid handle"], "improvised": ["Gallon water jug held with neutral grip"]}'::jsonb,'[{"substitute_text": "Cable hammer curl", "equipment_required": [["Cable machine"]], "is_improvised": false}, {"substitute_text": "Band hammer curl", "equipment_required": [["Resistance band"]], "is_improvised": false}, {"substitute_text": "Gallon water jug held with neutral grip", "equipment_required": [], "is_improvised": true}, {"substitute_text": "loaded grocery bag with rigid handle", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX005", "exercise_name": "Dead Hang"}, {"exercise_id": "EX006", "exercise_name": "Pull-Up (BW)"}]'::jsonb,'EX006','Pull-Up (BW)','EX005','Dead Hang',NULL,'Neutral grip (palms facing each other); the brachioradialis is the primary forearm flexor for grip and the muscle that fatigues first during dead hangs, pull-ups, and climbing; hammer curl specifically loads it in a way standard bicep curls do not; used in your Week 1 training plan; builds the grip-supporting forearm strength that underlies all pulling work in the DB; also supports elbow joint health under high pull-up volume','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX235','Tricep Pushdown / Extension (Cable / Band)','Strength',ARRAY['Push-H'],ARRAY['Triceps (all three heads)'],ARRAY['Anconeus','Forearm Extensors'],ARRAY['Cable machine','Resistance band'],ARRAY[]::TEXT[],'Elbow — hyperextension at lockout; Wrist — deviation if grip angle wrong; Shoulder — anterior stress if elbows drift forward',ARRAY['Elbow','Wrist','Shoulder'],ARRAY[]::TEXT[],'{"standard": ["Band tricep extension", "Overhead DB extension", "Skull crusher (barbell)", "band anchored overhead on door for pushdown", "diamond push-up (bodyweight tricep emphasis)"], "improvised": ["Chair dips (hands on chair seat, feet on floor)"]}'::jsonb,'[{"substitute_text": "Band tricep extension", "equipment_required": [["Resistance band"]], "is_improvised": false}, {"substitute_text": "Overhead DB extension", "equipment_required": [["Dumbbell"]], "is_improvised": false}, {"substitute_text": "Skull crusher (barbell)", "equipment_required": [["Barbell", "Squat rack"]], "is_improvised": false}, {"substitute_text": "Chair dips (hands on chair seat, feet on floor)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "band anchored overhead on door for pushdown", "equipment_required": [["Resistance band"]], "is_improvised": true}, {"substitute_text": "diamond push-up (bodyweight tricep emphasis)", "equipment_required": [], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX228", "exercise_name": "Push-Up (Bodyweight)"}, {"exercise_id": "EX110", "exercise_name": "Antagonist Push-Up"}]'::jsonb,'EX229','Bench Press (Barbell / DB)','EX228','Push-Up (Bodyweight)',NULL,'Elbows fixed at sides; extend forearm to full lockout; the triceps are the antagonist to the heavy pulling volume in the DB (pull-ups, rows, hangs); without tricep balance work, elbow tendinopathy develops from the flexor-extensor imbalance; also the direct strength base for push-up lockout, bench press lockout, vault lock-off, and mantling; used in your training plan','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX236','Leg Curl (Machine / Band)','Strength',ARRAY['Hinge'],ARRAY['Hamstrings (concentric emphasis)'],ARRAY['Gastrocnemius','Popliteus'],ARRAY['Leg curl machine','Resistance band','Stability ball'],ARRAY[]::TEXT[],'Knee — anterior cruciate ligament stress if machine poorly aligned; Hamstring — cramp at peak contraction; Lumbar — extension if prone position not braced',ARRAY['Knee','Hamstring','Lower back'],ARRAY[]::TEXT[],'{"standard": ["Stability ball hamstring curl", "Sliding disc hamstring curl", "Band ankle curl", "band around ankle anchored to bed leg"], "improvised": ["Towel hamstring curl on smooth floor (heel slides)"]}'::jsonb,'[{"substitute_text": "Stability ball hamstring curl", "equipment_required": [["Stability ball"]], "is_improvised": false}, {"substitute_text": "Sliding disc hamstring curl", "equipment_required": [["Slider discs"]], "is_improvised": false}, {"substitute_text": "Band ankle curl", "equipment_required": [["Resistance band"]], "is_improvised": false}, {"substitute_text": "Towel hamstring curl on smooth floor (heel slides)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "band around ankle anchored to bed leg", "equipment_required": [["Resistance band"]], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX020", "exercise_name": "Nordic Hamstring Curl"}, {"exercise_id": "EX003", "exercise_name": "Romanian Deadlift"}]'::jsonb,'EX020','Nordic Hamstring Curl','EX039','Glute Bridge (Double-Leg)',NULL,'Concentric hamstring loading — the pattern entirely absent from the DB until now; Nordic Hamstring Curl (EX020) covers eccentric only; some athletes need to build concentric hamstring strength before they can safely train the eccentric; also addresses the hamstring weakness that cycling creates (cyclists are quad-dominant); prone or seated depending on machine; band around ankle is the hotel substitute; regression for Nordic Curl','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX237','Leg Extension (Machine)','Strength',ARRAY['Squat'],ARRAY['Quadriceps (all four heads','VMO emphasis at terminal extension)'],ARRAY['Tibialis Anterior'],ARRAY['Leg extension machine'],ARRAY[]::TEXT[],'Knee — patellar tendon stress under heavy load; Anterior Cruciate Ligament — open-chain shear force at full extension (control load); Hip — none (isolated joint)',ARRAY['Knee','ACL','Hip'],ARRAY[]::TEXT[],'{"standard": ["Band terminal knee extension (EX063 as partial sub)", "Sissy squat (bodyweight quad isolation)"], "improvised": ["No direct substitute \u2014 use wall sit (EX037) or TKE with band on chair leg"]}'::jsonb,'[{"substitute_text": "Band terminal knee extension (EX063 as partial sub)", "equipment_required": [["Resistance band"]], "is_improvised": false}, {"substitute_text": "Sissy squat (bodyweight quad isolation)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "No direct substitute \u2014 use wall sit (EX037) or TKE with band on chair leg", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX063", "exercise_name": "Terminal Knee Extension (TKE)"}, {"exercise_id": "EX021", "exercise_name": "Bulgarian Split Squat"}]'::jsonb,'EX021','Bulgarian Split Squat (DB)','EX063','Terminal Knee Extension (TKE)',NULL,'The primary progressive quad isolation exercise; TKE (EX063) is an activation drill at light band resistance — leg extension provides the progressive overload path for quad strengthening under controlled conditions; relevant to knee rehab, pre/post-surgery, and addressing the quad weakness that contributes to patellofemoral pain; use controlled tempo and moderate load — this is a precision tool not a max-effort lift','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX238','Burpee','Power',ARRAY['Push-H','Squat','Locomotion'],ARRAY['Full Body (Pectorals','Triceps','Quadriceps','Glutes','Hip Flexors)'],ARRAY['Core','Calves','Shoulder Stabilisers'],ARRAY['Weighted vest'],ARRAY[]::TEXT[],'Wrist — extension load on ground contact; Shoulder — anterior stress on rapid push-up phase; Lumbar — hyperextension if core doesn''t brace through the transition; Knee — valgus on jump landing; Achilles — reactive load on jump',ARRAY['Wrist','Shoulder','Lower back','Knee','Achilles'],ARRAY[]::TEXT[],'{"standard": ["Step-back burpee (reduced impact)", "Box burpee (elevated hands)", "hotel room floor space"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "Step-back burpee (reduced impact)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "Box burpee (elevated hands)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "hotel room floor space", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX228", "exercise_name": "Push-Up (Bodyweight)"}, {"exercise_id": "EX032", "exercise_name": "Jump Squat"}]'::jsonb,NULL,NULL,'EX228','Push-Up (Bodyweight)',NULL,'Squat down, hands to floor, jump or step feet back to plank, push-up, jump feet to hands, jump up; the universal metabolic conditioning exercise and the standard OCR penalty; combines squat, push-up, and jump in one movement; the full-body integration and rapid position changes make this uniquely applicable to multi-sport transitions and fall-recovery scenarios; hotel-friendly; scaleable from step-back (regression) to jump-over-obstacle (progression)','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX239','Turkish Get-Up (KB / DB)','Strength',ARRAY['Anti-Rotation','Anti-Extension','Single-Leg'],ARRAY['Shoulder Stabilisers','Core','Glutes','Quadriceps'],ARRAY['Obliques','Hip Flexors','Triceps','Forearm Stabilisers'],ARRAY['Kettlebell','Dumbbell'],ARRAY[]::TEXT[],'Shoulder — sustained overhead stability under load throughout; Wrist — extension load in posted hand; Lumbar — rotation if core not braced during transitions; Knee — medial stress in half-kneeling position',ARRAY['Shoulder','Wrist','Lower back','Knee'],ARRAY[]::TEXT[],'{"standard": ["Bodyweight get-up (no load)", "Half get-up (stop at kneeling)", "shoe held overhead for bodyweight patterning"], "improvised": ["Gallon water jug or filled bag as KB substitute"]}'::jsonb,'[{"substitute_text": "Bodyweight get-up (no load)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Half get-up (stop at kneeling)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Gallon water jug or filled bag as KB substitute", "equipment_required": [], "is_improvised": true}, {"substitute_text": "shoe held overhead for bodyweight patterning", "equipment_required": [], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX043", "exercise_name": "Single-Leg Balance Hold"}, {"exercise_id": "EX219", "exercise_name": "Side Plank"}]'::jsonb,NULL,NULL,'EX043','Single-Leg Balance Hold',NULL,'From supine to standing with weight locked out overhead; the most complete single exercise for integrated full-body stability; every transition (roll to elbow, post to hand, sweep leg, stand) trains a different stability pattern; directly applicable to getting up from the ground under load (AR transitions, fell running falls, mountaineering); the sustained overhead hold trains the shoulder stability that supports all pressing and carrying; novel enough to maintain athlete engagement; progress: bodyweight → light KB → heavy KB','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX240','Bear Crawl','Activation / Primer',ARRAY['Locomotion','Anti-Extension','Anti-Rotation'],ARRAY['Core','Shoulder Stabilisers','Hip Flexors','Quadriceps'],ARRAY['Glutes','Triceps','Ankle Stabilisers'],ARRAY[]::TEXT[],ARRAY[]::TEXT[],'Wrist — extension load on hands; Shoulder — sustained loading in crawl position; Lumbar — rotation and extension if moving too fast; Knee — contact on hard surfaces',ARRAY['Wrist','Shoulder','Lower back','Knee'],ARRAY[]::TEXT[],'{"standard": ["towel under hands on smooth floor for reduced friction"], "improvised": ["No equipment needed"]}'::jsonb,'[{"substitute_text": "No equipment needed", "equipment_required": [], "is_improvised": true}, {"substitute_text": "towel under hands on smooth floor for reduced friction", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX216", "exercise_name": "Plank (Front)"}, {"exercise_id": "EX218", "exercise_name": "Bird-Dog"}]'::jsonb,NULL,NULL,'EX216','Plank (Front)',NULL,'Hands and feet on ground, knees hovering 2 inches above floor; move opposite hand and foot forward simultaneously; the crawling locomotion pattern is absent elsewhere in the DB; builds shoulder stability, hip mobility, core anti-rotation, and proprioceptive awareness simultaneously; used as warm-up, OCR obstacle, and general conditioning; keep the back flat — if the hips sway, slow down','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX241','Single-Arm KB Front Squat','Strength',ARRAY['Squat','Anti-Lateral-Flexion'],ARRAY['Quadriceps','Glutes','Obliques','Quadratus Lumborum'],ARRAY['Core','Shoulder Stabilisers','Forearm (rack position)'],ARRAY['Kettlebell'],ARRAY[]::TEXT[],'Knee — valgus under asymmetric load (the failure this exercise exposes); Wrist — extension in rack position; Shoulder — anterior stress in rack; Lumbar — lateral flexion toward unloaded side if core fails',ARRAY['Knee','Wrist','Shoulder','Lower back'],ARRAY[]::TEXT[],'{"standard": ["Double KB front squat (bilateral KB rack sub for asymmetric)", "Goblet squat (EX002 as bilateral sub)"], "improvised": ["Gallon jug or filled bag held at shoulder in rack position"]}'::jsonb,'[{"substitute_text": "Double KB front squat (bilateral KB rack sub for asymmetric)", "equipment_required": [["Kettlebell"]], "is_improvised": false}, {"substitute_text": "Goblet squat (EX002 as bilateral sub)", "equipment_required": [["Dumbbell"], ["Kettlebell"]], "is_improvised": false}, {"substitute_text": "Gallon jug or filled bag held at shoulder in rack position", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX002", "exercise_name": "Goblet Squat (DB/KB)"}, {"exercise_id": "EX219", "exercise_name": "Side Plank"}]'::jsonb,'EX231','Front Squat (Barbell / KB)','EX002','Goblet Squat (DB/KB)',NULL,'KB in front rack on one side; squat with perfect symmetry — the loaded side should not lean, drop, or rotate; the anti-lateral-flexion demand is categorically different from bilateral goblet or back squat; directly trains the asymmetric trunk stability used in pack carry, single-blade paddling, and loaded cycling; the obliques and quadratus lumborum resist lateral collapse on every rep — bilateral squats do not create this demand','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX242','Single-Arm DB Bench Press','Strength',ARRAY['Push-H','Anti-Rotation'],ARRAY['Pectorals','Triceps','Anterior Deltoid','Obliques'],ARRAY['Core (anti-rotation)','Glutes (hip stability on bench)'],ARRAY['Dumbbell','Bench'],ARRAY[]::TEXT[],'Shoulder — anterior capsule stress at bottom of ROM; Lumbar — rotation toward loaded side if core fails; Elbow — medial stress under load',ARRAY['Shoulder','Lower back','Elbow'],ARRAY[]::TEXT[],'{"standard": ["Floor press single-arm (no bench)", "Cable single-arm press (standing)", "single-arm push-up (advanced)"], "improvised": ["Single-arm floor press with gallon jug"]}'::jsonb,'[{"substitute_text": "Floor press single-arm (no bench)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Cable single-arm press (standing)", "equipment_required": [["Cable machine"]], "is_improvised": false}, {"substitute_text": "Single-arm floor press with gallon jug", "equipment_required": [], "is_improvised": true}, {"substitute_text": "single-arm push-up (advanced)", "equipment_required": [], "is_improvised": false}]'::jsonb,'[{"exercise_id": "EX228", "exercise_name": "Push-Up (Bodyweight)"}, {"exercise_id": "EX011", "exercise_name": "Pallof Press"}]'::jsonb,NULL,NULL,'EX228','Push-Up (Bodyweight)',NULL,'One DB pressed while lying on bench; the body wants to roll toward the loaded side — resisting this is the core anti-rotation stimulus that bilateral bench pressing does not produce; glutes and core must fire to maintain stable hip position on the bench; directly trains the asymmetric pressing that happens in vaulting (one arm), mantling (shifting weight), and paddle exit (one-arm push away from water); also reveals and addresses left-right pressing imbalances','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX243','Suitcase Carry','Loaded Carry',ARRAY['Carry','Anti-Lateral-Flexion'],ARRAY['Obliques','Quadratus Lumborum','Grip','Forearms'],ARRAY['Glutes','Core','Trapezius','Calves'],ARRAY['Dumbbell','Kettlebell'],ARRAY[]::TEXT[],'Lumbar — lateral flexion toward loaded side (the failure this corrects); Grip — forearm fatigue under sustained one-side load; Shoulder — trap overload with heavy weight',ARRAY['Lower back','Shoulder'],ARRAY[]::TEXT[],'{"standard": ["Farmer carry (EX009 bilateral version)", "Loaded backpack one-strap carry", "filled grocery bag", "suitcase in one hand"], "improvised": ["Gallon jug in one hand"]}'::jsonb,'[{"substitute_text": "Farmer carry (EX009 bilateral version)", "equipment_required": [], "is_improvised": false}, {"substitute_text": "Loaded backpack one-strap carry", "equipment_required": [["Backpack"], ["Weighted vest"]], "is_improvised": false}, {"substitute_text": "Gallon jug in one hand", "equipment_required": [], "is_improvised": true}, {"substitute_text": "filled grocery bag", "equipment_required": [], "is_improvised": true}, {"substitute_text": "suitcase in one hand", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX009", "exercise_name": "Farmer Carry"}, {"exercise_id": "EX219", "exercise_name": "Side Plank"}]'::jsonb,'EX244','Overhead Carry / Waiter Walk','EX009','Farmer Carry',NULL,'Farmer carry with one hand only; the body must resist lateral flexion toward the loaded side — this is a walking side plank; the anti-lateral-flexion pattern directly transfers to pack carry with asymmetric loads, portage with boat on one shoulder, and single-arm gear hauling; walk tall with shoulders level — if the loaded shoulder drops, reduce weight; distinct from bilateral farmer carry (EX009) because the core demand changes completely','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX244','Overhead Carry / Waiter Walk','Loaded Carry',ARRAY['Carry','Anti-Lateral-Flexion','Push-V'],ARRAY['Shoulder Stabilisers (Rotator Cuff','Deltoid)','Obliques','Core'],ARRAY['Trapezius','Quadratus Lumborum','Glutes','Calves'],ARRAY['Dumbbell','Kettlebell'],ARRAY[]::TEXT[],'Shoulder — impingement if overhead position is forced beyond available range; Lumbar — hyperextension if ribcage flares under overhead load; Wrist — extension load under KB; Cervical — lateral strain if head tilts away from load',ARRAY['Shoulder','Lower back','Wrist','Neck'],ARRAY[]::TEXT[],'{"standard": ["Single-arm overhead KB carry (both KB and DB work)", "Bottoms-up KB carry (instability progression)", "filled bag held overhead"], "improvised": ["Gallon jug locked out overhead"]}'::jsonb,'[{"substitute_text": "Single-arm overhead KB carry (both KB and DB work)", "equipment_required": [["Dumbbell"]], "is_improvised": false}, {"substitute_text": "Bottoms-up KB carry (instability progression)", "equipment_required": [["Kettlebell"]], "is_improvised": false}, {"substitute_text": "Gallon jug locked out overhead", "equipment_required": [], "is_improvised": true}, {"substitute_text": "filled bag held overhead", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX098", "exercise_name": "DB Shoulder Press"}, {"exercise_id": "EX243", "exercise_name": "Suitcase Carry"}]'::jsonb,NULL,NULL,'EX243','Suitcase Carry',NULL,'One weight locked out overhead; walk with tall posture; the shoulder must stabilise under load while the body moves — the exact demand of carrying gear overhead on a portage or stabilising a pack when it shifts during technical terrain; also builds the thoracic extension and ribcage control needed for sustained riding position; unique in the DB: combines shoulder stability, anti-lateral-flexion, and locomotion simultaneously','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX245','Single-Arm KB Clean','Power',ARRAY['Hinge','Hip-Ext','Anti-Rotation'],ARRAY['Glutes','Hamstrings','Forearm Flexors','Core (anti-rotation)'],ARRAY['Trapezius','Shoulder Stabilisers','Obliques'],ARRAY['Kettlebell'],ARRAY[]::TEXT[],'Wrist — impact on catch if technique wrong (KB flips onto forearm); Shoulder — anterior stress at rack; Lumbar — rotation under explosive hip drive; Grip — finger callus and skin tear with high volume',ARRAY['Wrist','Shoulder','Lower back'],ARRAY[]::TEXT[],'{"standard": ["Single-arm KB swing (regression \u2014 no catch)", "DB clean (DB substitution for KB)", "filled bag with handle"], "improvised": ["Gallon jug (light single-arm clean)"]}'::jsonb,'[{"substitute_text": "Single-arm KB swing (regression \u2014 no catch)", "equipment_required": [["Kettlebell"]], "is_improvised": false}, {"substitute_text": "DB clean (DB substitution for KB)", "equipment_required": [["Dumbbell"]], "is_improvised": false}, {"substitute_text": "Gallon jug (light single-arm clean)", "equipment_required": [], "is_improvised": true}, {"substitute_text": "filled bag with handle", "equipment_required": [], "is_improvised": true}]'::jsonb,'[{"exercise_id": "EX031", "exercise_name": "Kettlebell Swing (Two-Hand)"}, {"exercise_id": "EX232", "exercise_name": "Hang Clean"}]'::jsonb,'EX232','Hang Clean (Barbell / KB)','EX031','Kettlebell Swing (Two-Hand)',NULL,'Explosive hip extension with single-arm catch to rack position; the unilateral explosive hip drive creates an anti-rotation demand that bilateral cleans do not — the core must resist the rotational force of the one-sided power generation; directly trains the asymmetric explosive power pattern used in single-blade paddle stroke power, scrambling push-off, and standing pedal surges; the KB catch teaches wrist control and deceleration under load; progress from two-hand KB swing → single-arm swing → single-arm clean','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz);
INSERT INTO layer0.sport_exercise_map (exercise_id,exercise_name,exercise_type,sport_name,sport_relevance_note,priority,etl_version,etl_run_at) VALUES ('EX001','Back Squat (Barbell)','Strength','Trail Running','Primary lower body strength builder; powers uphill drive and controls eccentric descent load under pack','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX002','Goblet Squat (DB/KB)','Strength','Trail Running','Hotel substitute for back squat; same sport carryover with less equipment','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX003','Romanian Deadlift (Barbell)','Strength','Trail Running','Hamstring and glute loading for push-off power and descent control; posterior chain base','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX004','Single-Leg RDL (DB)','Strength','Trail Running','Unilateral posterior chain; directly mirrors single-leg braking mechanics on trail descents','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX007','Box Jump','Plyometric','Trail Running','Explosive hip extension for steep uphill transitions and obstacle clearance','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX008','Broad Jump','Plyometric','Trail Running','Horizontal power output; stream crossings, obstacle hops; also a field test metric','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX009','Farmer Carry','Loaded Carry','Trail Running','Pack carry simulation; builds grip, trap, and core endurance under sustained load','Medium','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX010','Rucking (Weighted Hike)','Loaded Carry','Trail Running','Direct race sim for foot legs; primary training modality for AR pack adaptation','Critical','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX011','Pallof Press (Band/Cable)','Isometric','Trail Running','Core anti-rotation under load; controls lateral trunk sway with heavy pack','Medium','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX012','Copenhagen Plank','Isometric','Trail Running','Groin and adductor strength for lateral terrain demands and hip stability under fatigue','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX013','Hip Circle (Band)','Activation / Primer','Trail Running','Pre-run glute activation; ensures glutes fire before demand is placed on the kinetic chain','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX014','World''s Greatest Stretch','Mobility','Trail Running','Full lower chain prep in one drill; hip flexors, T-spine, hamstrings — all trail running limiters','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX015','Pigeon Pose','Flexibility / Stretching','Trail Running','Piriformis and hip external rotator recovery; prevents sciatic and IT band issues post-run','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX016','Thoracic Rotation Drill','Mobility','Trail Running','T-spine mobility for arm swing counterrotation; stiff T-spine increases lumbar stress on uneven terrain','Medium','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX017','Lateral Band Walk','Activation / Primer','Trail Running','Glute med activation; controls knee valgus under fatigue — a primary cause of IT band and patellofemoral pain','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX018','Foam Roll (IT Band / Quads / Lats)','Recovery / Soft Tissue','Trail Running','IT band, quad, and calf recovery post long run or hike; reduces next-day soreness','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
