  ('EX020','Nordic Hamstring Curl','Strength','Trail Running','Eccentric hamstring loading; prevents the most common trail running soft tissue injury on descents','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX021','Bulgarian Split Squat (DB)','Strength','Trail Running','Best single lower body exercise for trail running; mimics single-leg descent braking mechanics','Critical','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX022','Reverse Lunge (DB or BW)','Strength','Trail Running','Knee-friendly lunge variant; single-leg control and hip stability under moving load','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX023','Lateral Lunge (DB or BW)','Strength','Trail Running','Lateral stability and groin strength for off-camber and sideslope terrain','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
