  ('EX028','Pistol Squat / Assisted Pistol','Strength','Trail Running','Single-leg eccentric control at full range of motion; steep descent mechanics and scramble prep','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX029','Sled Push','Power','Trail Running','Leg power accumulation without eccentric stress; ideal for high volume blocks without soreness penalty','Medium','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
