  ('EX031','Kettlebell Swing (Two-Hand)','Power','Trail Running','Explosive hip extension power; improves uphill stride drive; high metabolic conditioning benefit','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX032','Jump Squat (BW or Light Load)','Power','Trail Running','Rate of force development for reactive foot placement on technical terrain','Medium','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
