  ('EX039','Glute Bridge (Double-Leg)','Activation / Primer','Trail Running','Glute activation pre-run; ensures glute max fires during push-off rather than hamstring-dominating','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX040','Clamshell (Band)','Activation / Primer','Trail Running','Glute med activation; first step in pre-run hip activation sequence','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
