  ('EX044','BOSU Single-Leg Squat','Balance / Proprioception','Trail Running','Reactive stability on unstable surface; directly mimics rocky trail terrain demands','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX045','Ankle Mobility Drill (Wall)','Mobility','Trail Running','Dorsiflexion range; restricted ankle limits squat depth and uphill running mechanics','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
