  ('EX048','Hill Repeats','Interval / Tempo','Trail Running','Uphill-specific power and aerobic capacity; primary race-specific interval for AR trail legs','Critical','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
