  ('EX052','Downhill Running Technique Drill','Technical / Skill','Trail Running','Downhill mechanics — foot strike, scanning, lean; top AR injury site and time sink if underprepared','Critical','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX010','Rucking (Weighted Hike)','Loaded Carry','Orienteering','Race sim for pack-loaded navigation on foot; pace management under load','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX008','Broad Jump','Plyometric','Orienteering','Horizontal power for obstacle clearance and terrain hops during route navigation','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX012','Copenhagen Plank','Isometric','Orienteering','Hip adductor stability; lateral cuts and direction changes on uneven orienteering terrain','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX017','Lateral Band Walk','Activation / Primer','Orienteering','Glute med activation for lateral stability during rapid direction changes','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX034','Lateral Bound','Plyometric','Orienteering','Lateral power; simulates the quick lateral footwork needed on off-trail navigation terrain','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX048','Hill Repeats','Interval / Tempo','Orienteering','Uphill aerobic capacity; orienteering maps often use terrain with significant elevation changes','High','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('EX001','Back Squat (Barbell)','Strength','Orienteering','General leg strength base; supports sustained running and direction change demand','Medium','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
