  ('EX004','Single-Leg RDL (DB)','Strength','Orienteering','Unilateral stability; controls ankle and hip on technical off-trail terrain','Medium','0B-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
