  ('Swimrun','D-004','Swimming','Primary',30.0,35.0,20.0,25.0,18.0,22.0,15.0,18.0,'Separate swim sessions to build individual base before combining. KEY: Open-water acclimatization in Build/Peak phase. Volumes drop slightly into Peak as combined-session work absorbs swim volume.','included','Separate swim sessions to build individual base before combining.','KEY: Open-water acclimatization in Build/Peak phase. | Volumes drop slightly into Peak as combined-session work absorbs swim volume.','Separate swim sessions to build individual base before combining. KEY: Open-water acclimatization in Build/Peak phase. Volumes drop slightly into Peak as combined-session work absorbs swim volume.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
  ('Swimrun','D-002','Road Running','Primary',45.0,50.0,38.0,45.0,38.0,44.0,38.0,44.0,'Trail running dominant — Swimrun events average 65–75% running by time. Pure run sessions in Base; combined with swim from Build onward.','included','Trail running dominant — Swimrun events average 65–75% running by time.','Pure run sessions in Base; | combined with swim from Build onward.','Trail running dominant — Swimrun events average 65–75% running by time. Pure run sessions in Base; combined with swim from Build onward.',NULL,'0A-v1.6.6','2026-06-10T17:40:05.453426+00:00'::timestamptz),
